import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import { X, ChevronRight, ChevronLeft, ZoomIn, ZoomOut, Download } from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
}

// ForwardRef is needed for the HTMLFlipBook to work properly
const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm">
                {props.number}
            </div>
        </div>
    </div>
  );
});

Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose }) => {
  const bookRef = useRef<any>(null);
  const [currentPage, setCurrentPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });
  const [isMobile, setIsMobile] = useState(false);

  // Responsive calculations
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;

      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);

      let width, height;

      if (isSmallScreen) {
        // Mobile: Maximize width
        width = Math.min(windowWidth - 32, 500); // 32px padding
        height = width * 1.414; // A4 Ratio

        // Check if height overflows
        if (height > windowHeight - 140) {
            height = windowHeight - 140;
            width = height / 1.414;
        }
      } else {
        // Desktop: Two pages side-by-side logic handled by PageFlip
        // We set dimensions for a SINGLE page
        height = Math.min(windowHeight - 140, 800);
        width = height / 1.414;
      }

      setDimensions({ width: Math.floor(width), height: Math.floor(height) });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
  }, []);

  const nextFlip = () => {
    if (bookRef.current) {
        bookRef.current.pageFlip().flipNext();
    }
  };

  const prevFlip = () => {
    if (bookRef.current) {
        bookRef.current.pageFlip().flipPrev();
    }
  };

  const onInit = useCallback((e: any) => {
      setTotalPages(e.object.pages.length);
  }, []);


  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-dark-bg/95 backdrop-blur-md animate-fade-in">
      {/* Header Toolbar */}
      <div className="flex items-center justify-between p-4 border-b border-dark-border bg-dark-bg/50">
        <div className="flex flex-col">
            <h2 className="text-white font-bold text-lg">{catalog.title}</h2>
            <span className="text-slate-400 text-xs">
                 صفحه {currentPage + 1} از {catalog.pages.length}
            </span>
        </div>
        <button 
            onClick={onClose}
            className="p-2 rounded-full bg-slate-800 text-white hover:bg-red-500 transition-colors"
        >
            <X size={20} />
        </button>
      </div>

      {/* Book Container */}
      <div className="flex-grow flex items-center justify-center relative overflow-hidden p-4">
        {/* Nav Buttons - Desktop */}
        <button 
            onClick={nextFlip}
            className="hidden md:flex absolute right-4 z-10 p-3 bg-brand-600/80 hover:bg-brand-500 text-white rounded-full shadow-lg transition-transform hover:scale-110 backdrop-blur-sm"
        >
            <ChevronRight size={24} />
        </button>

        <button 
            onClick={prevFlip}
            className="hidden md:flex absolute left-4 z-10 p-3 bg-brand-600/80 hover:bg-brand-500 text-white rounded-full shadow-lg transition-transform hover:scale-110 backdrop-blur-sm"
        >
            <ChevronLeft size={24} />
        </button>

        {/* The FlipBook */}
        <div style={{ maxHeight: '100%', maxWidth: '100%' }}>
            {/* @ts-ignore - Library types mismatch slightly with React 18 but works */}
            <HTMLFlipBook
                width={dimensions.width}
                height={dimensions.height}
                size="stretch"
                minWidth={300}
                maxWidth={1000}
                minHeight={400}
                maxHeight={1533}
                maxShadowOpacity={0.5}
                showCover={true}
                mobileScrollSupport={true}
                onFlip={onFlip}
                onInit={onInit}
                ref={bookRef}
                className="shadow-2xl"
                style={{ margin: '0 auto' }}
                usePortrait={isMobile}
                startPage={0}
                drawShadow={true}
                flippingTime={1000}
                useMouseEvents={true}
                swipeDistance={30}
            >
                {catalog.pages.map((pageUrl, index) => (
                    <Page number={index + 1} key={index}>
                         <img 
                            src={pageUrl} 
                            alt={`Page ${index + 1}`} 
                            className="w-full h-full object-cover"
                            loading={index < 4 ? "eager" : "lazy"}
                         />
                    </Page>
                ))}
            </HTMLFlipBook>
        </div>
      </div>

      {/* Mobile Toolbar (Bottom) */}
      <div className="md:hidden p-4 bg-dark-card border-t border-dark-border flex justify-between items-center safe-area-bottom">
        <button 
            onClick={nextFlip}
            className="p-3 rounded-xl bg-slate-800 text-white active:bg-brand-600 transition-colors"
        >
            <ChevronRight size={24} />
        </button>

        <span className="text-white text-sm font-medium bg-slate-800 px-4 py-2 rounded-lg">
            {currentPage + 1} / {catalog.pages.length}
        </span>

        <button 
            onClick={prevFlip}
            className="p-3 rounded-xl bg-slate-800 text-white active:bg-brand-600 transition-colors"
        >
            <ChevronLeft size={24} />
        </button>
      </div>
    </div>
  );
};

export default BookViewer;

