import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  Download, 
  Maximize, 
  Minimize, 
  Volume2, 
  VolumeX,
  Settings,
  Share2
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
}

// Sound effect URL (Paper flip)
const PAGE_FLIP_SOUND_URL = "https://cdn.pixabay.com/audio/2022/03/24/audio_3497d6205e.mp3";

// ForwardRef is needed for the HTMLFlipBook to work properly
const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none">
                {props.number}
            </div>
        </div>
    </div>
  );
});

Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });
  const [isMobile, setIsMobile] = useState(false);

  // Settings State
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // Handle Resize
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;

      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);

      let width, height;

      if (isSmallScreen) {
        // Mobile: Maximize width
        width = Math.min(windowWidth - 32, 500); 
        height = width * 1.414; 

        if (height > windowHeight - 160) {
            height = windowHeight - 160;
            width = height / 1.414;
        }
      } else {
        // Desktop
        height = Math.min(windowHeight - 140, 800);
        width = height / 1.414;
      }

      setDimensions({ width: Math.floor(width), height: Math.floor(height) });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Handle Fullscreen events
  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {
            // Auto-play policy might block this without interaction
        });
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip().flipNext();
  const prevFlip = () => bookRef.current?.pageFlip().flipPrev();
  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable fullscreen: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const handleDownload = () => {
    // Determine file to download. For this demo, we use the first page image.
    // In production, this would be a PDF URL from the catalog object.
    const link = document.createElement('a');
    link.href = catalog.pages[0];
    link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex flex-col bg-dark-bg/95 backdrop-blur-md animate-fade-in transition-all duration-300"
    >
      {/* Header Toolbar */}
      <div className="flex items-center justify-between p-4 border-b border-dark-border bg-dark-bg/80 backdrop-blur-md select-none">

        {/* Title & Info */}
        <div className="flex flex-col">
            <h2 className="text-white font-bold text-lg leading-tight">{catalog.title}</h2>
            <span className="text-slate-400 text-xs mt-0.5">
                 صفحه {currentPage + 1} از {catalog.pages.length}
            </span>
        </div>

        {/* Desktop Controls */}
        <div className="flex items-center gap-2">

            <div className="hidden md:flex items-center gap-1 bg-dark-card rounded-lg p-1 border border-dark-border mr-2">
                <button 
                    onClick={() => setIsSoundEnabled(!isSoundEnabled)}
                    className="p-2 text-slate-300 hover:text-white hover:bg-slate-700 rounded-md transition-colors"
                    title={isSoundEnabled ? "قطع صدا" : "وصل صدا"}
                >
                    {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>
                <button 
                    onClick={toggleFullscreen}
                    className="p-2 text-slate-300 hover:text-white hover:bg-slate-700 rounded-md transition-colors"
                    title={isFullscreen ? "خروج از تمام‌صفحه" : "تمام‌صفحه"}
                >
                    {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                </button>
                <button 
                    onClick={handleDownload}
                    className="p-2 text-slate-300 hover:text-white hover:bg-slate-700 rounded-md transition-colors"
                    title="دانلود"
                >
                    <Download size={18} />
                </button>
            </div>

            <button 
                onClick={onClose}
                className="p-2 rounded-full bg-slate-800 text-white hover:bg-red-500 hover:text-white transition-colors border border-dark-border"
                title="بستن"
            >
                <X size={20} />
            </button>
        </div>
      </div>

      {/* Book Container */}
      <div className="flex-grow flex items-center justify-center relative overflow-hidden p-4">

        {/* Background Overlay for focus */}
        <div 
            className="absolute inset-0 bg-black/20 pointer-events-none" 
            style={{ opacity: isFullscreen ? 1 : 0 }} 
        />

        {/* Nav Buttons - Desktop */}
        <button 
            onClick={nextFlip}
            className="hidden md:flex absolute right-4 z-10 p-3 bg-brand-600/90 hover:bg-brand-500 text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-brand-400/20 group"
        >
            <ChevronRight size={24} className="group-active:translate-x-1 transition-transform" />
        </button>

        <button 
            onClick={prevFlip}
            className="hidden md:flex absolute left-4 z-10 p-3 bg-brand-600/90 hover:bg-brand-500 text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-brand-400/20 group"
        >
            <ChevronLeft size={24} className="group-active:-translate-x-1 transition-transform" />
        </button>

        {/* The FlipBook */}
        <div style={{ maxHeight: '100%', maxWidth: '100%', perspective: '1500px' }}>
            {/* @ts-ignore - Library types mismatch workarounds */}
            <HTMLFlipBook
                width={dimensions.width}
                height={dimensions.height}
                size="stretch"
                minWidth={300}
                maxWidth={1000}
                minHeight={400}
                maxHeight={1533}
                maxShadowOpacity={0.5}
                showCover={true}
                mobileScrollSupport={true}
                onFlip={onFlip}
                onInit={onInit}
                ref={bookRef}
                className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`} // Prevent flash before resize
                style={{ margin: '0 auto' }}
                usePortrait={isMobile}
                startPage={0}
                drawShadow={true}
                flippingTime={800}
                useMouseEvents={true}
                swipeDistance={30}
            >
                {catalog.pages.map((pageUrl, index) => (
                    <Page number={index + 1} key={index}>
                         <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                            <img 
                                src={pageUrl} 
                                alt={`Page ${index + 1}`} 
                                className="w-full h-full object-cover select-none"
                                loading={index < 4 ? "eager" : "lazy"}
                                draggable={false}
                            />
                         </div>
                    </Page>
                ))}
            </HTMLFlipBook>
        </div>
      </div>

      {/* Mobile Toolbar (Bottom) */}
      <div className="md:hidden bg-dark-card border-t border-dark-border safe-area-bottom">
        <div className="flex justify-between items-center px-4 py-3">
             <button 
                onClick={nextFlip}
                className="p-3 rounded-xl bg-slate-800 text-white active:bg-brand-600 transition-colors"
            >
                <ChevronRight size={24} />
            </button>

            <div className="flex gap-4 text-slate-400">
                <button onClick={() => setIsSoundEnabled(!isSoundEnabled)}>
                     {isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                </button>
                <button onClick={handleDownload}>
                     <Download size={20} />
                </button>
            </div>

            <button 
                onClick={prevFlip}
                className="p-3 rounded-xl bg-slate-800 text-white active:bg-brand-600 transition-colors"
            >
                <ChevronLeft size={24} />
            </button>
        </div>
      </div>
    </div>
  );
};

export default BookViewer;

import React from 'react';
import { Catalog } from '../types';
import { BookOpen, Calendar, ChevronLeft } from 'lucide-react';

interface CatalogCardProps {
  catalog: Catalog;
  onClick: (catalog: Catalog) => void;
