                        readOnly
                        className="w-full h-48 bg-slate-50 border border-skin-border rounded-lg p-4 text-xs font-mono dir-ltr text-left"
                        value={generateDataFile()}
                    />
                    <button 
                        onClick={copyToClipboard}
                        className="absolute top-4 right-4 bg-skin-primary text-white px-3 py-1.5 rounded text-xs flex items-center gap-2 hover:bg-skin-primary-hover"
                    >
                        <Copy size={14} />
                        کپی کد
                    </button>
                </div>
            </div>
        )}

        {/* List & Add Button */}
        {!showForm && (
            <div>
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold">لیست کاتالوگ‌ها</h2>
                    <div className="flex gap-2">
                        <button 
                            onClick={resetToDefault}
                            className="text-sm text-skin-muted hover:text-red-500 underline px-4"
                        >
                            بازنشانی به پیش‌فرض
                        </button>
                        <button 
                            onClick={() => { resetForm(); setShowForm(true); }}
                            className="bg-skin-primary hover:bg-skin-primary-hover text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-md"
                        >
                            <Plus size={20} />
                            افزودن کاتالوگ جدید
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {catalogs.map(cat => (
                        <div key={cat.id} className="bg-skin-card border border-skin-border rounded-xl overflow-hidden group hover:shadow-lg transition-all flex flex-col">
                            <div className="h-48 relative bg-gray-100">
                                <img src={cat.coverImage} className="w-full h-full object-cover" alt={cat.title} />
                                <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
                                    <button onClick={() => handleEdit(cat)} className="p-2 bg-white rounded-full text-blue-600 hover:scale-110 transition-transform">
                                        <Edit2 size={20} />
                                    </button>
                                    <button onClick={() => deleteCatalog(cat.id)} className="p-2 bg-white rounded-full text-red-600 hover:scale-110 transition-transform">
                                        <Trash2 size={20} />
                                    </button>
                                </div>
                            </div>
                            <div className="p-4 flex-grow">
                                <h3 className="font-bold text-lg mb-1">{cat.title}</h3>
                                <p className="text-sm text-skin-muted line-clamp-2 mb-2">{cat.description}</p>
                                <div className="text-xs text-skin-muted flex gap-2 mt-auto">
                                    <span>{cat.date}</span> | <span>{cat.pageCount} صفحه</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        )}

        {/* Edit/Create Form */}
        {showForm && (
            <div className="max-w-4xl mx-auto bg-skin-card border border-skin-border rounded-xl p-6 md:p-8 shadow-xl">
                <div className="flex justify-between items-center mb-8 border-b border-skin-border pb-4">
                    <h2 className="text-2xl font-bold flex items-center gap-2">
                        {editingId ? <Edit2 size={24} className="text-blue-500" /> : <Plus size={24} className="text-green-500" />}
                        {editingId ? 'ویرایش کاتالوگ' : 'افزودن کاتالوگ جدید'}
                    </h2>
                    <button onClick={resetForm} className="p-2 hover:bg-skin-control-bg rounded-full text-skin-muted">
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-skin-muted">عنوان کاتالوگ</label>
                            <input 
                                className="w-full p-3 bg-skin-control-bg border border-skin-border rounded-lg focus:border-skin-primary outline-none"
                                value={formData.title}
                                onChange={e => setFormData({...formData, title: e.target.value})}
                                placeholder="مثلا: کاتالوگ محصول X"
                                required
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-skin-muted">تاریخ انتشار</label>
                            <input 
                                className="w-full p-3 bg-skin-control-bg border border-skin-border rounded-lg focus:border-skin-primary outline-none"
                                value={formData.date}
                                onChange={e => setFormData({...formData, date: e.target.value})}
                                placeholder="۱۴۰۳/۰۱/۰۱"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-skin-muted">توضیحات کوتاه</label>
                        <textarea 
                            className="w-full p-3 bg-skin-control-bg border border-skin-border rounded-lg focus:border-skin-primary outline-none h-24"
                            value={formData.description}
                            onChange={e => setFormData({...formData, description: e.target.value})}
                            placeholder="توضیحات مختصر در مورد کاتالوگ..."
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-skin-muted flex items-center gap-2">
                             <FileText size={16} />
