                        </label>
                        <input 
                            className="w-full p-3 bg-skin-control-bg border border-skin-border rounded-lg focus:border-skin-primary outline-none dir-ltr text-left"
                            value={formData.pdfUrl}
                            onChange={e => setFormData({...formData, pdfUrl: e.target.value})}
                            placeholder="https://example.com/file.pdf"
                        />
                        <p className="text-xs text-skin-muted">لینک مستقیم فایل PDF را وارد کنید.</p>
                    </div>

                    {/* Cover Image */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-skin-muted flex items-center gap-2">
                             <ImageIcon size={16} />
                             تصویر کاور
                        </label>
                        <div className="flex flex-col md:flex-row gap-4 items-start">
                             <div className="w-32 h-44 bg-gray-100 border border-dashed border-gray-400 rounded-lg flex items-center justify-center overflow-hidden shrink-0 relative">
                                {formData.coverImage ? (
                                    <img src={formData.coverImage} className="w-full h-full object-cover" />
                                ) : (
                                    <span className="text-xs text-gray-400">بدون تصویر</span>
                                )}
                             </div>
                             <div className="flex-grow space-y-3 w-full">
                                <input 
                                    className="w-full p-2 text-sm bg-skin-control-bg border border-skin-border rounded-lg dir-ltr"
                                    value={formData.coverImage}
                                    onChange={e => setFormData({...formData, coverImage: e.target.value})}
                                    placeholder="آدرس URL تصویر یا انتخاب فایل از سیستم"
                                />
                                <label className="flex items-center justify-center gap-2 bg-skin-control-bg hover:bg-skin-control-hover border border-skin-border text-skin-text py-2 px-4 rounded-lg cursor-pointer transition-colors w-full md:w-auto text-sm">
                                    <Upload size={16} />
                                    <span>انتخاب فایل کاور از سیستم (تبدیل به کد)</span>
                                    <input type="file" accept="image/*" className="hidden" onChange={e => handleImageUpload(e, 'cover')} />
                                </label>
                             </div>
                        </div>
                    </div>

                    {/* Pages */}
                    <div className="space-y-4 border-t border-skin-border pt-6">
                        <div className="flex justify-between items-center">
                            <label className="text-lg font-bold text-skin-text flex items-center gap-2">
                                <LayoutGrid size={20} />
                                صفحات کاتالوگ ({formData.pages?.length || 0})
                            </label>
                            <label className="flex items-center gap-2 bg-skin-primary hover:bg-skin-primary-hover text-white py-2 px-4 rounded-lg cursor-pointer text-sm shadow-sm transition-colors">
                                <Upload size={16} />
                                <span>افزودن صفحات از سیستم</span>
                                <input type="file" accept="image/*" multiple className="hidden" onChange={e => handleImageUpload(e, 'pages')} />
                            </label>
                        </div>

                        <div className="space-y-2">
                             <textarea 
                                className="w-full p-3 bg-skin-control-bg border border-skin-border rounded-lg focus:border-skin-primary outline-none h-32 text-xs font-mono dir-ltr"
                                value={formData.pages?.join('\n')}
                                onChange={e => setFormData({...formData, pages: e.target.value.split('\n').filter(Boolean), pageCount: e.target.value.split('\n').filter(Boolean).length})}
                                placeholder="لینک هر صفحه را در یک خط وارد کنید..."
                            />
                            <p className="text-xs text-skin-muted">می‌توانید لینک تصاویر را به صورت دستی (هر کدام در یک خط) وارد کنید یا از دکمه بالا برای آپلود استفاده کنید.</p>
                        </div>

                        {/* Page Previews */}
                        {formData.pages && formData.pages.length > 0 && (
                            <div className="flex gap-4 overflow-x-auto pb-4 py-2 bg-skin-control-bg/50 rounded-xl px-4 scrollbar-hide">
                                {formData.pages.map((page, idx) => (
                                    <div key={idx} className="relative w-24 h-32 shrink-0 group">
                                        <img src={page} className="w-full h-full object-cover rounded-md border border-skin-border bg-white" />
                                        <div className="absolute top-1 left-1 bg-black/70 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full">
                                            {idx + 1}
                                        </div>
                                        <button 
                                            type="button"
                                            onClick={() => removePage(idx)}
                                            className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-md opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <X size={12} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="pt-6 border-t border-skin-border flex justify-end gap-3 sticky bottom-0 bg-skin-card p-4 -mx-6 -mb-6 md:-mx-8 md:-mb-8 border-t shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                        <button 
                            type="button" 
                            onClick={resetForm}
                            className="px-6 py-2.5 rounded-lg border border-skin-border text-skin-muted hover:bg-skin-control-hover transition-colors"
                        >
                            انصراف
                        </button>
                        <button 
                            type="submit"
                            className="px-8 py-2.5 rounded-lg bg-skin-primary hover:bg-skin-primary-hover text-white font-bold shadow-lg shadow-skin-primary/30 transition-all active:scale-95 flex items-center gap-2"
                        >
                            <Save size={18} />
                            ذخیره تغییرات
                        </button>
                    </div>
                </form>
            </div>
        )}
      </main>
    </div>
  );
};

