import React, { useState, useEffect } from 'react';
import { Catalog } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import BookViewer from './components/BookViewer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import { Search, Grid, Sun, Moon, BookOpen, Settings } from 'lucide-react';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';

const MainApp = () => {
  const { catalogs } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Apply theme to document
  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') {
      document.documentElement.setAttribute('data-theme', theme);
    }
  }, [theme]);

  // Check URL hash for admin shortcut
  useEffect(() => {
    if (window.location.hash === '#admin') {
      setViewMode('admin');
    }
  }, []);

  const filteredCatalogs = catalogs.filter(cat => 
    cat.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    cat.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const getThemeIcon = () => {
    switch(theme) {
        case 'light': return <Sun size={20} />;
        case 'dark': return <Moon size={20} />;
        case 'reading': return <BookOpen size={20} />;
    }
  };

  const getThemeLabel = () => {
     switch(theme) {
        case 'light': return 'روز';
        case 'dark': return 'شب';
        case 'reading': return 'مطالعه';
    }
  };

  // Admin Logic
  if (viewMode === 'admin') {
    if (!isAuthenticated) {
      return (
        <AdminLogin 
          onLogin={() => setIsAuthenticated(true)} 
          onBack={() => setViewMode('home')} 
        />
      );
    }
    return (
      <AdminPanel 
        onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} 
      />
    );
  }

  return (
    <div className="min-h-screen font-sans bg-skin-base text-skin-text transition-colors duration-300">

      {/* Header */}
      <header className="sticky top-0 z-40 w-full backdrop-blur-lg bg-skin-base/80 border-b border-skin-border">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img 
              src="https://nafaspharmed.com/wp-content/uploads/2025/11/logo_fa.png" 
              alt="نفس فارمد" 
              className="h-10 w-auto object-contain" 
            />
          </div>

          <div className="flex items-center gap-4">
             {/* Search Bar (Desktop) */}
             <div className="hidden md:flex items-center bg-skin-card border border-skin-border rounded-full px-4 py-2 w-80 focus-within:border-skin-primary transition-colors">
                <Search size={18} className="text-skin-muted ml-2" />
                <input 
                    type="text" 
                    placeholder="جستجو در کاتالوگ‌ها..." 
                    className="bg-transparent border-none outline-none text-sm text-skin-text w-full placeholder-skin-muted"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
             </div>

             {/* Theme Toggle */}
             <button 
                onClick={toggleTheme}
                className="flex items-center gap-2 px-3 py-2 rounded-lg bg-skin-card border border-skin-border text-skin-text hover:bg-skin-control-hover transition-colors"
                title="تغییر تم"
             >
                {getThemeIcon()}
                <span className="text-xs font-medium hidden sm:inline">{getThemeLabel()}</span>
             </button>

             {/* Admin Button (Hidden on mobile usually, but kept accessible) */}
             <button
                onClick={() => setViewMode('admin')}
                className="p-2 text-skin-muted hover:text-skin-primary transition-colors"
                title="ورود به پنل مدیریت"
             >
                <Settings size={20} />
             </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8 md:py-12">

        {/* Intro Section */}
        <div className="mb-10 text-center md:text-right md:flex justify-between items-end border-b border-skin-border pb-8">
            <div className="max-w-2xl">
                <h2 className="text-3xl md:text-4xl font-black text-skin-text mb-4 leading-tight">
                    کتابخانه دیجیتال داروخانه <span className="text-transparent bg-clip-text bg-gradient-to-r from-skin-primary to-skin-primary-hover">نفس فارمد</span>
                </h2>
                <p className="text-skin-muted text-lg">
                    دسترسی سریع به جدیدترین کاتالوگ‌ها و بروشورهای محصولات دارویی نفس فارمد
                </p>
            </div>
            <div className="hidden md:flex items-center gap-2 text-skin-muted mt-4 md:mt-0 bg-skin-card px-4 py-2 rounded-lg border border-skin-border">
                <Grid size={18} />
                <span>{filteredCatalogs.length} کاتالوگ موجود</span>
            </div>
        </div>

        {/* Mobile Search */}
        <div className="md:hidden mb-8">
             <div className="flex items-center bg-skin-card border border-skin-border rounded-xl px-4 py-3 w-full focus-within:border-skin-primary transition-colors shadow-sm">
                <Search size={20} className="text-skin-muted ml-3" />
                <input 
                    type="text" 
                    placeholder="جستجو..." 
                    className="bg-transparent border-none outline-none text-skin-text w-full placeholder-skin-muted"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>
        </div>

        {/* Grid */}
        {filteredCatalogs.length > 0 ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 md:gap-8">
            {filteredCatalogs.map(catalog => (
                <CatalogCard 
                    key={catalog.id} 
                    catalog={catalog} 
                    onClick={setSelectedCatalog} 
                />
            ))}
            </div>
        ) : (
            <div className="flex flex-col items-center justify-center py-20 text-skin-muted">
                <Search size={48} className="mb-4 opacity-50" />
                <p className="text-lg font-medium">هیچ کاتالوگی یافت نشد.</p>
            </div>
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-skin-border py-8 mt-12 bg-skin-base/50">
        <div className="container mx-auto px-4 text-center text-skin-muted text-sm">
            <p>© تمامی حقوق مادی و معنوی این سایت متعلق به شرکت دانش بنیان نفس زیست فارمد است.</p>
        </div>
      </footer>

      {/* Viewer Modal */}
      {selectedCatalog && (
        <BookViewer 
            catalog={selectedCatalog} 
            onClose={() => setSelectedCatalog(null)} 
        />
      )}
    </div>
  );
}

function App() {
  return (
    <CatalogProvider>
      <MainApp />
    </CatalogProvider>
  );
}

export default App;

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],
  // This ensures assets are linked relatively (e.g., "./assets/...") 
