import React, { useState } from 'react';
import { useCatalogs } from '../context/CatalogContext';
import { Catalog } from '../types';
import { 
  Plus, Trash2, Edit2, Save, X, Upload, 
  Image as ImageIcon, FileText, LayoutGrid, LogOut, Copy 
} from 'lucide-react';

interface AdminPanelProps {
  onLogout: () => void;
}

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogout }) => {
  const { catalogs, addCatalog, updateCatalog, deleteCatalog, resetToDefault } = useCatalogs();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [showExport, setShowExport] = useState(false);

  // Form State
  const [formData, setFormData] = useState<Partial<Catalog>>({
    title: '',
    description: '',
    date: '',
    pdfUrl: '',
    coverImage: '',
    pages: [],
    pageCount: 0
  });

  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      date: new Date().toLocaleDateString('fa-IR'),
      pdfUrl: '',
      coverImage: '',
      pages: [],
      pageCount: 0
    });
    setEditingId(null);
    setShowForm(false);
  };

  const handleEdit = (catalog: Catalog) => {
    setFormData(catalog);
    setEditingId(catalog.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: 'cover' | 'pages') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      if (field === 'cover') {
        const base64 = await fileToBase64(files[0]);
        setFormData(prev => ({ ...prev, coverImage: base64 }));
      } else {
        const newPages = await Promise.all(Array.from(files).map(fileToBase64));
        setFormData(prev => ({
          ...prev,
          pages: [...(prev.pages || []), ...newPages],
          pageCount: (prev.pages?.length || 0) + newPages.length
        }));
      }
    } catch (error) {
      alert('خطا در بارگذاری تصویر');
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.coverImage || !formData.pages?.length) {
        alert('لطفا عنوان، تصویر کاور و صفحات را تکمیل کنید');
        return;
    }

    const catalogData: Catalog = {
        id: editingId || Date.now().toString(),
        title: formData.title!,
        description: formData.description || '',
        date: formData.date || '',
        pdfUrl: formData.pdfUrl || undefined,
        coverImage: formData.coverImage!,
        pages: formData.pages!,
        pageCount: formData.pages!.length
    };

    if (editingId) {
        updateCatalog(editingId, catalogData);
    } else {
        addCatalog(catalogData);
    }
    resetForm();
  };

  const removePage = (index: number) => {
    const newPages = formData.pages?.filter((_, i) => i !== index);
    setFormData(prev => ({ ...prev, pages: newPages, pageCount: newPages?.length || 0 }));
  };

  const generateDataFile = () => {
    // We add eslint-disable and ts-nocheck to prevent build errors with large Base64 strings or formatting
    const header = `/* eslint-disable */\n// @ts-nocheck\nimport { Catalog } from './types';\n\n`;
    const jsonContent = JSON.stringify(catalogs, null, 2);
    return `${header}export const CATALOGS: Catalog[] = ${jsonContent};`;
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generateDataFile());
    alert('کد کپی شد! حالا محتوای فایل data.ts را با این کد جایگزین کنید.');
  };

  return (
    <div className="min-h-screen bg-skin-base text-skin-text pb-20">
      {/* Admin Header */}
      <header className="bg-skin-card border-b border-skin-border sticky top-0 z-20">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 font-bold text-skin-primary">
            <LayoutGrid />
            <span>پنل مدیریت نفس فارمد</span>
          </div>
          <div className="flex items-center gap-3">
             <button 
                onClick={() => setShowExport(!showExport)}
                className="text-sm bg-yellow-100 text-yellow-800 px-3 py-1.5 rounded-lg hover:bg-yellow-200 transition-colors"
             >
                خروجی دیتا (برای بیلد)
             </button>
             <button 
                onClick={onLogout}
                className="flex items-center gap-2 text-sm text-red-500 hover:bg-red-50 px-3 py-1.5 rounded-lg transition-colors"
             >
                <LogOut size={16} />
                خروج
             </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">

        {/* Export Area */}
        {showExport && (
            <div className="bg-skin-card border-2 border-yellow-200 rounded-xl p-6 mb-8 shadow-sm">
