  const [showForm, setShowForm] = useState(false);
  const [showExport, setShowExport] = useState(false);

  // Form State
  const [formData, setFormData] = useState<Partial<Catalog>>({
    title: '',
    description: '',
    date: '',
    pdfUrl: '',
    coverImage: '',
    pages: [],
    pageCount: 0
  });

  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      date: new Date().toLocaleDateString('fa-IR'),
      pdfUrl: '',
      coverImage: '',
      pages: [],
      pageCount: 0
    });
    setEditingId(null);
    setShowForm(false);
  };

  const handleEdit = (catalog: Catalog) => {
    setFormData(catalog);
    setEditingId(catalog.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: 'cover' | 'pages') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      if (field === 'cover') {
        const base64 = await fileToBase64(files[0]);
        setFormData(prev => ({ ...prev, coverImage: base64 }));
      } else {
        const newPages = await Promise.all(Array.from(files).map(fileToBase64));
        setFormData(prev => ({
          ...prev,
          pages: [...(prev.pages || []), ...newPages],
          pageCount: (prev.pages?.length || 0) + newPages.length
        }));
      }
    } catch (error) {
      alert('خطا در بارگذاری تصویر');
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.coverImage || !formData.pages?.length) {
