import React, { createContext, useContext, useState, useEffect } from 'react';
import { Catalog } from '../types';
import { CATALOGS as INITIAL_CATALOGS } from '../data';

interface CatalogContextType {
  catalogs: Catalog[];
  addCatalog: (catalog: Catalog) => void;
  updateCatalog: (id: string, updatedCatalog: Catalog) => void;
  deleteCatalog: (id: string) => void;
  resetToDefault: () => void;
}

const CatalogContext = createContext<CatalogContextType | undefined>(undefined);

export const CatalogProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [catalogs, setCatalogs] = useState<Catalog[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load from LocalStorage on init
  useEffect(() => {
    const saved = localStorage.getItem('nafas_catalogs');
    if (saved) {
      try {
        setCatalogs(JSON.parse(saved));
      } catch (e) {
        setCatalogs(INITIAL_CATALOGS);
      }
    } else {
      setCatalogs(INITIAL_CATALOGS);
    }
    setIsLoaded(true);
  }, []);

  // Save to LocalStorage whenever catalogs change
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('nafas_catalogs', JSON.stringify(catalogs));
    }
  }, [catalogs, isLoaded]);

  const addCatalog = (catalog: Catalog) => {
    setCatalogs(prev => [catalog, ...prev]);
  };

  const updateCatalog = (id: string, updatedCatalog: Catalog) => {
    setCatalogs(prev => prev.map(cat => cat.id === id ? updatedCatalog : cat));
  };

  const deleteCatalog = (id: string) => {
    // Removed window.confirm here to allow custom UI confirmation
    setCatalogs(prev => prev.filter(cat => cat.id !== id));
  };

  const resetToDefault = () => {
    if (window.confirm('آیا مطمئن هستید؟ تمام تغییرات شما حذف و به حالت اولیه باز می‌گردد.')) {
      setCatalogs(INITIAL_CATALOGS);
    }
  };

  return (
    <CatalogContext.Provider value={{ catalogs, addCatalog, updateCatalog, deleteCatalog, resetToDefault }}>
      {children}
    </CatalogContext.Provider>
  );
};

export const useCatalogs = () => {
  const context = useContext(CatalogContext);
  if (context === undefined) {
    throw new Error('useCatalogs must be used within a CatalogProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useCatalogs } from '../context/CatalogContext';
import { Catalog } from '../types';
import { 
  Plus, Trash2, Edit2, Save, X, Upload, 
  Image as ImageIcon, FileText, LayoutGrid, LogOut, Copy, AlertTriangle
} from 'lucide-react';

interface AdminPanelProps {
  onLogout: () => void;
}

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogout }) => {
  const { catalogs, addCatalog, updateCatalog, deleteCatalog, resetToDefault } = useCatalogs();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [showExport, setShowExport] = useState(false);
  const [deleteConfirmationId, setDeleteConfirmationId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Catalog>>({
    title: '',
    description: '',
    date: '',
    pdfUrl: '',
    coverImage: '',
    pages: [],
    pageCount: 0
  });

  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      date: new Date().toLocaleDateString('fa-IR'),
      pdfUrl: '',
      coverImage: '',
      pages: [],
      pageCount: 0
    });
    setEditingId(null);
    setShowForm(false);
  };

  const handleEdit = (catalog: Catalog) => {
    setFormData(catalog);
    setEditingId(catalog.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: 'cover' | 'pages') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      if (field === 'cover') {
        const base64 = await fileToBase64(files[0]);
        setFormData(prev => ({ ...prev, coverImage: base64 }));
      } else {
        const newPages = await Promise.all(Array.from(files).map(fileToBase64));
        setFormData(prev => ({
          ...prev,
          pages: [...(prev.pages || []), ...newPages],
          pageCount: (prev.pages?.length || 0) + newPages.length
        }));
      }
    } catch (error) {
      alert('خطا در بارگذاری تصویر');
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.coverImage || !formData.pages?.length) {
        alert('لطفا عنوان، تصویر کاور و صفحات را تکمیل کنید');
        return;
    }

    const catalogData: Catalog = {
        id: editingId || Date.now().toString(),
        title: formData.title!,
        description: formData.description || '',
        date: formData.date || '',
        pdfUrl: formData.pdfUrl || undefined,
        coverImage: formData.coverImage!,
        pages: formData.pages!,
        pageCount: formData.pages!.length
    };

    if (editingId) {
        updateCatalog(editingId, catalogData);
    } else {
        addCatalog(catalogData);
    }
    resetForm();
  };

  const removePage = (index: number) => {
    const newPages = formData.pages?.filter((_, i) => i !== index);
    setFormData(prev => ({ ...prev, pages: newPages, pageCount: newPages?.length || 0 }));
  };

  const generateDataFile = () => {
    const header = `/* eslint-disable */\n// @ts-nocheck\nimport { Catalog } from './types';\n\n`;
    const jsonContent = JSON.stringify(catalogs, null, 2);
    return `${header}export const CATALOGS: Catalog[] = ${jsonContent};`;
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generateDataFile());
