                        </div>

                        {/* Page Previews */}
                        {formData.pages && formData.pages.length > 0 && (
                            <div className="flex gap-4 overflow-x-auto pb-4 py-2 bg-skin-control-bg/50 rounded-xl px-4 scrollbar-hide">
                                {formData.pages.map((page, idx) => (
