                    <div className="pt-6 border-t border-skin-border flex justify-end gap-3 sticky bottom-0 bg-skin-card p-4 -mx-6 -mb-6 md:-mx-8 md:-mb-8 border-t shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                        <button 
