        {/* Toolbar (Display Settings) */}
        <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4 bg-skin-card p-3 rounded-xl border border-skin-border shadow-sm sticky top-20 z-30 mx-0 sm:mx-0">
            <div className="flex items-center gap-2 text-skin-text font-bold text-sm w-full sm:w-auto">
                 <div className="bg-skin-control-bg p-1.5 rounded-lg">
                    {displayMode === 'grid' ? <LayoutGrid size={18} /> : <LayoutList size={18} />}
                 </div>
                 <span>{processedCatalogs.length} کاتالوگ موجود</span>
            </div>

            <div className="flex items-center gap-2 w-full sm:w-auto justify-between sm:justify-end">
                 {/* Sort Dropdown */}
                 <div className="relative flex items-center flex-grow sm:flex-grow-0">
                    <ArrowDownUp size={16} className="absolute right-3 text-skin-muted pointer-events-none" />
                    <select
                        value={sortBy}
                        onChange={(e) => setSortBy(e.target.value as SortOption)}
                        className="w-full sm:w-48 appearance-none bg-skin-control-bg hover:bg-skin-control-hover text-skin-text text-xs sm:text-sm rounded-lg pr-9 pl-3 py-2.5 outline-none border border-transparent focus:border-skin-primary transition-colors cursor-pointer"
                    >
                        <option value="newest">جدیدترین</option>
                        <option value="oldest">قدیمی‌ترین</option>
                        <option value="az">حروف الفبا (آ-ی)</option>
                        <option value="za">حروف الفبا (ی-آ)</option>
                    </select>
                 </div>

                 <div className="w-px h-6 bg-skin-border mx-1 hidden sm:block"></div>

                 {/* View Toggle */}
                 <div className="flex bg-skin-control-bg p-1 rounded-lg border border-skin-border shrink-0">
                     <button 
                        onClick={() => setDisplayMode('grid')}
                        className={`p-2 rounded-md transition-all ${displayMode === 'grid' ? 'bg-skin-card text-skin-primary shadow-sm' : 'text-skin-muted hover:text-skin-text'}`}
                        title="نمایش شبکه‌ای"
