            </div>
        </div>

        {/* Grid / List Container */}
        {processedCatalogs.length > 0 ? (
            <div className={`grid gap-4 md:gap-6 ${
                displayMode === 'grid' 
                    ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' 
                    : 'grid-cols-1 md:grid-cols-2' // List mode: 1 col on mobile, 2 on tablet/desktop
            }`}>
            {processedCatalogs.map(catalog => (
                <CatalogCard 
                    key={catalog.id} 
                    catalog={catalog} 
                    onClick={setSelectedCatalog} 
                    viewMode={displayMode}
                />
            ))}
            </div>
        ) : (
            <div className="flex flex-col items-center justify-center py-20 text-skin-muted bg-skin-card border border-dashed border-skin-border rounded-xl">
                <Search size={48} className="mb-4 opacity-50" />
                <p className="text-lg font-medium">هیچ کاتالوگی یافت نشد.</p>
                <button onClick={() => setSearchTerm('')} className="mt-2 text-skin-primary hover:underline text-sm">
                    پاک کردن جستجو
                </button>
            </div>
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-skin-border py-8 mt-12 bg-skin-base/50">
        <div className="container mx-auto px-4 text-center text-skin-muted text-sm">
            <p>© تمامی حقوق مادی و معنوی این سایت متعلق به شرکت دانش بنیان نفس زیست فارمد است.</p>
        </div>
      </footer>

      {/* Viewer Modal */}
      {selectedCatalog && (
        <BookViewer 
            catalog={selectedCatalog} 
            onClose={() => setSelectedCatalog(null)} 
        />
      )}
    </div>
  );
}

function App() {
  return (
    <CatalogProvider>
      <MainApp />
    </CatalogProvider>
  );
}

