import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  Download, 
  Maximize, 
  Minimize, 
  Volume2, 
  VolumeX,
  FileText,
  ZoomIn,
  ZoomOut
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
}

// Sound effect URL (Paper flip)
const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// ForwardRef is needed for the HTMLFlipBook to work properly
const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none">
                {props.number}
            </div>
        </div>
    </div>
  );
});

Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });
  const [isMobile, setIsMobile] = useState(false);

  // Settings State
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);
  const [zoomLevel, setZoomLevel] = useState(1);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // Handle Resize - OPTIMIZED TO FILL SCREEN
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;

      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);

      // Define available space constraints
      // On mobile we need space for header (approx 60px) and footer controls (approx 80px) + padding
      // On desktop we need space for header (approx 70px) + padding
      const verticalPadding = isSmallScreen ? 140 : 100; 
      const horizontalPadding = isSmallScreen ? 20 : 100; // More side padding on desktop for buttons

      const availableHeight = windowHeight - verticalPadding;
      const availableWidth = windowWidth - horizontalPadding;

      // Aspect ratio of A4 paper is approx 1.414 (Height/Width)
      const aspectRatio = 1.414;

      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      // If calculated width is wider than screen, limit by width
      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      setDimensions({ 
          width: Math.floor(bookWidth), 
          height: Math.floor(bookHeight) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Handle Fullscreen events
  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {
            // Auto-play policy might block this without interaction
        });
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip().flipNext();
  const prevFlip = () => bookRef.current?.pageFlip().flipPrev();
  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable fullscreen: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const handleZoomIn = () => {
    setZoomLevel(prev => Math.min(prev + 0.2, 2.5)); // Max zoom 2.5x
  };

  const handleZoomOut = () => {
    setZoomLevel(prev => Math.max(prev - 0.2, 0.6)); // Min zoom 0.6x
  };

  const handleDownload = () => {
    const link = document.createElement('a');

    // Prefer PDF URL if available
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    }

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex flex-col bg-skin-overlay backdrop-blur-md animate-fade-in transition-all duration-300"
    >
      {/* Header Toolbar */}
      <div className="flex items-center justify-between p-4 border-b border-skin-border bg-skin-base/90 backdrop-blur-md select-none z-20 shadow-sm">

        {/* Title & Info */}
        <div className="flex flex-col">
            <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
            <span className="text-skin-muted text-xs mt-0.5">
                 صفحه {currentPage + 1} از {catalog.pages.length}
            </span>
        </div>

        {/* Desktop Controls */}
        <div className="flex items-center gap-2">

            <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                <button 
                    onClick={handleZoomOut}
                    className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"
                    title="کوچک‌نمایی"
                >
                    <ZoomOut size={18} />
                </button>
                 <span className="text-xs w-8 text-center tabular-nums text-skin-muted select-none">
                    {Math.round(zoomLevel * 100)}%
                </span>
                <button 
                    onClick={handleZoomIn}
                    className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"
                    title="بزرگ‌نمایی"
                >
                    <ZoomIn size={18} />
                </button>
                <div className="w-px h-5 bg-gray-300 mx-1"></div>
                <button 
                    onClick={() => setIsSoundEnabled(!isSoundEnabled)}
                    className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"
                    title={isSoundEnabled ? "قطع صدا" : "وصل صدا"}
                >
                    {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>
                <button 
                    onClick={toggleFullscreen}
                    className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"
                    title={isFullscreen ? "خروج از تمام‌صفحه" : "تمام‌صفحه"}
                >
                    {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                </button>
                <button 
                    onClick={handleDownload}
                    className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"
                    title={catalog.pdfUrl ? "دانلود فایل PDF" : "دانلود تصویر"}
                >
                    {catalog.pdfUrl ? <FileText size={18} /> : <Download size={18} />}
                </button>
            </div>

            <button 
                onClick={onClose}
                className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border"
                title="بستن"
            >
                <X size={20} />
            </button>
        </div>
      </div>

      {/* Book Container */}
      <div className="flex-grow flex items-center justify-center relative overflow-hidden p-0 md:p-4 bg-skin-base/30">

        {/* Background Overlay for focus */}
        <div 
            className="absolute inset-0 bg-skin-base/20 pointer-events-none" 
            style={{ opacity: isFullscreen ? 1 : 0 }} 
        />

        {/* Nav Buttons - Desktop */}
        <button 
            onClick={nextFlip}
            className="hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group"
        >
            <ChevronRight size={24} className="group-active:translate-x-1 transition-transform" />
        </button>

        <button 
            onClick={prevFlip}
            className="hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group"
        >
            <ChevronLeft size={24} className="group-active:-translate-x-1 transition-transform" />
        </button>

        {/* The FlipBook Wrapper for Zoom */}
        <div 
            style={{ 
                transform: `scale(${zoomLevel})`, 
                transition: 'transform 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94)',
                transformOrigin: 'center center'
            }}
            className="flex items-center justify-center"
        >
            {/* @ts-ignore */}
            <HTMLFlipBook
                width={dimensions.width}
                height={dimensions.height}
                size="fixed" // Changed to fixed to respect our optimized calculations
                minWidth={300}
                maxWidth={3000} // Increased significantly
                minHeight={400}
                maxHeight={4000} // Increased significantly
                maxShadowOpacity={0.5}
                showCover={false}
                mobileScrollSupport={true}
                onFlip={onFlip}
                onInit={onInit}
                ref={bookRef}
                className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`}
                style={{ margin: '0 auto' }}
                usePortrait={isMobile}
                startPage={0}
                drawShadow={true}
                flippingTime={800}
                useMouseEvents={true}
                swipeDistance={30}
            >
                {catalog.pages.map((pageUrl, index) => (
                    <Page number={index + 1} key={index}>
                         <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                            <img 
                                src={pageUrl} 
                                alt={`Page ${index + 1}`} 
                                className="w-full h-full object-contain select-none bg-white"
                                loading={index < 4 ? "eager" : "lazy"}
                                draggable={false}
                            />
                         </div>
                    </Page>
                ))}
            </HTMLFlipBook>
        </div>
      </div>

      {/* Mobile Toolbar (Bottom) */}
      <div className="md:hidden bg-skin-card border-t border-skin-border safe-area-bottom z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
        <div className="flex flex-col gap-2 px-4 py-2">
            {/* Zoom Controls Mobile */}
            <div className="flex justify-center items-center gap-4 py-1 border-b border-gray-100 pb-2 mb-1">
                 <button onClick={handleZoomOut} className="p-1.5 bg-gray-100 rounded text-gray-600">
                    <ZoomOut size={16} />
                 </button>
                 <span className="text-xs font-mono text-gray-500 w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                 <button onClick={handleZoomIn} className="p-1.5 bg-gray-100 rounded text-gray-600">
                    <ZoomIn size={16} />
                 </button>
            </div>

            <div className="flex justify-between items-center">
                <button 
                    onClick={nextFlip}
                    className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors"
                >
                    <ChevronRight size={24} />
                </button>

                <div className="flex gap-4 text-skin-muted">
                    <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">
                        {isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                    </button>
                    <button onClick={handleDownload} className="p-2">
                        {catalog.pdfUrl ? <FileText size={20} /> : <Download size={20} />}
                    </button>
                </div>

                <button 
                    onClick={prevFlip}
                    className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors"
                >
                    <ChevronLeft size={24} />
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

