    const catalogsJson = JSON.stringify(catalogs, null, 2);
    const videosJson = JSON.stringify(videos, null, 2);
    return `${header}export const CATALOGS: Catalog[] = ${catalogsJson};\n\nexport const VIDEOS: Video[] = ${videosJson};`;
  };

