                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {processedVideos.map(video => (
                        <VideoCard 
                            key={video.id}
                            video={video}
                            onClick={setSelectedVideo}
                        />
                    ))}
                </div>
            </div>
        )}

      </main>

      {/* Footer */}
      <footer className="border-t border-skin-border py-8 mt-12 bg-skin-base/50">
        <div className="container mx-auto px-4 text-center text-skin-muted text-sm">
            <p>© تمامی حقوق مادی و معنوی این سایت متعلق به شرکت دانش بنیان نفس زیست فارمد است.</p>
        </div>
      </footer>

      {/* Modals */}
      {selectedCatalog && (
        <BookViewer 
            catalog={selectedCatalog} 
            onClose={() => setSelectedCatalog(null)} 
        />
      )}

      {selectedVideo && (
        <VideoPlayer
            video={selectedVideo}
            onClose={() => setSelectedVideo(null)}
        />
      )}
    </div>
  );
}

function App() {
  return (
    <CatalogProvider>
      <MainApp />
    </CatalogProvider>
  );
}

