                            className="flex-grow sm:flex-grow-0 bg-skin-primary hover:bg-skin-primary-hover text-white px-4 py-2 rounded-lg flex items-center justify-center gap-2 transition-colors shadow-md text-sm font-bold"
                        >
                            <Plus size={18} />
                            افزودن جدید
