                                            <button onClick={(e) => { e.stopPropagation(); setDeleteConfirmation({id: vid.id, type: 'videos'}); }} className="p-1.5 bg-red-50 text-red-600 rounded hover:bg-red-100"><Trash2 size={14} /></button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>
        )}

