import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import BookViewer from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon } from 'lucide-react';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Display Settings
  const [sortBy, setSortBy] = useState<SortOption>('newest');

  // Default to grid initially, but useEffect will correct it immediately based on screen width
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  // Force responsive layout: List for Mobile, Grid for Desktop
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) {
        setDisplayMode('list');
      } else {
        setDisplayMode('grid');
      }
    };

    // Run immediately on mount
    handleResize();

    // Listen for resize events
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Apply theme to document
  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') {
      document.documentElement.setAttribute('data-theme', theme);
    }
  }, [theme]);

  // Check URL hash for admin shortcut
  useEffect(() => {
    if (window.location.hash === '#admin') {
      setViewMode('admin');
    }
  }, []);

  // Keyboard Shortcut for Admin Panel (Alt + U)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Check for Alt + u (works with both English 'u' and Persian 'ع')
      if (e.altKey && (e.key.toLowerCase() === 'u' || e.key === 'ع')) {
        e.preventDefault(); // Prevent default browser behavior if any
        setViewMode('admin');
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Filter & Sort Logic
  const getProcessedCatalogs = () => {
    let result = catalogs.filter(cat => 
        cat.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        cat.description.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return result.sort((a, b) => {
        switch (sortBy) {
            case 'newest': return b.date.localeCompare(a.date);
            case 'oldest': return a.date.localeCompare(b.date);
            case 'az': return a.title.localeCompare(b.title, 'fa');
            case 'za': return b.title.localeCompare(a.title, 'fa');
            default: return 0;
        }
    });
  };

  const processedCatalogs = getProcessedCatalogs();

  // Filter Videos
  const processedVideos = videos.filter(vid => 
     vid.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
     vid.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const getThemeIcon = () => {
    switch(theme) {
        case 'light': return <Sun size={20} />;
        case 'dark': return <Moon size={20} />;
        case 'reading': return <BookOpen size={20} />;
    }
  };

  const getThemeLabel = () => {
     switch(theme) {
        case 'light': return 'روز';
        case 'dark': return 'شب';
        case 'reading': return 'مطالعه';
    }
  };

  // Admin Logic
  if (viewMode === 'admin') {
    if (!isAuthenticated) {
      return (
        <AdminLogin 
          onLogin={() => setIsAuthenticated(true)} 
          onBack={() => setViewMode('home')} 
        />
      );
    }
    return (
      <AdminPanel 
        onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} 
      />
    );
  }

  return (
    <div className="min-h-screen font-sans bg-skin-base text-skin-text transition-colors duration-300 relative flex flex-col">

      {/* Header */}
      <header className="sticky top-0 z-40 w-full backdrop-blur-lg bg-skin-base/80 border-b border-skin-border">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img 
              src="https://nafaspharmed.com/wp-content/uploads/2025/11/logo_fa.png" 
              alt="نفس فارمد" 
              className="h-10 w-auto object-contain" 
            />
          </div>

          <div className="flex items-center gap-4">
             {/* Search Bar (Desktop) */}
             <div className="hidden md:flex items-center bg-skin-card border border-skin-border rounded-full px-4 py-2 w-80 focus-within:border-skin-primary transition-colors">
                <Search size={18} className="text-skin-muted ml-2" />
                <input 
                    type="text" 
                    placeholder="جستجو..." 
                    className="bg-transparent border-none outline-none text-sm text-skin-text w-full placeholder-skin-muted"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
             </div>

             {/* Theme Toggle */}
             <button 
                onClick={toggleTheme}
                className="flex items-center gap-2 px-3 py-2 rounded-lg bg-skin-card border border-skin-border text-skin-text hover:bg-skin-control-hover transition-colors"
                title="تغییر تم"
             >
                {getThemeIcon()}
                <span className="text-xs font-medium hidden sm:inline">{getThemeLabel()}</span>
             </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8 md:py-12 flex-grow">

        {/* Intro Section */}
        <div className="mb-8 text-center md:text-right border-b border-skin-border pb-8">
            <h2 className="text-2xl md:text-4xl font-black text-skin-text mb-4 leading-tight">
                پورتال آموزشی شرکت داروسازی <span className="text-transparent bg-clip-text bg-gradient-to-r from-skin-primary to-skin-primary-hover">نفس زیست فارمد</span>
            </h2>
            <p className="text-skin-muted text-sm md:text-lg">
                دسترسی سریع به جدیدترین کاتالوگ‌ها، بروشورها و ویدئوهای آموزشی محصولات داروسازی نفس زیست فارمد
            </p>
        </div>

        {/* Mobile Search */}
        <div className="md:hidden mb-6">
             <div className="flex items-center bg-skin-card border border-skin-border rounded-xl px-4 py-3 w-full focus-within:border-skin-primary transition-colors shadow-sm">
                <Search size={20} className="text-skin-muted ml-3" />
                <input 
                    type="text" 
                    placeholder="جستجو..." 
                    className="bg-transparent border-none outline-none text-skin-text w-full placeholder-skin-muted"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>
        </div>

        {/* --- CATALOGS SECTION --- */}
        <div className="mb-12">
            <div className="flex flex-col sm:flex-row justify-between items-end mb-6 gap-4">
                <h3 className="text-xl md:text-2xl font-bold text-skin-text flex items-center gap-2">
                    <BookOpen className="text-skin-primary" />
                    کاتالوگ‌ها و بروشورها
                </h3>

                {/* Toolbar */}
                <div className="flex items-center gap-2 bg-skin-card p-1.5 rounded-xl border border-skin-border shadow-sm">
                     {/* Sort Dropdown */}
                     <div className="relative flex items-center">
                        <ArrowDownUp size={16} className="absolute right-2 text-skin-muted pointer-events-none" />
                        <select
                            value={sortBy}
                            onChange={(e) => setSortBy(e.target.value as SortOption)}
                            className="appearance-none bg-skin-control-bg hover:bg-skin-control-hover text-skin-text text-xs rounded-lg pr-7 pl-2 py-1.5 outline-none cursor-pointer"
                        >
                            <option value="newest">جدیدترین</option>
                            <option value="oldest">قدیمی‌ترین</option>
                            <option value="az">حروف الفبا</option>
                        </select>
                     </div>
                     <div className="w-px h-5 bg-skin-border mx-1"></div>
                     <button onClick={() => setDisplayMode('grid')} className={`p-1.5 rounded-lg ${displayMode === 'grid' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutGrid size={16} /></button>
                     <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-lg ${displayMode === 'list' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutList size={16} /></button>
                </div>
            </div>

            {/* Grid / List Container */}
            {processedCatalogs.length > 0 ? (
                <div className={`grid gap-4 md:gap-6 ${
                    displayMode === 'grid' 
                        ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' 
                        : 'grid-cols-1 md:grid-cols-2'
                }`}>
                {processedCatalogs.map(catalog => (
                    <CatalogCard 
                        key={catalog.id} 
                        catalog={catalog} 
                        onClick={setSelectedCatalog} 
                        viewMode={displayMode}
                    />
                ))}
                </div>
            ) : (
                <div className="py-10 text-center text-skin-muted bg-skin-card border border-dashed border-skin-border rounded-xl">
                    <p>هیچ کاتالوگی یافت نشد.</p>
                </div>
            )}
        </div>

        {/* --- VIDEOS SECTION --- */}
        {processedVideos.length > 0 && (
            <div className="mb-8 pt-8 border-t border-skin-border">
                <div className="mb-6">
                    <h3 className="text-xl md:text-2xl font-bold text-skin-text flex items-center gap-2 mb-2">
                        <VideoIcon className="text-skin-primary" />
                        ویدئوهای آموزشی
                    </h3>
                    <p className="text-skin-muted text-sm">فیلم‌های آموزشی نحوه مصرف و معرفی محصولات</p>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {processedVideos.map(video => (
                        <VideoCard 
                            key={video.id}
                            video={video}
                            onClick={setSelectedVideo}
                        />
                    ))}
                </div>
            </div>
        )}

      </main>

      {/* Footer */}
      <footer className="border-t border-skin-border py-6 mt-12 bg-skin-base/50">
        <div className="container mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <p className="text-skin-muted text-sm text-center">© تمامی حقوق مادی و معنوی این سایت متعلق به شرکت دانش بنیان نفس زیست فارمد است.</p>

            {/* DBS Graphic Credit - In Footer (Non-Floating) */}
            <a 
                href="https://dbsgraphic.ir/" 
                target="_blank" 
                rel="noopener noreferrer"
                dir="ltr"
                className="text-[10px] font-medium text-skin-muted/80 hover:text-skin-primary transition-colors flex items-center gap-1 bg-skin-card/50 px-3 py-1.5 rounded-full border border-skin-border shadow-sm"
            >
                Created with <span className="text-red-500 animate-pulse">❤</span> by DBS Graphic
            </a>
        </div>
      </footer>

      {/* Floating Elements */}

      {/* Nafas Pharmed Button - Bottom Right (Still Floating) */}
      <a 
        href="https://nafaspharmed.com/" 
        target="_blank" 
        rel="noopener noreferrer"
        className="fixed bottom-4 right-4 z-30 bg-skin-primary hover:bg-skin-primary-hover text-white text-xs font-bold px-4 py-2 rounded-full shadow-lg transition-transform hover:-translate-y-1 hover:shadow-xl flex items-center gap-2"
      >
         نفس زیست فارمد
      </a>

      {/* Modals */}
      {selectedCatalog && (
        <BookViewer 
            catalog={selectedCatalog} 
            onClose={() => setSelectedCatalog(null)} 
        />
      )}

      {selectedVideo && (
        <VideoPlayer
            video={selectedVideo}
            onClose={() => setSelectedVideo(null)}
        />
      )}
    </div>
  );
