import React, { createContext, useContext, useState, useEffect } from 'react';
import { Catalog, Video } from '../types';
import { CATALOGS as INITIAL_CATALOGS, VIDEOS as INITIAL_VIDEOS } from '../initialData';

interface CatalogContextType {
  catalogs: Catalog[];
  videos: Video[];
  addCatalog: (catalog: Catalog) => void;
  updateCatalog: (id: string, updatedCatalog: Catalog) => void;
  deleteCatalog: (id: string) => void;
  addVideo: (video: Video) => void;
  updateVideo: (id: string, updatedVideo: Video) => void;
  deleteVideo: (id: string) => void;
  resetToDefault: () => void;
  importData: (catalogs: Catalog[], videos: Video[]) => void;
}

const CatalogContext = createContext<CatalogContextType | undefined>(undefined);

export const CatalogProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [catalogs, setCatalogs] = useState<Catalog[]>([]);
  const [videos, setVideos] = useState<Video[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load Data Strategy:
  // 1. External File (window.NAFAS_DATA from data.js) - Highest Priority
  // 2. LocalStorage (User edits via Admin Panel)
  // 3. Default Hardcoded Data (initialData.ts)
  useEffect(() => {
    // Check for External Data First
    if (window.NAFAS_DATA) {
      console.log('Loading data from external file (data.js)');
      setCatalogs(window.NAFAS_DATA.catalogs || []);
      setVideos(window.NAFAS_DATA.videos || []);
      setIsLoaded(true);
      return;
    }

    // Fallback to LocalStorage
    const savedCatalogs = localStorage.getItem('nafas_catalogs');
    const savedVideos = localStorage.getItem('nafas_videos');

    if (savedCatalogs) {
      try {
        setCatalogs(JSON.parse(savedCatalogs));
      } catch (e) {
        setCatalogs(INITIAL_CATALOGS);
      }
    } else {
      setCatalogs(INITIAL_CATALOGS);
    }

    if (savedVideos) {
      try {
        setVideos(JSON.parse(savedVideos));
      } catch (e) {
        setVideos(INITIAL_VIDEOS);
      }
    } else {
      setVideos(INITIAL_VIDEOS);
    }

    setIsLoaded(true);
  }, []);

  // Save to LocalStorage whenever data changes (Admin Panel usage)
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('nafas_catalogs', JSON.stringify(catalogs));
      localStorage.setItem('nafas_videos', JSON.stringify(videos));
    }
  }, [catalogs, videos, isLoaded]);

  // Catalog Actions
  const addCatalog = (catalog: Catalog) => {
    setCatalogs(prev => [catalog, ...prev]);
  };

  const updateCatalog = (id: string, updatedCatalog: Catalog) => {
    setCatalogs(prev => prev.map(cat => cat.id === id ? updatedCatalog : cat));
  };

  const deleteCatalog = (id: string) => {
    setCatalogs(prev => prev.filter(cat => cat.id !== id));
  };

  // Video Actions
  const addVideo = (video: Video) => {
    setVideos(prev => [video, ...prev]);
  };

  const updateVideo = (id: string, updatedVideo: Video) => {
    setVideos(prev => prev.map(vid => vid.id === id ? updatedVideo : vid));
  };

  const deleteVideo = (id: string) => {
    setVideos(prev => prev.filter(vid => vid.id !== id));
  };

  const resetToDefault = () => {
    if (window.confirm('آیا مطمئن هستید؟ تمام تغییرات شما حذف و به حالت اولیه باز می‌گردد.')) {
      setCatalogs(INITIAL_CATALOGS);
      setVideos(INITIAL_VIDEOS);
      // Also clear localStorage so next time defaults load unless external file exists
      localStorage.removeItem('nafas_catalogs');
      localStorage.removeItem('nafas_videos');
    }
  };

  const importData = (newCatalogs: Catalog[], newVideos: Video[]) => {
    setCatalogs(newCatalogs);
    setVideos(newVideos);
  };

  return (
    <CatalogContext.Provider value={{ 
      catalogs, videos, 
      addCatalog, updateCatalog, deleteCatalog, 
      addVideo, updateVideo, deleteVideo,
      resetToDefault,
      importData 
    }}>
      {children}
    </CatalogContext.Provider>
  );
};

export const useCatalogs = () => {
  const context = useContext(CatalogContext);
  if (context === undefined) {
    throw new Error('useCatalogs must be used within a CatalogProvider');
  }
  return context;
};

import React, { useState, useEffect } from 'react';
import { useCatalogs } from '../context/CatalogContext';
import { Catalog, Video } from '../types';
import { 
  Plus, Trash2, Edit2, Save, X, Upload, 
  Image as ImageIcon, FileText, LayoutGrid, LogOut, Copy, 
  AlertTriangle, Video as VideoIcon, Book, Link as LinkIcon,
  Database, CheckCircle
} from 'lucide-react';

interface AdminPanelProps {
  onLogout: () => void;
}

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

type Tab = 'catalogs' | 'videos';

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogout }) => {
  const { catalogs, videos, addCatalog, updateCatalog, deleteCatalog, addVideo, updateVideo, deleteVideo, resetToDefault, importData } = useCatalogs();

  const [activeTab, setActiveTab] = useState<Tab>('catalogs');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [showExport, setShowExport] = useState(false);
  const [deleteConfirmation, setDeleteConfirmation] = useState<{id: string, type: Tab} | null>(null);

  // Database Code Management
  const [dbCode, setDbCode] = useState('');

  // New state for manual page URL input
  const [newPageUrl, setNewPageUrl] = useState('');

  // Form State - Catalog
  const [catalogForm, setCatalogForm] = useState<Partial<Catalog>>({
    title: '', description: '', date: '', pdfUrl: '', coverImage: '', pages: [], pageCount: 0
  });

  // Form State - Video
  const [videoForm, setVideoForm] = useState<Partial<Video>>({
    title: '', description: '', date: '', videoUrl: '', coverImage: '', duration: ''
  });

  // Update dbCode whenever data changes (unless user is editing it manually?)
  // For simplicity and to ensure sync, we update it, but we let user edit it freely.
  // When 'showExport' is opened, we'll sync it once.
  useEffect(() => {
     if (!showExport) {
        const catalogsJson = JSON.stringify(catalogs, null, 2);
        const videosJson = JSON.stringify(videos, null, 2);
        setDbCode(`window.NAFAS_DATA = {\n  catalogs: ${catalogsJson},\n  videos: ${videosJson}\n};`);
     }
  }, [catalogs, videos, showExport]);

  const resetForms = () => {
    const today = new Date().toLocaleDateString('fa-IR');
    setCatalogForm({
      title: '', description: '', date: today, pdfUrl: '', coverImage: '', pages: [], pageCount: 0
    });
    setVideoForm({
      title: '', description: '', date: today, videoUrl: '', coverImage: '', duration: ''
    });
    setEditingId(null);
    setShowForm(false);
    setNewPageUrl('');
  };

  const handleEdit = (item: Catalog | Video, type: Tab) => {
    if (type === 'catalogs') {
        setCatalogForm(item as Catalog);
    } else {
        setVideoForm(item as Video);
    }
    setEditingId(item.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: string, type: Tab) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      if (type === 'catalogs') {
          if (field === 'cover') {
            const base64 = await fileToBase64(files[0]);
            setCatalogForm(prev => ({ ...prev, coverImage: base64 }));
          } else if (field === 'pages') {
            const newPages = await Promise.all(Array.from(files).map(fileToBase64));
            setCatalogForm(prev => ({
              ...prev,
              pages: [...(prev.pages || []), ...newPages],
              pageCount: (prev.pages?.length || 0) + newPages.length
            }));
          }
      } else {
          // Video Cover
           const base64 = await fileToBase64(files[0]);
           setVideoForm(prev => ({ ...prev, coverImage: base64 }));
      }
    } catch (error) {
      alert('خطا در بارگذاری تصویر');
    }
  };

  const handleAddPageUrl = () => {
    if (!newPageUrl.trim()) return;
    setCatalogForm(prev => ({
        ...prev,
        pages: [...(prev.pages || []), newPageUrl.trim()],
        pageCount: (prev.pages?.length || 0) + 1
    }));
    setNewPageUrl('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (activeTab === 'catalogs') {
        if (!catalogForm.title || !catalogForm.coverImage || !catalogForm.pages?.length) {
            alert('لطفا عنوان، تصویر کاور و صفحات را تکمیل کنید');
            return;
        }
        const data: Catalog = {
            id: editingId || Date.now().toString(),
            title: catalogForm.title!,
            description: catalogForm.description || '',
            date: catalogForm.date || '',
            pdfUrl: catalogForm.pdfUrl || undefined,
            coverImage: catalogForm.coverImage!,
            pages: catalogForm.pages!,
            pageCount: catalogForm.pages!.length
        };
        if (editingId) updateCatalog(editingId, data); else addCatalog(data);

    } else {
        if (!videoForm.title || !videoForm.coverImage || !videoForm.videoUrl) {
            alert('لطفا عنوان، تصویر کاور و آدرس ویدئو را تکمیل کنید');
            return;
        }
        const data: Video = {
            id: editingId || Date.now().toString(),
            title: videoForm.title!,
            description: videoForm.description || '',
            date: videoForm.date || '',
            videoUrl: videoForm.videoUrl!,
            coverImage: videoForm.coverImage!,
            duration: videoForm.duration
        };
        if (editingId) updateVideo(editingId, data); else addVideo(data);
    }
    resetForms();
  };

  const removePage = (index: number) => {
    const newPages = catalogForm.pages?.filter((_, i) => i !== index);
    setCatalogForm(prev => ({ ...prev, pages: newPages, pageCount: newPages?.length || 0 }));
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(dbCode);
    alert('کد کپی شد! حالا محتوای فایل data.js را با این کد جایگزین کنید.');
  };

  const handleApplyCode = () => {
    try {
        // Simple parser to extract JSON object from window assignment
        // Removes 'window.NAFAS_DATA =' from start and ';' from end if present
        let cleanJson = dbCode.trim();
        if (cleanJson.startsWith('window.NAFAS_DATA')) {
            const firstBrace = cleanJson.indexOf('{');
            const lastBrace = cleanJson.lastIndexOf('}');
            if (firstBrace !== -1 && lastBrace !== -1) {
                cleanJson = cleanJson.substring(firstBrace, lastBrace + 1);
            }
        }

        const data = JSON.parse(cleanJson);

        if (Array.isArray(data.catalogs) && Array.isArray(data.videos)) {
            importData(data.catalogs, data.videos);
            alert('تغییرات با موفقیت اعمال شد!');
        } else {
            alert('فرمت کد اشتباه است. باید شامل catalogs و videos باشد.');
        }
    } catch (e) {
        console.error(e);
        alert('خطا در پردازش کد. لطفا مطمئن شوید فرمت صحیح است.');
    }
  };

