  const tapTimeout = useRef<any>(null);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // Handle Resize - OPTIMIZED TO FILL SCREEN
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;

      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);

      // Define available space constraints
      // On mobile we need space for header (approx 60px) and footer controls (approx 80px) + padding
      // On desktop we need space for header (approx 70px) + padding
      const verticalPadding = isSmallScreen ? 100 : 100; 
      const horizontalPadding = isSmallScreen ? 10 : 100;

      const availableHeight = windowHeight - verticalPadding;
      const availableWidth = windowWidth - horizontalPadding;

      // Aspect ratio of A4 paper is approx 1.414 (Height/Width)
      const aspectRatio = 1.414;

      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      // If calculated width is wider than screen, limit by width
      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      setDimensions({ 
          width: Math.floor(bookWidth), 
          height: Math.floor(bookHeight) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Handle Fullscreen events
  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {
            // Auto-play policy might block this without interaction
        });
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip().flipNext();
  const prevFlip = () => bookRef.current?.pageFlip().flipPrev();
  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable fullscreen: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const handleZoomIn = () => {
    setZoomLevel(prev => Math.min(prev + 0.5, 3.0)); // Increase zoom steps
  };

  const handleZoomOut = () => {
    setZoomLevel(prev => Math.max(prev - 0.5, 1)); // Reset to 1 min
  };

  // Smart Tap Handler (Single vs Double Tap)
  const handleTap = (e: React.MouseEvent | React.TouchEvent) => {
    // Only trigger if clicking on the book wrapper, not controls
    const now = Date.now();
    const DOUBLE_TAP_DELAY = 300;

    if (now - lastTap.current < DOUBLE_TAP_DELAY) {
      // DOUBLE TAP DETECTED
      if (tapTimeout.current) {
        clearTimeout(tapTimeout.current);
        tapTimeout.current = null;
      }

      // Toggle Zoom
      if (zoomLevel > 1) {
        setZoomLevel(1);
      } else {
        setZoomLevel(2.5); // Instant Zoom to 2.5x
      }
    } else {
      // POTENTIAL SINGLE TAP
      lastTap.current = now;
      tapTimeout.current = setTimeout(() => {
        // Trigger Single Tap Action (Toggle UI)
        setShowControls(prev => !prev);
      }, DOUBLE_TAP_DELAY);
    }
  };

  const handleDownload = () => {
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex flex-col bg-skin-overlay backdrop-blur-md animate-fade-in transition-all duration-300"
    >
      {/* Header Toolbar */}
      <div 
        className={`flex items-center justify-between p-4 border-b border-skin-border bg-skin-base/90 backdrop-blur-md select-none z-20 shadow-sm transition-opacity duration-300 ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col">
            <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
            <span className="text-skin-muted text-xs mt-0.5">
                 صفحه {currentPage + 1} از {catalog.pages.length}
            </span>
        </div>

        {/* Desktop Controls */}
        <div className="flex items-center gap-2">
            <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomOut size={18} /></button>
                 <span className="text-xs w-8 text-center tabular-nums text-skin-muted select-none">{Math.round(zoomLevel * 100)}%</span>
                <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomIn size={18} /></button>
                <div className="w-px h-5 bg-gray-300 mx-1"></div>
                <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                    {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>
                <button onClick={toggleFullscreen} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                    {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                </button>
                <button onClick={handleDownload} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                    {catalog.pdfUrl ? <FileText size={18} /> : <Download size={18} />}
                </button>
            </div>
            <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border pointer-events-auto">
                <X size={20} />
            </button>
        </div>
      </div>

      {/* Book Container - Updated for Zoom/Pan */}
      <div 
        className={`flex-grow flex relative p-0 md:p-4 bg-skin-base/30 transition-all duration-300 ${zoomLevel > 1 ? 'overflow-auto items-start justify-center' : 'overflow-hidden items-center justify-center'}`}
      >

        {/* Nav Buttons - Desktop (Hide when controls hidden) */}
        <button 
            onClick={(e) => { e.stopPropagation(); nextFlip(); }}
            className={`hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        >
            <ChevronRight size={24} className="group-active:translate-x-1 transition-transform" />
        </button>

        <button 
            onClick={(e) => { e.stopPropagation(); prevFlip(); }}
            className={`hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        >
            <ChevronLeft size={24} className="group-active:-translate-x-1 transition-transform" />
        </button>

        {/* The FlipBook Wrapper */}
        <div 
            onClick={handleTap}
            style={{ 
                transform: `scale(${zoomLevel})`, 
                transition: 'transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94)',
