        className="fixed inset-0 z-50 flex flex-col bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden"
    >
      {/* Header Toolbar */}
      <div 
        className={`flex items-center justify-between p-4 border-b border-skin-border bg-skin-base/90 backdrop-blur-md z-20 shadow-sm transition-opacity duration-300 absolute top-0 left-0 right-0 ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col">
            <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
            <span className="text-skin-muted text-xs mt-0.5">
                 صفحه {currentPage + 1} از {catalog.pages.length}
            </span>
        </div>

        {/* Desktop Controls */}
        <div className="flex items-center gap-2">
            <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomOut size={18} /></button>
                 <span className="text-xs w-8 text-center tabular-nums text-skin-muted select-none">{Math.round(zoomLevel * 100)}%</span>
                <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomIn size={18} /></button>
                <div className="w-px h-5 bg-gray-300 mx-1"></div>
                <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                    {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>
                <button onClick={toggleFullscreen} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                    {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                </button>
                <button onClick={handleDownload} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                    <FileDown size={18} />
                </button>
            </div>
            <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border pointer-events-auto">
                <X size={20} />
            </button>
        </div>
      </div>

      {/* Book Container - Touch & Mouse Handling Wrapper */}
      <div 
        className="flex-grow flex items-center justify-center relative w-full h-full overflow-hidden cursor-grab active:cursor-grabbing"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseLeave}
      >

        {/* Nav Buttons - Desktop */}
        <button 
            onClick={(e) => { e.stopPropagation(); nextFlip(); }}
            className={`hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        >
            <ChevronRight size={24} className="group-active:translate-x-1 transition-transform" />
        </button>

        <button 
            onClick={(e) => { e.stopPropagation(); prevFlip(); }}
            className={`hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        >
            <ChevronLeft size={24} className="group-active:-translate-x-1 transition-transform" />
        </button>

        {/* The FlipBook Wrapper with Transform */}
        <div 
            style={{ 
                transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`,
                transition: isGesturing ? 'none' : 'transform 0.2s ease-out',
                transformOrigin: 'center center',
            }}
            className="flex items-center justify-center relative"
        >
            {/* Page Curl Visual Cues (Interactive on Hover) */}
            {zoomLevel === 1 && totalPages > 0 && (
                <>
                    {/* Left Bottom Curl (Next Page Hint) */}
                    {currentPage < totalPages - 1 && (
                        <div 
                            className="absolute -bottom-2 -left-2 w-16 h-16 z-10 cursor-pointer group transition-all duration-300 hover:scale-125"
                            onClick={(e) => { e.stopPropagation(); nextFlip(); }}
                        >
                            <div className="absolute bottom-0 left-0 w-full h-full bg-gradient-to-tr from-black/30 via-transparent to-transparent rounded-bl-2xl transition-all group-hover:from-skin-primary/40" />
                            <div className="absolute bottom-0 left-0 w-0 h-0 border-b-[24px] border-l-[24px] border-b-white border-l-transparent shadow-lg rotate-90 transition-all group-hover:border-b-[32px] group-hover:border-l-[32px]" />
                        </div>
                    )}
                    {/* Right Bottom Curl (Prev Page Hint) */}
                    {currentPage > 0 && (
                        <div 
                            className="absolute -bottom-2 -right-2 w-16 h-16 z-10 cursor-pointer group transition-all duration-300 hover:scale-125"
                            onClick={(e) => { e.stopPropagation(); prevFlip(); }}
                        >
                            <div className="absolute bottom-0 right-0 w-full h-full bg-gradient-to-tl from-black/30 via-transparent to-transparent rounded-br-2xl transition-all group-hover:from-skin-primary/40" />
                            <div className="absolute bottom-0 right-0 w-0 h-0 border-b-[24px] border-r-[24px] border-b-white border-r-transparent shadow-lg -rotate-90 transition-all group-hover:border-b-[32px] group-hover:border-r-[32px]" />
                        </div>
                    )}
                </>
            )}

            {/* @ts-ignore */}
            <HTMLFlipBook
                width={dimensions.width}
                height={dimensions.height}
                size="fixed"
                minWidth={300}
                maxWidth={3000}
                minHeight={400}
                maxHeight={4000}
                maxShadowOpacity={0.5}
                showCover={false}
                mobileScrollSupport={false}
                onFlip={onFlip}
                onInit={onInit}
                ref={bookRef}
                className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`}
                style={{ margin: '0 auto' }}
                usePortrait={isMobile}
                startPage={0}
                drawShadow={true}
                flippingTime={800}
                useMouseEvents={false}
                swipeDistance={10000}
            >
                {catalog.pages.map((pageUrl, index) => (
                    <Page number={index + 1} key={index}>
                         <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                            <img 
                                src={pageUrl} 
                                alt={`Page ${index + 1}`} 
                                className="w-full h-full object-contain select-none pointer-events-none bg-white"
                                loading={index < 4 ? "eager" : "lazy"}
                                onDragStart={(e) => e.preventDefault()} // Prevent browser image drag
                            />
                         </div>
                    </Page>
                ))}
            </HTMLFlipBook>
        </div>
      </div>

      {/* Mobile Toolbar (Bottom) */}
      <div 
        className={`md:hidden bg-skin-card border-t border-skin-border safe-area-bottom z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] transition-all duration-300 absolute bottom-0 left-0 right-0 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-2 px-4 py-2">
            {/* Zoom Controls Mobile */}
            <div className="flex justify-center items-center gap-4 py-1 border-b border-gray-100 pb-2 mb-1">
                 <button onClick={handleZoomOut} className="p-1.5 bg-gray-100 rounded text-gray-600">
                    <ZoomOut size={16} />
                 </button>
                 <span className="text-xs font-mono text-gray-500 w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                 <button onClick={handleZoomIn} className="p-1.5 bg-gray-100 rounded text-gray-600">
                    <ZoomIn size={16} />
                 </button>
            </div>

            <div className="flex justify-between items-center">
                <button 
                    onClick={nextFlip}
                    className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors"
                >
                    <ChevronRight size={24} />
                </button>

                <div className="flex gap-4 text-skin-muted">
                    <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">
                        {isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                    </button>
                    <button onClick={handleDownload} className="p-2">
                        <FileDown size={20} />
                    </button>
                </div>

                <button 
                    onClick={prevFlip}
                    className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors"
                >
                    <ChevronLeft size={24} />
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

