import React, { useRef, useState } from 'react';
import { Catalog } from '../types';
import { BookOpen, Calendar, ChevronLeft, Download } from 'lucide-react';

interface CatalogCardProps {
  catalog: Catalog;
  onClick: (catalog: Catalog) => void;
  viewMode?: 'grid' | 'list';
}

const CatalogCard: React.FC<CatalogCardProps> = ({ catalog, onClick, viewMode = 'grid' }) => {
  const isList = viewMode === 'list';
  const cardRef = useRef<HTMLDivElement>(null);
  const [transform, setTransform] = useState('');

  // 3D Tilt Logic
  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current || isList) return;
    const { left, top, width, height } = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - left) / width;
    const y = (e.clientY - top) / height;

    // Tilt limit (degrees)
    const tiltX = (0.5 - y) * 20; 
    const tiltY = (x - 0.5) * 20;

    setTransform(`perspective(1000px) rotateX(${tiltX}deg) rotateY(${tiltY}deg) scale(1.02)`);
  };

  const handleMouseLeave = () => {
    setTransform('');
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    const link = document.createElement('a');

    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title}.jpg`;
    }

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div 
      ref={cardRef}
      onClick={() => onClick(catalog)}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{ transform: transform, transition: transform ? 'transform 0.1s ease-out' : 'transform 0.5s ease-out' }}
      className={`group bg-skin-card border border-skin-border rounded-2xl overflow-hidden cursor-pointer shadow-sm hover:shadow-2xl hover:border-skin-primary flex ${isList ? 'flex-row h-40 sm:h-48' : 'flex-col h-full'} will-change-transform`}
    >
      <div className={`relative overflow-hidden bg-gray-200 ${isList ? 'w-1/3 sm:w-40 shrink-0' : 'aspect-[3/4] w-full'}`}>
        <img 
          src={catalog.coverImage} 
          alt={catalog.title}
          loading="lazy"
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-80" />

        {/* Category Badge */}
        {catalog.category && (
             <div className="absolute top-3 left-3 bg-black/50 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-md">
                {catalog.category}
             </div>
        )}

        {/* Updated Badge */}
        <div className={`absolute top-3 right-3 bg-skin-primary text-white text-[10px] sm:text-xs font-bold px-2 py-0.5 sm:px-3 sm:py-1 rounded-full shadow-lg backdrop-blur-sm bg-opacity-90`}>
            بروز شده
        </div>
      </div>

      <div className={`flex flex-col flex-grow ${isList ? 'p-3 sm:p-5 justify-center' : 'p-5'}`}>
        <div className="flex items-center gap-2 text-skin-primary text-xs sm:text-sm mb-1 sm:mb-2 font-medium">
            <BookOpen size={isList ? 14 : 16} />
            <span>{catalog.pageCount} صفحه</span>
        </div>

        <h3 className={`font-bold text-skin-text mb-1 sm:mb-2 leading-tight group-hover:text-skin-primary transition-colors ${isList ? 'text-base sm:text-xl' : 'text-xl'}`}>
          {catalog.title}
        </h3>

        <p className={`text-skin-muted text-xs sm:text-sm line-clamp-2 ${isList ? 'mb-2' : 'mb-4 flex-grow'}`}>
          {catalog.description}
        </p>

        <div className={`flex items-center justify-between border-skin-border pt-2 sm:pt-4 ${isList ? 'mt-0 border-t-0' : 'mt-auto border-t'}`}>
            <span className="flex items-center text-skin-muted text-[10px] sm:text-xs">
                <Calendar size={12} className="mr-1 ml-1 sm:w-3.5 sm:h-3.5" />
                {catalog.date}
            </span>

            <div className="flex items-center gap-2">
                <button 
                  onClick={handleDownload}
                  className="p-1.5 text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg rounded-full transition-colors"
                  title="دانلود"
                >
                    <Download size={18} />
                </button>
                <span className={`flex items-center text-skin-text text-xs sm:text-sm font-medium group-hover:translate-x-[-4px] transition-transform ${isList ? 'hidden sm:flex' : ''}`}>
                    مشاهده
                    <ChevronLeft size={16} className="mr-1" />
                </span>
            </div>
        </div>
      </div>
    </div>
  );
};

