import React, { useRef, useState } from 'react';
import { Catalog } from '../types';
import { BookOpen, Calendar, ChevronLeft, Download } from 'lucide-react';

interface CatalogCardProps {
  catalog: Catalog;
  onClick: (catalog: Catalog) => void;
  viewMode?: 'grid' | 'list';
}

const CatalogCard: React.FC<CatalogCardProps> = ({ catalog, onClick, viewMode = 'grid' }) => {
  const isList = viewMode === 'list';
  const cardRef = useRef<HTMLDivElement>(null);
  const [transform, setTransform] = useState('');

  // 3D Tilt Logic
  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current || isList) return;
    const { left, top, width, height } = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - left) / width;
    const y = (e.clientY - top) / height;

    // Tilt limit (degrees)
    const tiltX = (0.5 - y) * 20; 
    const tiltY = (x - 0.5) * 20;

    setTransform(`perspective(1000px) rotateX(${tiltX}deg) rotateY(${tiltY}deg) scale(1.02)`);
  };

  const handleMouseLeave = () => {
    setTransform('');
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    const link = document.createElement('a');

    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title}.jpg`;
    }

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Language Badge Helper
  const getLangBadge = (lang?: string) => {
      if (lang === 'en') return { flag: '🇬🇧', code: 'EN' };
      return { flag: '🇮🇷', code: 'IR' };
  };

  const langData = getLangBadge(catalog.language);

  return (
    <div 
      ref={cardRef}
      onClick={() => onClick(catalog)}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{ transform: transform, transition: transform ? 'transform 0.1s ease-out' : 'transform 0.5s ease-out' }}
      className={`group bg-skin-card border border-skin-border rounded-2xl overflow-hidden cursor-pointer shadow-sm hover:shadow-2xl hover:border-skin-primary flex ${isList ? 'flex-row h-40 sm:h-48' : 'flex-col h-full'} will-change-transform`}
    >
      <div className={`relative overflow-hidden bg-gray-200 ${isList ? 'w-1/3 sm:w-40 shrink-0' : 'aspect-[3/4] w-full'}`}>
        <img 
          src={catalog.coverImage} 
          alt={catalog.title}
          loading="lazy"
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-80" />

        {/* Badges Container */}
        <div className="absolute top-3 left-3 flex gap-2">
            {/* Category Badge */}
            {catalog.category && (
                <div className="bg-black/50 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-md">
                    {catalog.category}
                </div>
            )}

            {/* Language Badge */}
            <div className="bg-black/50 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-md flex items-center gap-1" title={catalog.language === 'en' ? 'انگلیسی' : 'فارسی'}>
                <span className="text-xs leading-none">{langData.flag}</span>
                <span className="font-bold leading-none pt-0.5">{langData.code}</span>
            </div>
        </div>

      </div>

      <div className={`flex flex-col flex-grow ${isList ? 'p-3 sm:p-5 justify-center' : 'p-5'}`}>
        <div className="flex items-center gap-2 text-skin-primary text-xs sm:text-sm mb-1 sm:mb-2 font-medium">
            <BookOpen size={isList ? 14 : 16} />
            <span>{catalog.pageCount} صفحه</span>
        </div>

        <h3 className={`font-bold text-skin-text mb-1 sm:mb-2 leading-tight group-hover:text-skin-primary transition-colors ${isList ? 'text-base sm:text-xl' : 'text-xl'}`}>
          {catalog.title}
        </h3>

        <p className={`text-skin-muted text-xs sm:text-sm line-clamp-2 ${isList ? 'mb-2' : 'mb-4 flex-grow'}`}>
          {catalog.description}
        </p>

        <div className={`flex items-center justify-between border-skin-border pt-2 sm:pt-4 ${isList ? 'mt-0 border-t-0' : 'mt-auto border-t'}`}>
            <span className="flex items-center text-skin-muted text-[10px] sm:text-xs">
                <Calendar size={12} className="mr-1 ml-1 sm:w-3.5 sm:h-3.5" />
                {catalog.date}
            </span>

            <div className="flex items-center gap-2">
                <button 
                  onClick={handleDownload}
                  className="p-1.5 text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg rounded-full transition-colors"
                  title="دانلود"
                >
                    <Download size={18} />
                </button>
                <span className={`flex items-center text-skin-text text-xs sm:text-sm font-medium group-hover:translate-x-[-4px] transition-transform ${isList ? 'hidden sm:flex' : ''}`}>
                    مشاهده
                    <ChevronLeft size={16} className="mr-1" />
                </span>
            </div>
        </div>
      </div>
    </div>
  );
};

export default CatalogCard;

import React, { useState, useEffect } from 'react';
import { useCatalogs } from '../context/CatalogContext';
import { Catalog, Video } from '../types';
import { 
  Plus, Trash2, Edit2, Save, X, Upload, 
  Image as ImageIcon, FileText, LayoutGrid, LogOut, Copy, 
  AlertTriangle, Video as VideoIcon, Book, Link as LinkIcon,
  Database, CheckCircle, Tag, Globe
} from 'lucide-react';

interface AdminPanelProps {
  onLogout: () => void;
}

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

type Tab = 'catalogs' | 'videos';

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogout }) => {
  const { catalogs, videos, addCatalog, updateCatalog, deleteCatalog, addVideo, updateVideo, deleteVideo, resetToDefault, importData } = useCatalogs();

  const [activeTab, setActiveTab] = useState<Tab>('catalogs');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [showExport, setShowExport] = useState(false);
  const [deleteConfirmation, setDeleteConfirmation] = useState<{id: string, type: Tab} | null>(null);

  // Database Code Management
  const [dbCode, setDbCode] = useState('');

  // New state for manual page URL input
  const [newPageUrl, setNewPageUrl] = useState('');

  // Form State - Catalog
  const [catalogForm, setCatalogForm] = useState<Partial<Catalog>>({
    title: '', description: '', date: '', pdfUrl: '', coverImage: '', pages: [], pageCount: 0, category: 'عمومی', language: 'fa'
  });

  // Form State - Video
  const [videoForm, setVideoForm] = useState<Partial<Video>>({
    title: '', description: '', date: '', videoUrl: '', coverImage: '', duration: ''
  });

  // Calculate unique categories for suggestions
  const uniqueCategories = Array.from(new Set(catalogs.map(c => c.category))).filter(Boolean);

  // Update dbCode whenever data changes (unless user is editing it manually?)
  // For simplicity and to ensure sync, we update it, but we let user edit it freely.
  // When 'showExport' is opened, we'll sync it once.
  useEffect(() => {
     if (!showExport) {
        const catalogsJson = JSON.stringify(catalogs, null, 2);
        const videosJson = JSON.stringify(videos, null, 2);
        setDbCode(`window.NAFAS_DATA = {\n  catalogs: ${catalogsJson},\n  videos: ${videosJson}\n};`);
     }
  }, [catalogs, videos, showExport]);

  const resetForms = () => {
    const today = new Date().toLocaleDateString('fa-IR');
    setCatalogForm({
      title: '', description: '', date: today, pdfUrl: '', coverImage: '', pages: [], pageCount: 0, category: 'عمومی', language: 'fa'
    });
    setVideoForm({
      title: '', description: '', date: today, videoUrl: '', coverImage: '', duration: ''
    });
    setEditingId(null);
    setShowForm(false);
    setNewPageUrl('');
  };

  const handleEdit = (item: Catalog | Video, type: Tab) => {
    if (type === 'catalogs') {
        setCatalogForm(item as Catalog);
    } else {
        setVideoForm(item as Video);
    }
    setEditingId(item.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: string, type: Tab) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      if (type === 'catalogs') {
          if (field === 'cover') {
            const base64 = await fileToBase64(files[0]);
            setCatalogForm(prev => ({ ...prev, coverImage: base64 }));
          } else if (field === 'pages') {
            const newPages = await Promise.all(Array.from(files).map(fileToBase64));
            setCatalogForm(prev => ({
              ...prev,
              pages: [...(prev.pages || []), ...newPages],
              pageCount: (prev.pages?.length || 0) + newPages.length
            }));
          }
      } else {
          // Video Cover
           const base64 = await fileToBase64(files[0]);
           setVideoForm(prev => ({ ...prev, coverImage: base64 }));
      }
    } catch (error) {
      alert('خطا در بارگذاری تصویر');
    }
  };

  const handleAddPageUrl = () => {
    if (!newPageUrl.trim()) return;
    setCatalogForm(prev => ({
        ...prev,
        pages: [...(prev.pages || []), newPageUrl.trim()],
        pageCount: (prev.pages?.length || 0) + 1
    }));
    setNewPageUrl('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (activeTab === 'catalogs') {
        if (!catalogForm.title || !catalogForm.coverImage || !catalogForm.pages?.length) {
            alert('لطفا عنوان، تصویر کاور و صفحات را تکمیل کنید');
            return;
        }
        const data: Catalog = {
            id: editingId || Date.now().toString(),
            title: catalogForm.title!,
            description: catalogForm.description || '',
            date: catalogForm.date || '',
            pdfUrl: catalogForm.pdfUrl || undefined,
            coverImage: catalogForm.coverImage!,
            pages: catalogForm.pages!,
            pageCount: catalogForm.pages!.length,
            category: catalogForm.category || 'عمومی',
            language: catalogForm.language || 'fa'
        };
        if (editingId) updateCatalog(editingId, data); else addCatalog(data);

    } else {
        if (!videoForm.title || !videoForm.coverImage || !videoForm.videoUrl) {
            alert('لطفا عنوان، تصویر کاور و آدرس ویدئو را تکمیل کنید');
            return;
        }
        const data: Video = {
            id: editingId || Date.now().toString(),
            title: videoForm.title!,
            description: videoForm.description || '',
            date: videoForm.date || '',
            videoUrl: videoForm.videoUrl!,
            coverImage: videoForm.coverImage!,
            duration: videoForm.duration
        };
        if (editingId) updateVideo(editingId, data); else addVideo(data);
    }
    resetForms();
  };

  const removePage = (index: number) => {
    const newPages = catalogForm.pages?.filter((_, i) => i !== index);
    setCatalogForm(prev => ({ ...prev, pages: newPages, pageCount: newPages?.length || 0 }));
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(dbCode);
    alert('کد کپی شد! حالا محتوای فایل data.js را با این کد جایگزین کنید.');
  };

  const handleApplyCode = () => {
    try {
        // Simple parser to extract JSON object from window assignment
        // Removes 'window.NAFAS_DATA =' from start and ';' from end if present
        let cleanJson = dbCode.trim();
        if (cleanJson.startsWith('window.NAFAS_DATA')) {
            const firstBrace = cleanJson.indexOf('{');
            const lastBrace = cleanJson.lastIndexOf('}');
            if (firstBrace !== -1 && lastBrace !== -1) {
                cleanJson = cleanJson.substring(firstBrace, lastBrace + 1);
            }
        }

        const data = JSON.parse(cleanJson);

        if (Array.isArray(data.catalogs) && Array.isArray(data.videos)) {
            importData(data.catalogs, data.videos);
            alert('تغییرات با موفقیت اعمال شد!');
        } else {
            alert('فرمت کد اشتباه است. باید شامل catalogs و videos باشد.');
        }
    } catch (e) {
        console.error(e);
        alert('خطا در پردازش کد. لطفا مطمئن شوید فرمت صحیح است.');
    }
  };

  const confirmDelete = () => {
    if (deleteConfirmation) {
      if (deleteConfirmation.type === 'catalogs') {
          deleteCatalog(deleteConfirmation.id);
      } else {
          deleteVideo(deleteConfirmation.id);
      }
      setDeleteConfirmation(null);
    }
  };

  return (
    <div className="min-h-screen bg-skin-base text-skin-text pb-20">

      {/* Delete Confirmation Modal */}
      {deleteConfirmation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
            <div className="bg-skin-card rounded-xl shadow-2xl max-w-sm w-full p-6 border border-skin-border">
                <div className="flex items-center gap-3 text-red-600 mb-4">
                    <div className="p-3 bg-red-100 rounded-full">
                        <AlertTriangle size={24} />
                    </div>
                    <h3 className="text-lg font-bold text-skin-text">حذف آیتم</h3>
                </div>
                <p className="text-skin-muted mb-6 text-sm leading-relaxed">
                    آیا از حذف این آیتم اطمینان دارید؟ این عملیات غیرقابل بازگشت است.
                </p>
                <div className="flex justify-end gap-3">
                    <button 
                        onClick={() => setDeleteConfirmation(null)}
                        className="px-4 py-2 text-skin-muted hover:bg-skin-control-bg rounded-lg transition-colors text-sm font-medium"
                    >
                        انصراف
                    </button>
                    <button 
                        onClick={confirmDelete}
                        className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors shadow-md text-sm font-medium flex items-center gap-2"
                    >
                        <Trash2 size={16} />
                        بله، حذف شود
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Admin Header */}
      <header className="bg-skin-card border-b border-skin-border sticky top-0 z-20">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 font-bold text-skin-primary">
            <LayoutGrid />
            <span className="hidden sm:inline">پنل مدیریت پیشرفته</span>
          </div>
          <div className="flex items-center gap-3">
             <button 
                onClick={() => setShowExport(!showExport)}
