                                     <input 
                                        className="w-full p-2 text-sm bg-skin-control-bg border border-skin-border rounded-lg dir-ltr"
                                        value={activeTab === 'catalogs' ? catalogForm.coverImage : videoForm.coverImage}
                                        onChange={e => activeTab === 'catalogs' ? setCatalogForm({...catalogForm, coverImage: e.target.value}) : setVideoForm({...videoForm, coverImage: e.target.value})}
