  return (
    <div 
      onClick={() => onClick(catalog)}
      className={`group bg-skin-card border border-skin-border rounded-2xl overflow-hidden cursor-pointer shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 flex ${isList ? 'flex-row h-40 sm:h-48' : 'flex-col h-full'}`}
    >
      <div className={`relative overflow-hidden bg-gray-200 ${isList ? 'w-1/3 sm:w-40 shrink-0' : 'aspect-[3/4] w-full'}`}>
        <img 
          src={catalog.coverImage} 
          alt={catalog.title}
          loading="lazy"
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-80" />

        {/* Badges Container */}
        <div className="absolute top-3 left-3 flex gap-2">
            {/* Category Badge */}
            {catalog.category && (
                <div className="bg-black/50 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-md">
                    {catalog.category}
                </div>
            )}

            {/* Language Badge */}
            <div className="bg-black/50 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-md flex items-center gap-1.5" title={catalog.language === 'en' ? 'انگلیسی' : 'فارسی'}>
                <img src={langData.img} alt={langData.code} className="w-4 h-3 object-cover rounded-[1px]" />
                <span className="font-bold leading-none pt-0.5">{langData.code}</span>
