import { Catalog } from '../types';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  Maximize, 
  Minimize, 
  Volume2, 
  VolumeX,
  FileDown,
  ZoomIn,
  ZoomOut,
  Book,
  Smartphone,
  List,
  ChevronUp,
  ChevronDown
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
}

// Sound effect URL
const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// Helper for distance between two touch points
const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

// ForwardRef for Page
const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

