  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;
      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);

      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 0 : 100;

      const availableHeight = windowHeight - verticalPadding;
      const availableWidth = windowWidth - horizontalPadding;

      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      setDimensions({ 
          width: Math.floor(bookWidth), 
          height: Math.floor(bookHeight) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    if (zoomLevel <= 1) {
      setPan({ x: 0, y: 0 });
    }
  }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  // SAFE PAGE FLIP ACCESS
  const nextFlip = () => bookRef.current?.pageFlip()?.flipNext();
  const prevFlip = () => bookRef.current?.pageFlip()?.flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip()?.flip(index);

  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(err => console.error(err));
    } else {
        document.exitFullscreen();
    }
  };

  const handleZoomIn = () => setZoomLevel(prev => {
      const next = Math.round((prev + 0.1) * 10) / 10;
      return Math.min(next, 4.0);
  });

  const handleZoomOut = () => setZoomLevel(prev => {
      const next = Math.round((prev - 0.1) * 10) / 10;
      return Math.max(next, 0.5);
  });

  const handleDownload = () => {
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
        setShowShareTooltip(true);
        setTimeout(() => setShowShareTooltip(false), 2000);
    });
  };

  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    if (annotationMode !== 'none') return;

    setIsGesturing(true);
    gesture.current.startX = clientX;
    gesture.current.startY = clientY;
    gesture.current.mode = mode;

    if (mode === 'pan') {
      gesture.current.startPanX = pan.x;
      gesture.current.startPanY = pan.y;
    }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode === 'pan') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      setPan({ 
        x: gesture.current.startPanX + dx, 
        y: gesture.current.startPanY + dy 
      });
    }
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (annotationMode !== 'none') return;
    setIsGesturing(false);

    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      const absDx = Math.abs(dx);
      const absDy = Math.abs(dy);

      if (absDx > 30 && absDx > absDy) {
        if (dx > 0) prevFlip(); 
        else nextFlip(); 
      }
    }

    if (gesture.current.mode === 'pinch') {
       if (zoomLevel < 1.1) setZoomLevel(1);
    }

    gesture.current.mode = 'none';
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (e.touches.length === 2) {
      setIsGesturing(true);
      gesture.current.mode = 'pinch';
      gesture.current.startDist = getDistance(e.touches);
      gesture.current.startZoom = zoomLevel;
    } else if (e.touches.length === 1) {
      const mode = zoomLevel > 1 ? 'pan' : 'swipe';
      startGesture(e.touches[0].clientX, e.touches[0].clientY, mode);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode === 'pinch' && e.touches.length === 2) {
      const dist = getDistance(e.touches);
      const scale = (dist / gesture.current.startDist) * gesture.current.startZoom;
      setZoomLevel(Math.min(Math.max(scale, 0.5), 4));
    } else if (e.touches.length === 1) {
      moveGesture(e.touches[0].clientX, e.touches[0].clientY);
    }
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    const touch = e.changedTouches[0];
    endGesture(touch.clientX, touch.clientY);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (annotationMode !== 'none') return;
    if (e.button !== 0) return;
    e.preventDefault(); 
    const mode = zoomLevel > 1 ? 'pan' : 'swipe';
    startGesture(e.clientX, e.clientY, mode);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode !== 'none') {
       e.preventDefault();
       moveGesture(e.clientX, e.clientY);
    }
  };

  const handleMouseUp = (e: React.MouseEvent) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode !== 'none') {
       endGesture(e.clientX, e.clientY);
    }
  };

  const handleMouseLeave = (e: React.MouseEvent) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode !== 'none') {
       endGesture(e.clientX, e.clientY);
    }
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden"
    >
      <div className="flex-grow flex flex-col h-full relative">
        {/* --- TOP PANEL --- */}
        <div 
            className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-20 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}
        >
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <div className="flex items-center gap-2 text-skin-muted text-xs mt-0.5">
                        <span>صفحه {currentPage + 1} از {catalog.pages.length}</span>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                        <div className="flex items-center gap-1 pr-1 border-l border-gray-300 ml-1 pl-1">
                            <button 
                                onClick={() => setAnnotationMode(annotationMode === 'pen' ? 'none' : 'pen')} 
                                className={`p-2 rounded-md transition-colors ${annotationMode === 'pen' ? 'bg-skin-primary text-white shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`}
                                title="هایلایت"
                            >
                                <PenTool size={18} />
                            </button>
                            <button 
                                onClick={() => setAnnotationMode(annotationMode === 'note' ? 'none' : 'note')} 
                                className={`p-2 rounded-md transition-colors ${annotationMode === 'note' ? 'bg-skin-primary text-white shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`}
                                title="یادداشت"
                            >
                                <NoteIcon size={18} />
                            </button>
                             <button 
                                onClick={() => setAnnotationMode(annotationMode === 'eraser' ? 'none' : 'eraser')} 
                                className={`p-2 rounded-md transition-colors ${annotationMode === 'eraser' ? 'bg-red-500 text-white shadow-sm' : 'text-skin-control-text hover:bg-red-100 hover:text-red-500'}`}
                                title="پاک‌کن صفحه"
                            >
                                <Eraser size={18} />
                            </button>
                        </div>

                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors" title={forceSinglePage ? "مشاهده دو صفحه" : "مشاهده تک صفحه"}>
                            {forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}
                        </button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomOut size={18} /></button>
                        <span className="text-xs w-8 text-center tabular-nums text-skin-muted select-none">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomIn size={18} /></button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                        </button>
                        <button onClick={toggleFullscreen} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                        </button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <div className="relative">
                            <button onClick={handleShare} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                                <Share2 size={18} />
                            </button>
                            {showShareTooltip && (
                                <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded whitespace-nowrap animate-fade-in flex items-center gap-1">
                                    <Check size={10} />
                                    لینک کپی شد
                                </div>
                            )}
                        </div>

                        <button onClick={handleDownload} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            <FileDown size={18} />
                        </button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border pointer-events-auto">
                        <X size={20} />
                    </button>
                </div>
            </div>

            <div className="flex justify-center -mb-3 pb-1">
                 <button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 shadow-sm text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg transition-colors">
                    <ChevronUp size={16} />
                 </button>
            </div>
        </div>

        <button 
            onClick={() => setShowTopPanel(true)}
            className={`absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all duration-300 ${!showTopPanel ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-full pointer-events-none'}`}
        >
            <ChevronDown size={20} />
        </button>

        {/* Book Container */}
        <div 
            className="flex-grow flex items-center justify-center relative w-full h-full overflow-hidden cursor-grab active:cursor-grabbing pb-20 pt-20" 
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseLeave}
            style={{ cursor: annotationMode !== 'none' ? 'crosshair' : 'grab' }}
        >
             {annotationMode === 'none' && (
                <>
                    <button onClick={(e) => { e.stopPropagation(); nextFlip(); }} className={`hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group opacity-100`}>
                        <ChevronRight size={24} className="group-active:translate-x-1 transition-transform" />
                    </button>

                    <button onClick={(e) => { e.stopPropagation(); prevFlip(); }} className={`hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group opacity-100`}>
                        <ChevronLeft size={24} className="group-active:-translate-x-1 transition-transform" />
                    </button>
                </>
             )}

            <div 
                style={{ 
                    transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`,
                    transition: isGesturing ? 'none' : 'transform 0.2s ease-out',
                    transformOrigin: 'center center',
                }}
                className="flex items-center justify-center relative"
            >
                {zoomLevel <= 1 && totalPages > 0 && annotationMode === 'none' && (
                    <>
                        {currentPage < totalPages - 1 && (
                            <div className="absolute -bottom-2 -left-2 w-16 h-16 z-10 cursor-pointer group transition-all duration-300 hover:scale-125" onClick={(e) => { e.stopPropagation(); nextFlip(); }}>
                                <div className="absolute bottom-0 left-0 w-full h-full bg-gradient-to-tr from-black/30 via-transparent to-transparent rounded-bl-2xl transition-all group-hover:from-skin-primary/40" />
                                <div className="absolute bottom-0 left-0 w-0 h-0 border-b-[24px] border-l-[24px] border-b-white border-l-transparent shadow-lg rotate-90 transition-all group-hover:border-b-[32px] group-hover:border-l-[32px]" />
                            </div>
                        )}
                        {currentPage > 0 && (
                            <div className="absolute -bottom-2 -right-2 w-16 h-16 z-10 cursor-pointer group transition-all duration-300 hover:scale-125" onClick={(e) => { e.stopPropagation(); prevFlip(); }}>
                                <div className="absolute bottom-0 right-0 w-full h-full bg-gradient-to-tl from-black/30 via-transparent to-transparent rounded-br-2xl transition-all group-hover:from-skin-primary/40" />
                                <div className="absolute bottom-0 right-0 w-0 h-0 border-b-[24px] border-r-[24px] border-b-white border-r-transparent shadow-lg -rotate-90 transition-all group-hover:border-b-[32px] group-hover:border-r-[32px]" />
                            </div>
                        )}
                    </>
                )}

                {/* @ts-ignore */}
                <HTMLFlipBook
                    key={`${dimensions.width}-${forceSinglePage}`} 
                    width={dimensions.width}
                    height={dimensions.height}
                    size="fixed"
                    minWidth={300}
                    maxWidth={3000}
                    minHeight={400}
                    maxHeight={4000}
                    maxShadowOpacity={0.5}
                    showCover={false}
                    mobileScrollSupport={false}
                    onFlip={onFlip}
                    onInit={onInit}
                    ref={bookRef}
                    className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`}
                    style={{ margin: '0 auto' }}
                    usePortrait={isMobile || forceSinglePage}
                    startPage={initialPage}
                    drawShadow={true}
                    flippingTime={800}
                    useMouseEvents={false}
                    swipeDistance={10000}
                >
                    {catalog.pages.map((pageUrl, index) => (
                        <Page 
                            number={index + 1} 
                            key={index}
                            catalogId={catalog.id}
                            annotationMode={annotationMode}
                            activeColor={highlightColor}
                        >
                             <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                                <img 
                                    src={pageUrl} 
                                    alt={`Page ${index + 1}`} 
                                    className="w-full h-full object-contain select-none pointer-events-none bg-white"
                                    loading={index < 4 ? "eager" : "lazy"}
                                    onDragStart={(e) => e.preventDefault()}
                                />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>
        </div>

        {/* --- BOTTOM PANEL --- */}
        <div className={`absolute bottom-0 left-0 right-0 z-20 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>

             <div className="flex justify-center -mt-3 pt-1 pointer-events-none">
                 <button onClick={() => setShowBottomPanel(false)} className="pointer-events-auto bg-skin-card border border-skin-border rounded-full p-1 shadow-sm text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg transition-colors relative z-30">
                    <ChevronDown size={16} />
                 </button>
             </div>

            <div 
                className={`md:hidden bg-skin-card border-t border-skin-border shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]`}
            >
                <div className="flex flex-col gap-2 px-4 py-2">
                    <div className="flex justify-center items-center gap-4 py-1 border-b border-gray-100 pb-2 mb-1">
                        <button onClick={handleZoomOut} className="p-1.5 bg-gray-100 rounded text-gray-600"><ZoomOut size={16} /></button>
                        <span className="text-xs font-mono text-gray-500 w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-1.5 bg-gray-100 rounded text-gray-600"><ZoomIn size={16} /></button>
                    </div>

                    <div className="flex justify-center items-center gap-2 pb-2 border-b border-gray-100 mb-1">
                        <button onClick={() => setAnnotationMode(annotationMode === 'pen' ? 'none' : 'pen')} className={`p-2 rounded ${annotationMode === 'pen' ? 'bg-skin-primary text-white' : 'bg-gray-100'}`}><PenTool size={16} /></button>
                        <button onClick={() => setAnnotationMode(annotationMode === 'note' ? 'none' : 'note')} className={`p-2 rounded ${annotationMode === 'note' ? 'bg-skin-primary text-white' : 'bg-gray-100'}`}><NoteIcon size={16} /></button>
                         <button onClick={() => setAnnotationMode(annotationMode === 'eraser' ? 'none' : 'eraser')} className={`p-2 rounded ${annotationMode === 'eraser' ? 'bg-red-500 text-white' : 'bg-gray-100'}`}><Eraser size={16} /></button>
                        <button onClick={handleShare} className="p-2 bg-gray-100 rounded text-gray-700 relative">
                             <Share2 size={16} />
                              {showShareTooltip && <span className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[9px] px-1 rounded">کپی شد</span>}
                        </button>
                    </div>

                    <div className="flex justify-between items-center">
                        <button onClick={nextFlip} className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors">
                            <ChevronRight size={24} />
                        </button>

                        <div className="flex gap-4 text-skin-muted">
                            <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">
                                {isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                            </button>
                            <button onClick={handleDownload} className="p-2"><FileDown size={20} /></button>
                        </div>

                        <button onClick={prevFlip} className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors">
                            <ChevronLeft size={24} />
                        </button>
                    </div>
                </div>
            </div>

            <div className={`h-20 bg-skin-card/90 backdrop-blur-md border-t border-skin-border flex items-center px-4 gap-2 overflow-x-auto`}>
                 {catalog.pages.map((page, idx) => (
                     <button 
                        key={idx} 
                        onClick={() => goToPage(idx)}
                        className={`shrink-0 h-16 w-12 rounded border-2 overflow-hidden transition-all ${currentPage === idx ? 'border-skin-primary scale-110 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}
                     >
                         <img src={page} className="w-full h-full object-cover" loading="lazy" />
                     </button>
                 ))}
            </div>
        </div>

        <button 
            onClick={() => setShowBottomPanel(true)}
            className={`absolute bottom-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all duration-300 ${!showBottomPanel ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'}`}
        >
            <ChevronUp size={20} />
        </button>

      </div>
    </div>
  );
};

export default BookViewer;

export interface Catalog {
  id: string;
  title: string;
  description: string;
  coverImage: string;
  pages: string[];
  pdfUrl?: string;
  date: string;
  pageCount: number;
  category: string;
  language?: 'fa' | 'en';
  toc?: { title: string; page: number }[];
}

export interface Video {
  id: string;
  title: string;
  description: string;
  coverImage: string;
  videoUrl: string;
  date: string;
  duration?: string;
}

export interface ViewerSettings {
  sound: boolean;
  autoPlay: boolean;
}

// Annotation Types
export interface Point {
  x: number;
  y: number;
}

export interface DrawingPath {
  points: Point[];
  color: string;
  width: number;
}

export interface StickyNote {
  id: string;
  x: number;
  y: number;
  text: string;
  color: string;
}

export interface PageAnnotation {
  paths: DrawingPath[];
  notes: StickyNote[];
}

// Global definition for external data file
declare global {
  interface Window {
    NAFAS_DATA?: {
      catalogs: Catalog[];
      videos: Video[];
    };
  }
}

import React, { useRef, useState, useEffect } from 'react';
import { PageAnnotation, DrawingPath, StickyNote, Point } from '../types';
import { X } from 'lucide-react';

interface AnnotationLayerProps {
  catalogId: string;
  pageIndex: number;
  mode: 'none' | 'pen' | 'note' | 'eraser';
  activeColor: string;
  isActive: boolean;
}

const AnnotationLayer: React.FC<AnnotationLayerProps> = ({ 
  catalogId, 
  pageIndex, 
  mode, 
  activeColor,
  isActive 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [data, setData] = useState<PageAnnotation>({ paths: [], notes: [] });
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentPath, setCurrentPath] = useState<Point[]>([]);

  // Load from LocalStorage
  useEffect(() => {
    try {
      const key = `nafas_annotation_${catalogId}_${pageIndex}`;
      const saved = localStorage.getItem(key);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && Array.isArray(parsed.paths) && Array.isArray(parsed.notes)) {
           setData(parsed);
        }
      }
    } catch (e) {
      console.error("Error loading annotations:", e);
    }
  }, [catalogId, pageIndex]);

  // Save to LocalStorage
  const saveData = (newData: PageAnnotation) => {
    try {
      const key = `nafas_annotation_${catalogId}_${pageIndex}`;
      localStorage.setItem(key, JSON.stringify(newData));
      setData(newData);
    } catch (e) {
      console.error("Error saving annotations:", e);
    }
  };

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    if (!canvasRef.current) return null;
    const rect = canvasRef.current.getBoundingClientRect();

    let clientX, clientY;
    if ('touches' in e) {
       if (e.touches && e.touches.length > 0) {
         clientX = e.touches[0].clientX;
         clientY = e.touches[0].clientY;
       } else return null;
    } else {
       clientX = (e as React.MouseEvent).clientX;
       clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - rect.left) / rect.width,
      y: (clientY - rect.top) / rect.height
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    if (mode !== 'pen' || !isActive) return;
    const point = getPoint(e);
    if (point) {
      setIsDrawing(true);
      setCurrentPath([point]);
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || mode !== 'pen') return;
    const point = getPoint(e);
    if (point) {
      setCurrentPath(prev => [...prev, point]);
    }
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);
    if (currentPath.length > 0) {
      const newPath: DrawingPath = { points: currentPath, color: activeColor, width: 20 };
      saveData({ ...data, paths: [...data.paths, newPath] });
    }
    setCurrentPath([]);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    if (canvas.width !== rect.width || canvas.height !== rect.height) {
        canvas.width = rect.width;
        canvas.height = rect.height;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    data.paths.forEach(path => {
      if (path.points.length < 2) return;
      ctx.beginPath();
      ctx.strokeStyle = path.color;
      ctx.lineWidth = path.width * (canvas.width / 1000) * 1.5;
      ctx.globalAlpha = 0.4;
      ctx.globalCompositeOperation = 'multiply'; 
      ctx.moveTo(path.points[0].x * canvas.width, path.points[0].y * canvas.height);
      for (let i = 1; i < path.points.length; i++) {
        ctx.lineTo(path.points[i].x * canvas.width, path.points[i].y * canvas.height);
      }
      ctx.stroke();
    });

    if (currentPath.length > 1) {
      ctx.beginPath();
      ctx.strokeStyle = activeColor;
      ctx.lineWidth = 20 * (canvas.width / 1000) * 1.5;
      ctx.globalAlpha = 0.4;
      ctx.globalCompositeOperation = 'multiply';
      ctx.moveTo(currentPath[0].x * canvas.width, currentPath[0].y * canvas.height);
      for (let i = 1; i < currentPath.length; i++) {
        ctx.lineTo(currentPath[i].x * canvas.width, currentPath[i].y * canvas.height);
      }
      ctx.stroke();
    }

    ctx.globalCompositeOperation = 'source-over';
    ctx.globalAlpha = 1;
  }, [data, currentPath, activeColor]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (mode !== 'note' || !isActive || !containerRef.current) return;
    if ((e.target as HTMLElement).closest('.sticky-note')) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    const newNote: StickyNote = { id: Date.now().toString(), x, y, text: '', color: '#fef3c7' };
    saveData({ ...data, notes: [...data.notes, newNote] });
  };

  const updateNote = (id: string, text: string) => {
    const newNotes = data.notes.map(n => n.id === id ? { ...n, text } : n);
    saveData({ ...data, notes: newNotes });
  };

  const deleteNote = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newNotes = data.notes.filter(n => n.id !== id);
    saveData({ ...data, notes: newNotes });
  };

  useEffect(() => {
    if (mode === 'eraser' && isActive) {
        const timer = setTimeout(() => {
             if (window.confirm('آیا مطمئن هستید که می‌خواهید تمام یادداشت‌ها و هایلایت‌های این صفحه را پاک کنید؟')) {
                saveData({ paths: [], notes: [] });
            }
        }, 100);
        return () => clearTimeout(timer);
    }
  }, [mode, isActive]);

  return (
    <div 
        ref={containerRef}
        className={`absolute inset-0 z-10 ${mode === 'pen' || mode === 'note' ? 'cursor-crosshair' : 'pointer-events-none'}`}
        onClick={handleContainerClick}
    >
        <canvas
            ref={canvasRef}
            className={`absolute inset-0 w-full h-full ${mode === 'pen' ? 'pointer-events-auto' : 'pointer-events-none'}`}
            onMouseDown={startDrawing}
            onMouseMove={draw}
            onMouseUp={stopDrawing}
            onMouseLeave={stopDrawing}
            onTouchStart={startDrawing}
            onTouchMove={draw}
            onTouchEnd={stopDrawing}
        />
        {data.notes.map(note => (
            <div
                key={note.id}
                className="sticky-note absolute p-2 rounded shadow-lg pointer-events-auto flex flex-col animate-fade-in"
                style={{
                    left: `${note.x * 100}%`, top: `${note.y * 100}%`,
                    backgroundColor: note.color, width: '140px', minHeight: '100px',
                    transform: 'translate(-50%, -50%) rotate(-1deg)', zIndex: 20
                }}
            >
                <div className="flex justify-end mb-1">
                    <button onClick={(e) => deleteNote(note.id, e)} className="text-red-500 hover:bg-red-100 rounded p-0.5">
                        <X size={12} />
                    </button>
                </div>
                <textarea
                    className="w-full h-full bg-transparent border-none outline-none text-xs text-slate-800 resize-none"
                    value={note.text}
                    onChange={(e) => updateNote(note.id, e.target.value)}
                    placeholder="بنویسید..."
                    onClick={(e) => e.stopPropagation()}
                    autoFocus={!note.text}
                />
            </div>
        ))}
    </div>
  );
};

export default AnnotationLayer;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import AnnotationLayer from './AnnotationLayer';
import { 
  X, ChevronRight, ChevronLeft, Maximize, Minimize, 
  Volume2, VolumeX, FileDown, ZoomIn, ZoomOut, 
  Book, Smartphone, ChevronUp, ChevronDown,
  PenTool, StickyNote as NoteIcon, Eraser, Share2, Check
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
  initialPage?: number;
}

const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number, catalogId: string, annotationMode: 'none' | 'pen' | 'note' | 'eraser', activeColor: string }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full relative" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            <AnnotationLayer 
                catalogId={props.catalogId} 
                pageIndex={props.number - 1} 
                mode={props.annotationMode}
                activeColor={props.activeColor}
                isActive={true} 
            />
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none z-0">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(initialPage);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });

  const [isMobile, setIsMobile] = useState(false);
  const [forceSinglePage, setForceSinglePage] = useState(false); 
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);
  const [showTopPanel, setShowTopPanel] = useState(true);
  const [showBottomPanel, setShowBottomPanel] = useState(true);

  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isGesturing, setIsGesturing] = useState(false);

  const [annotationMode, setAnnotationMode] = useState<'none' | 'pen' | 'note' | 'eraser'>('none');
  const [highlightColor, setHighlightColor] = useState('#fde047');
  const [showShareTooltip, setShowShareTooltip] = useState(false);

  const gesture = useRef({
    startX: 0, startY: 0, startPanX: 0, startPanY: 0, startDist: 0, startZoom: 1,
    mode: 'none' as 'none' | 'swipe' | 'pan' | 'pinch',
  });

  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // Update URL for Deep Linking
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    params.set('cat', catalog.id);
    params.set('page', (currentPage + 1).toString());
    const newUrl = `${window.location.pathname}?${params.toString()}`;
    window.history.replaceState({}, '', newUrl);
  }, [currentPage, catalog.id]);

  useEffect(() => {
    const handleResize = () => {
      const isSmallScreen = window.innerWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);
      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 0 : 100;
      const availableHeight = window.innerHeight - verticalPadding;
      const availableWidth = window.innerWidth - horizontalPadding;
      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;
      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }
      setDimensions({ width: Math.floor(bookWidth), height: Math.floor(bookHeight) });
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const handler = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handler);
    return () => document.removeEventListener('fullscreenchange', handler);
  }, []);

  useEffect(() => { if (zoomLevel <= 1) setPan({ x: 0, y: 0 }); }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip()?.flipNext();
  const prevFlip = () => bookRef.current?.pageFlip()?.flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip()?.flip(index);
  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) containerRef.current?.requestFullscreen().catch(e => {});
    else document.exitFullscreen();
  };

  const handleZoomIn = () => setZoomLevel(p => Math.min(Math.round((p + 0.1) * 10) / 10, 4));
  const handleZoomOut = () => setZoomLevel(p => Math.max(Math.round((p - 0.1) * 10) / 10, 0.5));

  const handleDownload = () => {
    const link = document.createElement('a');
    link.href = catalog.pdfUrl || catalog.pages[0];
    if (!catalog.pdfUrl) link.download = `${catalog.title}.jpg`;
    else link.target = '_blank';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href).then(() => {
        setShowShareTooltip(true);
        setTimeout(() => setShowShareTooltip(false), 2000);
    });
  };

  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    if (annotationMode !== 'none') return;
    setIsGesturing(true);
    gesture.current.startX = clientX; gesture.current.startY = clientY;
    gesture.current.mode = mode;
    if (mode === 'pan') { gesture.current.startPanX = pan.x; gesture.current.startPanY = pan.y; }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (annotationMode !== 'none' || gesture.current.mode !== 'pan') return;
    const dx = clientX - gesture.current.startX;
    const dy = clientY - gesture.current.startY;
    setPan({ x: gesture.current.startPanX + dx, y: gesture.current.startPanY + dy });
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (annotationMode !== 'none') return;
    setIsGesturing(false);
    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      if (Math.abs(dx) > 30) dx > 0 ? prevFlip() : nextFlip();
    }
    if (gesture.current.mode === 'pinch' && zoomLevel < 1.1) setZoomLevel(1);
    gesture.current.mode = 'none';
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (e.touches.length === 2) {
      setIsGesturing(true); gesture.current.mode = 'pinch';
      gesture.current.startDist = getDistance(e.touches);
      gesture.current.startZoom = zoomLevel;
    } else if (e.touches.length === 1) {
      startGesture(e.touches[0].clientX, e.touches[0].clientY, zoomLevel > 1 ? 'pan' : 'swipe');
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode === 'pinch' && e.touches.length === 2) {
      const scale = (getDistance(e.touches) / gesture.current.startDist) * gesture.current.startZoom;
      setZoomLevel(Math.min(Math.max(scale, 0.5), 4));
    } else if (e.touches.length === 1) moveGesture(e.touches[0].clientX, e.touches[0].clientY);
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    endGesture(e.changedTouches[0].clientX, e.changedTouches[0].clientY);
  };

  return (
    <div ref={containerRef} className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden">
      <div className="flex-grow flex flex-col h-full relative">
        {/* Top Panel */}
        <div className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-20 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}>
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <div className="text-skin-muted text-xs mt-0.5">صفحه {currentPage + 1} از {catalog.pages.length}</div>
                </div>
                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                        <button onClick={() => setAnnotationMode(annotationMode === 'pen' ? 'none' : 'pen')} className={`p-2 rounded-md transition-colors ${annotationMode === 'pen' ? 'bg-skin-primary text-white' : 'text-skin-control-text hover:bg-skin-control-hover'}`} title="هایلایت"><PenTool size={18} /></button>
                        <button onClick={() => setAnnotationMode(annotationMode === 'note' ? 'none' : 'note')} className={`p-2 rounded-md transition-colors ${annotationMode === 'note' ? 'bg-skin-primary text-white' : 'text-skin-control-text hover:bg-skin-control-hover'}`} title="یادداشت"><NoteIcon size={18} /></button>
                        <button onClick={() => setAnnotationMode(annotationMode === 'eraser' ? 'none' : 'eraser')} className={`p-2 rounded-md transition-colors ${annotationMode === 'eraser' ? 'bg-red-500 text-white' : 'text-skin-control-text hover:bg-red-100 hover:text-red-500'}`} title="پاک‌کن"><Eraser size={18} /></button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>
                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">{forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}</button>
                        <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md"><ZoomOut size={18} /></button>
                        <span className="text-xs w-8 text-center text-skin-muted">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md"><ZoomIn size={18} /></button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>
                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">{isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}</button>
                        <button onClick={toggleFullscreen} className="p-2">{isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}</button>
                        <div className="relative">
                            <button onClick={handleShare} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md"><Share2 size={18} /></button>
                            {showShareTooltip && <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded whitespace-nowrap flex items-center gap-1 animate-fade-in"><Check size={10} />کپی شد</div>}
                        </div>
                        <button onClick={handleDownload} className="p-2"><FileDown size={18} /></button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border"><X size={20} /></button>
                </div>
            </div>
            <div className="flex justify-center -mb-3 pb-1"><button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary transition-colors shadow-sm"><ChevronUp size={16} /></button></div>
        </div>

        <button onClick={() => setShowTopPanel(true)} className={`absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all ${!showTopPanel ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}><ChevronDown size={20} /></button>

        {/* Book Container */}
        <div className="flex-grow flex items-center justify-center relative w-full h-full overflow-hidden cursor-grab active:cursor-grabbing pb-20 pt-20" onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} onMouseDown={e => { if (e.button === 0) startGesture(e.clientX, e.clientY, zoomLevel > 1 ? 'pan' : 'swipe'); }} onMouseMove={e => moveGesture(e.clientX, e.clientY)} onMouseUp={e => endGesture(e.clientX, e.clientY)} onMouseLeave={e => endGesture(e.clientX, e.clientY)} style={{ cursor: annotationMode !== 'none' ? 'crosshair' : (zoomLevel > 1 ? 'move' : 'grab') }}>
            {annotationMode === 'none' && (
                <>
                    <button onClick={nextFlip} className="hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary text-white rounded-full shadow-lg transition-all hover:scale-110"><ChevronRight size={24} /></button>
                    <button onClick={prevFlip} className="hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary text-white rounded-full shadow-lg transition-all hover:scale-110"><ChevronLeft size={24} /></button>
                </>
            )}
            <div style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`, transition: isGesturing ? 'none' : 'transform 0.2s ease-out', transformOrigin: 'center center' }} className="flex items-center justify-center relative">
                {/* @ts-ignore */}
                <HTMLFlipBook key={`${dimensions.width}-${forceSinglePage}`} width={dimensions.width} height={dimensions.height} size="fixed" minWidth={300} maxWidth={3000} minHeight={400} maxHeight={4000} maxShadowOpacity={0.5} showCover={false} mobileScrollSupport={false} onFlip={onFlip} onInit={onInit} ref={bookRef} className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`} style={{ margin: '0 auto' }} usePortrait={isMobile || forceSinglePage} startPage={initialPage} drawShadow={true} flippingTime={800} useMouseEvents={false} swipeDistance={10000}>
                    {catalog.pages.map((pageUrl, index) => (
                        <Page number={index + 1} key={index} catalogId={catalog.id} annotationMode={annotationMode} activeColor={highlightColor}>
                             <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                                <img src={pageUrl} alt={`Page ${index + 1}`} className="w-full h-full object-contain pointer-events-none" loading={index < 4 ? "eager" : "lazy"} onDragStart={e => e.preventDefault()} />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>
        </div>

        {/* Bottom Panel */}
        <div className={`absolute bottom-0 left-0 right-0 z-20 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>
             <div className="flex justify-center -mt-3 pt-1 pointer-events-none"><button onClick={() => setShowBottomPanel(false)} className="pointer-events-auto bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary shadow-sm"><ChevronDown size={16} /></button></div>
             <div className="md:hidden bg-skin-card border-t border-skin-border p-4">
                 <div className="flex justify-around mb-4">
                    <button onClick={() => setAnnotationMode(annotationMode === 'pen' ? 'none' : 'pen')} className={`p-2 rounded ${annotationMode === 'pen' ? 'bg-skin-primary text-white' : 'bg-gray-100'}`}><PenTool size={18} /></button>
                    <button onClick={() => setAnnotationMode(annotationMode === 'note' ? 'none' : 'note')} className={`p-2 rounded ${annotationMode === 'note' ? 'bg-skin-primary text-white' : 'bg-gray-100'}`}><NoteIcon size={18} /></button>
                    <button onClick={handleShare} className="p-2 bg-gray-100 rounded text-gray-700 relative"><Share2 size={18} />{showShareTooltip && <span className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[9px] px-1 rounded whitespace-nowrap">کپی شد</span>}</button>
                 </div>
                 <div className="flex justify-between items-center">
                     <button onClick={nextFlip} className="p-3 bg-skin-control-bg rounded-xl"><ChevronRight size={24} /></button>
                     <div className="flex gap-4"><button onClick={() => setIsSoundEnabled(!isSoundEnabled)}>{isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}</button><button onClick={handleDownload}><FileDown size={20} /></button></div>
                     <button onClick={prevFlip} className="p-3 bg-skin-control-bg rounded-xl"><ChevronLeft size={24} /></button>
                 </div>
             </div>
             <div className="h-20 bg-skin-card/90 backdrop-blur-md border-t border-skin-border flex items-center px-4 gap-2 overflow-x-auto">
                 {catalog.pages.map((page, idx) => (
                     <button key={idx} onClick={() => goToPage(idx)} className={`shrink-0 h-16 w-12 rounded border-2 transition-all ${currentPage === idx ? 'border-skin-primary scale-110 shadow-lg' : 'border-transparent opacity-60'}`}><img src={page} className="w-full h-full object-cover" /></button>
                 ))}
            </div>
        </div>
        <button onClick={() => setShowBottomPanel(true)} className={`absolute bottom-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 border border-skin-border rounded-full p-2 text-skin-muted hover:text-skin-primary transition-all ${!showBottomPanel ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}><ChevronUp size={20} /></button>
      </div>
    </div>
  );
};

