import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import BookViewer from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import SkeletonCard from './components/SkeletonCard';
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon } from 'lucide-react';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [initialPage, setInitialPage] = useState(0);

  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [sortBy, setSortBy] = useState<SortOption>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('همه');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  const categories = ['همه', ...new Set(catalogs.map(c => c.category).filter(Boolean))];

  // Deep Linking Check on Mount
  useEffect(() => {
    if (catalogs.length > 0) {
        const params = new URLSearchParams(window.location.search);
        const catId = params.get('cat');
        const pageNum = params.get('page');

        if (catId) {
            const found = catalogs.find(c => c.id === catId);
            if (found) {
                let pIndex = 0;
                if (pageNum) {
                    pIndex = Math.max(0, parseInt(pageNum) - 1);
                    if (pIndex >= found.pages.length) pIndex = 0;
                }
                setInitialPage(pIndex);
                setSelectedCatalog(found);
            }
        }
    }
  }, [catalogs]);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 1200);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const handleResize = () => setDisplayMode(window.innerWidth < 768 ? 'list' : 'grid');
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    if (window.location.hash === '#admin') setViewMode('admin');
  }, []);

  const processedCatalogs = catalogs.filter(cat => 
    (selectedCategory === 'همه' || cat.category === selectedCategory) &&
    (cat.title.toLowerCase().includes(searchTerm.toLowerCase()) || cat.description.toLowerCase().includes(searchTerm.toLowerCase()))
  ).sort((a, b) => {
    switch (sortBy) {
        case 'newest': return b.date.localeCompare(a.date);
        case 'oldest': return a.date.localeCompare(b.date);
        case 'az': return a.title.localeCompare(b.title, 'fa');
        case 'za': return b.title.localeCompare(a.title, 'fa');
        default: return 0;
    }
  });

  const processedVideos = videos.filter(vid => 
     vid.title.toLowerCase().includes(searchTerm.toLowerCase()) || vid.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const handleCloseViewer = () => {
      setSelectedCatalog(null);
      const newUrl = window.location.pathname;
      window.history.replaceState({}, '', newUrl);
  };

  if (viewMode === 'admin') {
    if (!isAuthenticated) return <AdminLogin onLogin={() => setIsAuthenticated(true)} onBack={() => setViewMode('home')} />;
    return <AdminPanel onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} />;
  }

  return (
    <div className="min-h-screen font-sans bg-skin-base text-skin-text transition-colors duration-300 relative flex flex-col">
      <header className="sticky top-0 z-40 w-full backdrop-blur-lg bg-skin-base/80 border-b border-skin-border">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <img src="https://nafaspharmed.com/wp-content/uploads/2025/11/logo_fa.png" alt="نفس فارمد" className="h-10 w-auto object-contain" />
          <div className="flex items-center gap-4">
             <div className="hidden md:flex items-center bg-skin-card border border-skin-border rounded-full px-4 py-2 w-80 focus-within:border-skin-primary transition-colors">
                <Search size={18} className="text-skin-muted ml-2" />
                <input type="text" placeholder="جستجو..." className="bg-transparent border-none outline-none text-sm w-full" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
             </div>
             <button onClick={toggleTheme} className="p-2 rounded-lg bg-skin-card border border-skin-border">
                {theme === 'light' ? <Sun size={20} /> : theme === 'dark' ? <Moon size={20} /> : <BookOpen size={20} />}
             </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12 flex-grow">
        <div className="mb-8 text-center md:text-right border-b border-skin-border pb-8 animate-fade-in">
            <h2 className="text-2xl md:text-4xl font-black mb-4 leading-tight">پورتال آموزشی <span className="text-transparent bg-clip-text bg-gradient-to-r from-skin-primary to-skin-primary-hover">نفس زیست فارمد</span></h2>
            <p className="text-skin-muted text-sm md:text-lg">دسترسی سریع به جدیدترین کاتالوگ‌ها، بروشورها و ویدئوهای آموزشی</p>
        </div>

        <div className="mb-12">
            <div className="flex flex-col sm:flex-row justify-between items-end gap-4 mb-6">
                <h3 className="text-xl md:text-2xl font-bold flex items-center gap-2"><BookOpen className="text-skin-primary" />کاتالوگ‌ها</h3>
                <div className="flex items-center gap-2 bg-skin-card p-1.5 rounded-xl border border-skin-border shadow-sm">
                    <div className="relative flex items-center">
                        <ArrowDownUp size={16} className="absolute right-2 text-skin-muted pointer-events-none" />
                        <select value={sortBy} onChange={(e) => setSortBy(e.target.value as SortOption)} className="appearance-none bg-skin-control-bg hover:bg-skin-control-hover text-skin-text text-xs rounded-lg pr-7 pl-2 py-1.5 outline-none cursor-pointer">
                            <option value="newest">جدیدترین</option><option value="oldest">قدیمی‌ترین</option><option value="az">حروف الفبا</option>
                        </select>
                    </div>
                    <div className="w-px h-5 bg-skin-border mx-1"></div>
                    <button onClick={() => setDisplayMode('grid')} className={`p-1.5 rounded-lg ${displayMode === 'grid' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutGrid size={16} /></button>
                    <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-lg ${displayMode === 'list' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutList size={16} /></button>
                </div>
            </div>

            {isLoading ? (
                <div className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}>
                     {[1, 2, 3, 4].map(i => <SkeletonCard key={i} />)}
                </div>
            ) : processedCatalogs.length > 0 ? (
                <div className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}>
                {processedCatalogs.map(catalog => (
                    <CatalogCard key={catalog.id} catalog={catalog} onClick={(c) => { setInitialPage(0); setSelectedCatalog(c); }} viewMode={displayMode} />
                ))}
                </div>
            ) : (
                <div className="py-10 text-center text-skin-muted bg-skin-card border border-dashed border-skin-border rounded-xl"><p>هیچ کاتالوگی یافت نشد.</p></div>
            )}
        </div>

        {processedVideos.length > 0 && !isLoading && (
            <div className="mb-8 pt-8 border-t border-skin-border">
                <h3 className="text-xl md:text-2xl font-bold flex items-center gap-2 mb-6"><VideoIcon className="text-skin-primary" />ویدئوهای آموزشی</h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {processedVideos.map(video => <VideoCard key={video.id} video={video} onClick={setSelectedVideo} />)}
                </div>
            </div>
        )}
      </main>

      <footer className="border-t border-skin-border py-6 mt-12 bg-skin-base/50 text-center text-skin-muted text-sm">
          <p>© تمامی حقوق متعلق به شرکت نفس زیست فارمد است.</p>
      </footer>

      {selectedCatalog && <BookViewer catalog={selectedCatalog} initialPage={initialPage} onClose={handleCloseViewer} />}
      {selectedVideo && <VideoPlayer video={selectedVideo} onClose={() => setSelectedVideo(null)} />}
    </div>
  );
}

const App = () => (<CatalogProvider><MainApp /></CatalogProvider>);
export default App;

import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import BookViewer from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import SkeletonCard from './components/SkeletonCard';
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon } from 'lucide-react';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [initialPage, setInitialPage] = useState(0);

  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [sortBy, setSortBy] = useState<SortOption>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('همه');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  const categories = ['همه', ...new Set(catalogs.map(c => c.category).filter(Boolean))];

  // --- Deep Linking: Parse URL on mount or when catalogs load ---
  useEffect(() => {
    if (catalogs.length > 0) {
      const params = new URLSearchParams(window.location.search);
      const catId = params.get('cat');
      const pageNum = params.get('page');

      if (catId) {
        const found = catalogs.find(c => c.id === catId);
        if (found) {
          let pIndex = 0;
          if (pageNum) {
            // URL is 1-based, internal is 0-based
            pIndex = Math.max(0, parseInt(pageNum) - 1);
            if (pIndex >= found.pages.length) pIndex = 0;
          }

          // Small delay to ensure state transitions smoothly
          setInitialPage(pIndex);
          setSelectedCatalog(found);
        }
      }
    }
  }, [catalogs]);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 1200);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const handleResize = () => setDisplayMode(window.innerWidth < 768 ? 'list' : 'grid');
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    if (window.location.hash === '#admin') setViewMode('admin');
  }, []);

  const processedCatalogs = catalogs.filter(cat => 
    (selectedCategory === 'همه' || cat.category === selectedCategory) &&
    (cat.title.toLowerCase().includes(searchTerm.toLowerCase()) || cat.description.toLowerCase().includes(searchTerm.toLowerCase()))
  ).sort((a, b) => {
    switch (sortBy) {
        case 'newest': return b.date.localeCompare(a.date);
        case 'oldest': return a.date.localeCompare(b.date);
        case 'az': return a.title.localeCompare(b.title, 'fa');
        case 'za': return b.title.localeCompare(a.title, 'fa');
        default: return 0;
    }
  });

  const processedVideos = videos.filter(vid => 
     vid.title.toLowerCase().includes(searchTerm.toLowerCase()) || vid.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const handleCloseViewer = () => {
    setSelectedCatalog(null);
    // Clean URL when closing
    const newUrl = window.location.pathname;
    window.history.replaceState({}, '', newUrl);
  };

  const handleOpenCatalog = (cat: Catalog) => {
    setInitialPage(0);
    setSelectedCatalog(cat);
  };

  if (viewMode === 'admin') {
    if (!isAuthenticated) return <AdminLogin onLogin={() => setIsAuthenticated(true)} onBack={() => setViewMode('home')} />;
    return <AdminPanel onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} />;
  }

  return (
    <div className="min-h-screen font-sans bg-skin-base text-skin-text transition-colors duration-300 relative flex flex-col">
      <header className="sticky top-0 z-40 w-full backdrop-blur-lg bg-skin-base/80 border-b border-skin-border">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <img src="https://nafaspharmed.com/wp-content/uploads/2025/11/logo_fa.png" alt="نفس فارمد" className="h-10 w-auto object-contain" />
          <div className="flex items-center gap-4">
             <div className="hidden md:flex items-center bg-skin-card border border-skin-border rounded-full px-4 py-2 w-80 focus-within:border-skin-primary transition-colors">
                <Search size={18} className="text-skin-muted ml-2" />
                <input type="text" placeholder="جستجو..." className="bg-transparent border-none outline-none text-sm w-full" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
             </div>
             <button onClick={toggleTheme} className="p-2 rounded-lg bg-skin-card border border-skin-border">
                {theme === 'light' ? <Sun size={20} /> : theme === 'dark' ? <Moon size={20} /> : <BookOpen size={20} />}
             </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12 flex-grow">
        <div className="mb-8 text-center md:text-right border-b border-skin-border pb-8 animate-fade-in">
            <h2 className="text-2xl md:text-4xl font-black mb-4 leading-tight">پورتال آموزشی <span className="text-transparent bg-clip-text bg-gradient-to-r from-skin-primary to-skin-primary-hover">نفس زیست فارمد</span></h2>
            <p className="text-skin-muted text-sm md:text-lg">دسترسی سریع به جدیدترین کاتالوگ‌ها، بروشورها و ویدئوهای آموزشی</p>
        </div>

        <div className="mb-12">
            <div className="flex flex-col sm:flex-row justify-between items-end gap-4 mb-6">
                <h3 className="text-xl md:text-2xl font-bold flex items-center gap-2"><BookOpen className="text-skin-primary" />کاتالوگ‌ها</h3>
                <div className="flex items-center gap-2 bg-skin-card p-1.5 rounded-xl border border-skin-border shadow-sm">
                    <div className="relative flex items-center">
                        <ArrowDownUp size={16} className="absolute right-2 text-skin-muted pointer-events-none" />
                        <select value={sortBy} onChange={(e) => setSortBy(e.target.value as SortOption)} className="appearance-none bg-skin-control-bg hover:bg-skin-control-hover text-skin-text text-xs rounded-lg pr-7 pl-2 py-1.5 outline-none cursor-pointer">
                            <option value="newest">جدیدترین</option><option value="oldest">قدیمی‌ترین</option><option value="az">حروف الفبا</option>
                        </select>
                    </div>
                    <div className="w-px h-5 bg-skin-border mx-1"></div>
                    <button onClick={() => setDisplayMode('grid')} className={`p-1.5 rounded-lg ${displayMode === 'grid' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutGrid size={16} /></button>
                    <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-lg ${displayMode === 'list' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutList size={16} /></button>
                </div>
            </div>

            {isLoading ? (
                <div className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}>
                     {[1, 2, 3, 4].map(i => <SkeletonCard key={i} />)}
                </div>
            ) : processedCatalogs.length > 0 ? (
                <div className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}>
                {processedCatalogs.map(catalog => (
                    <CatalogCard key={catalog.id} catalog={catalog} onClick={handleOpenCatalog} viewMode={displayMode} />
                ))}
                </div>
            ) : (
                <div className="py-10 text-center text-skin-muted bg-skin-card border border-dashed border-skin-border rounded-xl"><p>هیچ کاتالوگی یافت نشد.</p></div>
            )}
        </div>

        {processedVideos.length > 0 && !isLoading && (
            <div className="mb-8 pt-8 border-t border-skin-border">
                <h3 className="text-xl md:text-2xl font-bold flex items-center gap-2 mb-6"><VideoIcon className="text-skin-primary" />ویدئوهای آموزشی</h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {processedVideos.map(video => <VideoCard key={video.id} video={video} onClick={setSelectedVideo} />)}
                </div>
            </div>
        )}
      </main>

      <footer className="border-t border-skin-border py-6 mt-12 bg-skin-base/50 text-center text-skin-muted text-sm">
          <p>© تمامی حقوق متعلق به شرکت نفس زیست فارمد است.</p>
      </footer>

      {selectedCatalog && <BookViewer catalog={selectedCatalog} initialPage={initialPage} onClose={handleCloseViewer} />}
      {selectedVideo && <VideoPlayer video={selectedVideo} onClose={() => setSelectedVideo(null)} />}
    </div>
  );
}

const App = () => (<CatalogProvider><MainApp /></CatalogProvider>);
export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import AnnotationLayer from './AnnotationLayer';
import { 
  X, ChevronRight, ChevronLeft, Maximize, Minimize, 
  Volume2, VolumeX, FileDown, ZoomIn, ZoomOut, 
  Book, Smartphone, ChevronUp, ChevronDown,
  PenTool, StickyNote as NoteIcon, Eraser, Share2, Check
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
  initialPage?: number;
}

const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number, catalogId: string, annotationMode: 'none' | 'pen' | 'note' | 'eraser', activeColor: string }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full relative" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            {/* Per-page annotation layer */}
            <AnnotationLayer 
                catalogId={props.catalogId} 
                pageIndex={props.number - 1} 
                mode={props.annotationMode}
                activeColor={props.activeColor}
                isActive={true} 
            />
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none z-0">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(initialPage);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });

  const [isMobile, setIsMobile] = useState(false);
  const [forceSinglePage, setForceSinglePage] = useState(false); 
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);
  const [showTopPanel, setShowTopPanel] = useState(true);
  const [showBottomPanel, setShowBottomPanel] = useState(true);

  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isGesturing, setIsGesturing] = useState(false);

  const [annotationMode, setAnnotationMode] = useState<'none' | 'pen' | 'note' | 'eraser'>('none');
  const [highlightColor, setHighlightColor] = useState('#fde047');
  const [showShareTooltip, setShowShareTooltip] = useState(false);

  const gesture = useRef({
    startX: 0, startY: 0, startPanX: 0, startPanY: 0, startDist: 0, startZoom: 1,
    mode: 'none' as 'none' | 'swipe' | 'pan' | 'pinch',
  });

  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // --- Deep Linking Sync: Update URL on Page Change ---
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    params.set('cat', catalog.id);
    params.set('page', (currentPage + 1).toString());
    const newUrl = `${window.location.pathname}?${params.toString()}`;
    window.history.replaceState({}, '', newUrl);
  }, [currentPage, catalog.id]);

  useEffect(() => {
    const handleResize = () => {
      const isSmallScreen = window.innerWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);
      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 0 : 100;
      const availableHeight = window.innerHeight - verticalPadding;
      const availableWidth = window.innerWidth - horizontalPadding;
      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;
      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }
      setDimensions({ width: Math.floor(bookWidth), height: Math.floor(bookHeight) });
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const handler = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handler);
    return () => document.removeEventListener('fullscreenchange', handler);
  }, []);

  useEffect(() => { if (zoomLevel <= 1) setPan({ x: 0, y: 0 }); }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  // Safe access to flip methods
  const nextFlip = () => bookRef.current?.pageFlip()?.flipNext();
  const prevFlip = () => bookRef.current?.pageFlip()?.flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip()?.flip(index);
  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) containerRef.current?.requestFullscreen().catch(e => {});
    else document.exitFullscreen();
  };

  const handleZoomIn = () => setZoomLevel(p => Math.min(Math.round((p + 0.1) * 10) / 10, 4));
  const handleZoomOut = () => setZoomLevel(p => Math.max(Math.round((p - 0.1) * 10) / 10, 0.5));

  const handleDownload = () => {
    const link = document.createElement('a');
    link.href = catalog.pdfUrl || catalog.pages[0];
    if (!catalog.pdfUrl) link.download = `${catalog.title}.jpg`;
    else link.target = '_blank';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleShare = () => {
    // Navigator.clipboard is precise and modern
    const shareUrl = window.location.href;
    navigator.clipboard.writeText(shareUrl).then(() => {
        setShowShareTooltip(true);
        setTimeout(() => setShowShareTooltip(false), 2000);
    }).catch(err => {
      // Fallback for older browsers
      const textArea = document.createElement("textarea");
      textArea.value = shareUrl;
      document.body.appendChild(textArea);
      textArea.select();
      document.execCommand('copy');
      document.body.removeChild(textArea);
      setShowShareTooltip(true);
      setTimeout(() => setShowShareTooltip(false), 2000);
    });
  };

  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    if (annotationMode !== 'none') return;
    setIsGesturing(true);
    gesture.current.startX = clientX; gesture.current.startY = clientY;
    gesture.current.mode = mode;
    if (mode === 'pan') { gesture.current.startPanX = pan.x; gesture.current.startPanY = pan.y; }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (annotationMode !== 'none' || gesture.current.mode !== 'pan') return;
    const dx = clientX - gesture.current.startX;
    const dy = clientY - gesture.current.startY;
    setPan({ x: gesture.current.startPanX + dx, y: gesture.current.startPanY + dy });
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (annotationMode !== 'none') return;
    setIsGesturing(false);
    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      if (Math.abs(dx) > 30) dx > 0 ? prevFlip() : nextFlip();
    }
    if (gesture.current.mode === 'pinch' && zoomLevel < 1.1) setZoomLevel(1);
    gesture.current.mode = 'none';
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (e.touches.length === 2) {
      setIsGesturing(true); gesture.current.mode = 'pinch';
      gesture.current.startDist = getDistance(e.touches);
      gesture.current.startZoom = zoomLevel;
    } else if (e.touches.length === 1) {
      startGesture(e.touches[0].clientX, e.touches[0].clientY, zoomLevel > 1 ? 'pan' : 'swipe');
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (gesture.current.mode === 'pinch' && e.touches.length === 2) {
      const scale = (getDistance(e.touches) / gesture.current.startDist) * gesture.current.startZoom;
      setZoomLevel(Math.min(Math.max(scale, 0.5), 4));
    } else if (e.touches.length === 1) moveGesture(e.touches[0].clientX, e.touches[0].clientY);
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (annotationMode !== 'none') return;
    if (e.changedTouches.length > 0) {
      endGesture(e.changedTouches[0].clientX, e.changedTouches[0].clientY);
    }
  };

  return (
    <div ref={containerRef} className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden">
      <div className="flex-grow flex flex-col h-full relative">
        {/* Top Panel */}
        <div className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-20 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}>
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <div className="text-skin-muted text-xs mt-0.5">صفحه {currentPage + 1} از {catalog.pages.length}</div>
                </div>
                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                        {/* Annotation Toolbar */}
                        <button onClick={() => setAnnotationMode(annotationMode === 'pen' ? 'none' : 'pen')} className={`p-2 rounded-md transition-colors ${annotationMode === 'pen' ? 'bg-skin-primary text-white shadow-md' : 'text-skin-control-text hover:bg-skin-control-hover'}`} title="هایلایت"><PenTool size={18} /></button>
                        <button onClick={() => setAnnotationMode(annotationMode === 'note' ? 'none' : 'note')} className={`p-2 rounded-md transition-colors ${annotationMode === 'note' ? 'bg-skin-primary text-white shadow-md' : 'text-skin-control-text hover:bg-skin-control-hover'}`} title="یادداشت"><NoteIcon size={18} /></button>
                        <button onClick={() => setAnnotationMode(annotationMode === 'eraser' ? 'none' : 'eraser')} className={`p-2 rounded-md transition-colors ${annotationMode === 'eraser' ? 'bg-red-500 text-white' : 'text-skin-control-text hover:bg-red-100 hover:text-red-500'}`} title="پاک‌کن"><Eraser size={18} /></button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors" title="تغییر نحوه نمایش">{forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}</button>
                        <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md"><ZoomOut size={18} /></button>
                        <span className="text-xs w-8 text-center text-skin-muted font-mono">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md"><ZoomIn size={18} /></button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">{isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}</button>
                        <button onClick={toggleFullscreen} className="p-2">{isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}</button>

                        <div className="relative">
                            <button onClick={handleShare} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md" title="اشتراک‌گذاری لینک مستقیم"><Share2 size={18} /></button>
                            {showShareTooltip && <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded whitespace-nowrap flex items-center gap-1 animate-fade-in"><Check size={10} />لینک مستقیم کپی شد</div>}
                        </div>
                        <button onClick={handleDownload} className="p-2" title="دانلود فایل"><FileDown size={18} /></button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border"><X size={20} /></button>
                </div>
            </div>
            <div className="flex justify-center -mb-3 pb-1"><button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary transition-colors shadow-sm"><ChevronUp size={16} /></button></div>
        </div>

        <button onClick={() => setShowTopPanel(true)} className={`absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all ${!showTopPanel ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}><ChevronDown size={20} /></button>

        {/* Book Container */}
        <div className="flex-grow flex items-center justify-center relative w-full h-full overflow-hidden cursor-grab active:cursor-grabbing pb-20 pt-20" onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} onMouseDown={e => { if (e.button === 0 && annotationMode === 'none') startGesture(e.clientX, e.clientY, zoomLevel > 1 ? 'pan' : 'swipe'); }} onMouseMove={e => moveGesture(e.clientX, e.clientY)} onMouseUp={e => endGesture(e.clientX, e.clientY)} onMouseLeave={e => endGesture(e.clientX, e.clientY)} style={{ cursor: annotationMode !== 'none' ? 'crosshair' : (zoomLevel > 1 ? 'move' : 'grab') }}>
            {annotationMode === 'none' && (
                <>
                    <button onClick={nextFlip} className="hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary text-white rounded-full shadow-lg transition-all hover:scale-110 active:scale-95"><ChevronRight size={24} /></button>
                    <button onClick={prevFlip} className="hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary text-white rounded-full shadow-lg transition-all hover:scale-110 active:scale-95"><ChevronLeft size={24} /></button>
                </>
            )}
            <div style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`, transition: isGesturing ? 'none' : 'transform 0.2s ease-out', transformOrigin: 'center center' }} className="flex items-center justify-center relative">
                {/* @ts-ignore */}
                <HTMLFlipBook 
                  key={`${dimensions.width}-${forceSinglePage}`} 
                  width={dimensions.width} 
                  height={dimensions.height} 
                  size="fixed" 
                  minWidth={300} 
                  maxWidth={3000} 
                  minHeight={400} 
                  maxHeight={4000} 
                  maxShadowOpacity={0.5} 
                  showCover={false} 
                  mobileScrollSupport={false} 
                  onFlip={onFlip} 
                  onInit={onInit} 
                  ref={bookRef} 
                  className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`} 
                  style={{ margin: '0 auto' }} 
                  usePortrait={isMobile || forceSinglePage} 
                  startPage={initialPage} 
                  drawShadow={true} 
                  flippingTime={800} 
                  useMouseEvents={false} 
                  swipeDistance={10000}
                >
                    {catalog.pages.map((pageUrl, index) => (
                        <Page number={index + 1} key={index} catalogId={catalog.id} annotationMode={annotationMode} activeColor={highlightColor}>
                             <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                                <img src={pageUrl} alt={`Page ${index + 1}`} className="w-full h-full object-contain pointer-events-none" loading={index < 4 ? "eager" : "lazy"} onDragStart={e => e.preventDefault()} />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>
        </div>

        {/* Bottom Panel */}
        <div className={`absolute bottom-0 left-0 right-0 z-20 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>
             <div className="flex justify-center -mt-3 pt-1 pointer-events-none"><button onClick={() => setShowBottomPanel(false)} className="pointer-events-auto bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary shadow-sm"><ChevronDown size={16} /></button></div>
             <div className="md:hidden bg-skin-card border-t border-skin-border p-4">
                 <div className="flex justify-around mb-4">
                    <button onClick={() => setAnnotationMode(annotationMode === 'pen' ? 'none' : 'pen')} className={`p-2 rounded ${annotationMode === 'pen' ? 'bg-skin-primary text-white shadow-md' : 'bg-gray-100'}`}><PenTool size={18} /></button>
                    <button onClick={() => setAnnotationMode(annotationMode === 'note' ? 'none' : 'note')} className={`p-2 rounded ${annotationMode === 'note' ? 'bg-skin-primary text-white shadow-md' : 'bg-gray-100'}`}><NoteIcon size={18} /></button>
                    <button onClick={handleShare} className="p-2 bg-gray-100 rounded text-gray-700 relative"><Share2 size={18} />{showShareTooltip && <span className="absolute -top-8 left-1/2 -translate-x-1/2 bg-black text-white text-[9px] px-2 py-1 rounded whitespace-nowrap z-50">کپی شد</span>}</button>
                 </div>
                 <div className="flex justify-between items-center">
                     <button onClick={nextFlip} className="p-3 bg-skin-control-bg rounded-xl active:bg-skin-primary active:text-white"><ChevronRight size={24} /></button>
                     <div className="flex gap-4"><button onClick={() => setIsSoundEnabled(!isSoundEnabled)}>{isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}</button><button onClick={handleDownload}><FileDown size={20} /></button></div>
                     <button onClick={prevFlip} className="p-3 bg-skin-control-bg rounded-xl active:bg-skin-primary active:text-white"><ChevronLeft size={24} /></button>
                 </div>
             </div>
             <div className="h-20 bg-skin-card/90 backdrop-blur-md border-t border-skin-border flex items-center px-4 gap-2 overflow-x-auto scrollbar-hide">
                 {catalog.pages.map((page, idx) => (
                     <button key={idx} onClick={() => goToPage(idx)} className={`shrink-0 h-16 w-12 rounded border-2 transition-all duration-300 ${currentPage === idx ? 'border-skin-primary scale-110 shadow-lg z-10' : 'border-transparent opacity-60'}`}><img src={page} className="w-full h-full object-cover rounded-sm" loading="lazy" /></button>
                 ))}
            </div>
        </div>
        <button onClick={() => setShowBottomPanel(true)} className={`absolute bottom-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 border border-skin-border rounded-full p-2 text-skin-muted hover:text-skin-primary shadow-lg transition-all ${!showBottomPanel ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}><ChevronUp size={20} /></button>
      </div>
    </div>
  );
};

export default BookViewer;

import React, { useState, useEffect } from 'react';
import { useCatalogs } from '../context/CatalogContext';
import { Catalog, Video } from '../types';
import { 
  Plus, Trash2, Edit2, Save, X, Upload, 
  Image as ImageIcon, FileText, LayoutGrid, LogOut, Copy, 
  AlertTriangle, Video as VideoIcon, Book, Link as LinkIcon,
  Database, CheckCircle, Tag, Globe
} from 'lucide-react';

interface AdminPanelProps {
  onLogout: () => void;
}

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

const PlayCircleIcon = () => (
    <div className="w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center border border-white/40">
        <svg viewBox="0 0 24 24" fill="white" className="w-5 h-5 ml-0.5"><path d="M8 5v14l11-7z"/></svg>
    </div>
);

type Tab = 'catalogs' | 'videos';

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogout }) => {
  const { catalogs, videos, addCatalog, updateCatalog, deleteCatalog, addVideo, updateVideo, deleteVideo, resetToDefault, importData } = useCatalogs();

  const [activeTab, setActiveTab] = useState<Tab>('catalogs');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [showExport, setShowExport] = useState(false);
  const [deleteConfirmation, setDeleteConfirmation] = useState<{id: string, type: Tab} | null>(null);

  // Database Code Management
  const [dbCode, setDbCode] = useState('');

  // New state for manual page URL input
  const [newPageUrl, setNewPageUrl] = useState('');

  // Form State - Catalog
  const [catalogForm, setCatalogForm] = useState<Partial<Catalog>>({
    title: '', description: '', date: '', pdfUrl: '', coverImage: '', pages: [], pageCount: 0, category: 'عمومی', language: 'fa'
  });

  // Form State - Video
  const [videoForm, setVideoForm] = useState<Partial<Video>>({
    title: '', description: '', date: '', videoUrl: '', coverImage: '', duration: ''
  });

  // Calculate unique categories for suggestions
  const uniqueCategories = Array.from(new Set(catalogs.map(c => c.category))).filter(Boolean);

  // Update dbCode whenever data changes
  useEffect(() => {
     if (!showExport) {
        const catalogsJson = JSON.stringify(catalogs, null, 2);
        const videosJson = JSON.stringify(videos, null, 2);
        setDbCode(`window.NAFAS_DATA = {\n  catalogs: ${catalogsJson},\n  videos: ${videosJson}\n};`);
     }
  }, [catalogs, videos, showExport]);

  const resetForms = () => {
    const today = new Date().toLocaleDateString('fa-IR');
    setCatalogForm({
      title: '', description: '', date: today, pdfUrl: '', coverImage: '', pages: [], pageCount: 0, category: 'عمومی', language: 'fa'
    });
    setVideoForm({
      title: '', description: '', date: today, videoUrl: '', coverImage: '', duration: ''
    });
    setEditingId(null);
    setShowForm(false);
    setNewPageUrl('');
  };

  const handleEdit = (item: Catalog | Video, type: Tab) => {
    if (type === 'catalogs') {
        setCatalogForm(item as Catalog);
    } else {
        setVideoForm(item as Video);
    }
    setEditingId(item.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: string, type: Tab) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      if (type === 'catalogs') {
          if (field === 'cover') {
            const base64 = await fileToBase64(files[0]);
            setCatalogForm(prev => ({ ...prev, coverImage: base64 }));
          } else if (field === 'pages') {
            const newPages = await Promise.all(Array.from(files).map(fileToBase64));
            setCatalogForm(prev => ({
              ...prev,
              pages: [...(prev.pages || []), ...newPages],
              pageCount: (prev.pages?.length || 0) + newPages.length
            }));
          }
      } else {
          // Video Cover
           const base64 = await fileToBase64(files[0]);
           setVideoForm(prev => ({ ...prev, coverImage: base64 }));
      }
    } catch (error) {
      alert('خطا در بارگذاری تصویر');
    }
  };

  const handleAddPageUrl = () => {
    if (!newPageUrl.trim()) return;
    setCatalogForm(prev => ({
        ...prev,
        pages: [...(prev.pages || []), newPageUrl.trim()],
        pageCount: (prev.pages?.length || 0) + 1
    }));
    setNewPageUrl('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (activeTab === 'catalogs') {
        if (!catalogForm.title || !catalogForm.coverImage || !catalogForm.pages?.length) {
            alert('لطفا عنوان، تصویر کاور و صفحات را تکمیل کنید');
            return;
        }
        const data: Catalog = {
            id: editingId || Date.now().toString(),
            title: catalogForm.title!,
            description: catalogForm.description || '',
            date: catalogForm.date || '',
            pdfUrl: catalogForm.pdfUrl || undefined,
            coverImage: catalogForm.coverImage!,
            pages: catalogForm.pages!,
            pageCount: catalogForm.pages!.length,
            category: catalogForm.category || 'عمومی',
            language: catalogForm.language || 'fa'
        };
        if (editingId) updateCatalog(editingId, data); else addCatalog(data);

    } else {
        if (!videoForm.title || !videoForm.coverImage || !videoForm.videoUrl) {
            alert('لطفا عنوان، تصویر کاور و آدرس ویدئو را تکمیل کنید');
            return;
        }
        const data: Video = {
            id: editingId || Date.now().toString(),
            title: videoForm.title!,
            description: videoForm.description || '',
            date: videoForm.date || '',
            videoUrl: videoForm.videoUrl!,
            coverImage: videoForm.coverImage!,
            duration: videoForm.duration
        };
        if (editingId) updateVideo(editingId, data); else addVideo(data);
    }
    resetForms();
  };

  const removePage = (index: number) => {
    const newPages = catalogForm.pages?.filter((_, i) => i !== index);
    setCatalogForm(prev => ({ ...prev, pages: newPages, pageCount: newPages?.length || 0 }));
  };

  const copyToClipboard = () => {
    if (!navigator.clipboard) {
        const textArea = document.createElement("textarea");
        textArea.value = dbCode;
        document.body.appendChild(textArea);
        textArea.select();
        document.execCommand('copy');
        document.body.removeChild(textArea);
        alert('کد کپی شد!');
        return;
    }
    navigator.clipboard.writeText(dbCode);
    alert('کد کپی شد! حالا محتوای فایل data.js را با این کد جایگزین کنید.');
  };

  const handleApplyCode = () => {
    try {
        let cleanJson = dbCode.trim();
        if (cleanJson.startsWith('window.NAFAS_DATA')) {
            const firstBrace = cleanJson.indexOf('{');
            const lastBrace = cleanJson.lastIndexOf('}');
            if (firstBrace !== -1 && lastBrace !== -1) {
                cleanJson = cleanJson.substring(firstBrace, lastBrace + 1);
            }
        }

        const data = JSON.parse(cleanJson);

        if (Array.isArray(data.catalogs) && Array.isArray(data.videos)) {
            importData(data.catalogs, data.videos);
            alert('تغییرات با موفقیت اعمال شد!');
        } else {
            alert('فرمت کد اشتباه است. باید شامل catalogs و videos باشد.');
        }
    } catch (e) {
        console.error(e);
        alert('خطا در پردازش کد. لطفا مطمئن شوید فرمت صحیح است.');
    }
  };

  const confirmDelete = () => {
    if (deleteConfirmation) {
      if (deleteConfirmation.type === 'catalogs') {
          deleteCatalog(deleteConfirmation.id);
      } else {
          deleteVideo(deleteConfirmation.id);
      }
      setDeleteConfirmation(null);
    }
  };

  return (
    <div className="min-h-screen bg-skin-base text-skin-text pb-20">

      {/* Delete Confirmation Modal */}
      {deleteConfirmation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
            <div className="bg-skin-card rounded-xl shadow-2xl max-w-sm w-full p-6 border border-skin-border">
                <div className="flex items-center gap-3 text-red-600 mb-4">
                    <div className="p-3 bg-red-100 rounded-full">
                        <AlertTriangle size={24} />
                    </div>
                    <h3 className="text-lg font-bold text-skin-text">حذف آیتم</h3>
                </div>
                <p className="text-skin-muted mb-6 text-sm leading-relaxed">
                    آیا از حذف این آیتم اطمینان دارید؟ این عملیات غیرقابل بازگشت است.
                </p>
                <div className="flex justify-end gap-3">
                    <button 
                        onClick={() => setDeleteConfirmation(null)}
                        className="px-4 py-2 text-skin-muted hover:bg-skin-control-bg rounded-lg transition-colors text-sm font-medium"
                    >
                        انصراف
                    </button>
                    <button 
                        onClick={confirmDelete}
                        className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors shadow-md text-sm font-medium flex items-center gap-2"
                    >
                        <Trash2 size={16} />
                        بله، حذف شود
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Admin Header */}
      <header className="bg-skin-card border-b border-skin-border sticky top-0 z-20">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
