                        </div>
                        <div className="w-px h-5 bg-skin-border mx-1"></div>
                        <button onClick={() => setDisplayMode('grid')} className={`p-1.5 rounded-lg ${displayMode === 'grid' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutGrid size={16} /></button>
                        <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-lg ${displayMode === 'list' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutList size={16} /></button>
                    </div>
                </div>
                {categories.length > 1 && (
                    <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                        {categories.map(cat => (
                            <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap transition-all ${selectedCategory === cat ? 'bg-skin-primary text-white shadow-md' : 'bg-skin-card border border-skin-border text-skin-text hover:bg-skin-control-bg'}`}>
                                {cat}
                            </button>
                        ))}
                    </div>
                )}
            </div>

            {isLoading ? (
                <div className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}>
                     {[1, 2, 3, 4].map(i => <SkeletonCard key={i} />)}
                </div>
            ) : processedCatalogs.length > 0 ? (
                <div className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}>
                {processedCatalogs.map(catalog => (
                    <CatalogCard key={catalog.id} catalog={catalog} onClick={handleOpenCatalog} viewMode={displayMode} />
                ))}
                </div>
            ) : (
                <div className="py-10 text-center text-skin-muted bg-skin-card border border-dashed border-skin-border rounded-xl"><p>هیچ کاتالوگی یافت نشد.</p></div>
            )}
        </div>

        {processedVideos.length > 0 && !isLoading && (
            <div className="mb-8 pt-8 border-t border-skin-border">
                <div className="mb-6">
                    <h3 className="text-xl md:text-2xl font-bold text-skin-text flex items-center gap-2 mb-2"><VideoIcon className="text-skin-primary" />ویدئوهای آموزشی</h3>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {processedVideos.map(video => <VideoCard key={video.id} video={video} onClick={setSelectedVideo} />)}
                </div>
            </div>
        )}
      </main>

      <footer className="border-t border-skin-border py-6 mt-12 bg-skin-base/50">
        <div className="container mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <p className="text-skin-muted text-sm text-center">© تمامی حقوق متعلق به شرکت نفس زیست فارمد است.</p>
            <a href="https://dbsgraphic.ir/" target="_blank" rel="noopener noreferrer" dir="ltr" className="text-[10px] text-skin-muted/80 hover:text-skin-primary transition-colors flex items-center gap-1 bg-skin-card/50 px-3 py-1.5 rounded-full border border-skin-border">
                Created with <span className="text-red-500 animate-pulse">❤</span> by DBS Graphic
            </a>
        </div>
      </footer>

      {/* AI ChatBot */}
      <ChatBot />

      {selectedCatalog && <BookViewer catalog={selectedCatalog} initialPage={initialPage} onClose={handleCloseViewer} />}
      {selectedVideo && <VideoPlayer video={selectedVideo} onClose={() => setSelectedVideo(null)} />}
    </div>
  );
}

function App() {
  return (<CatalogProvider><MainApp /></CatalogProvider>);
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Send, X, Bot, Loader2, Sparkles, User, Package, ChevronLeft, ArrowRight } from 'lucide-react';

const API_URL = './chat.php'; // آدرس فایل PHP

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

const PRODUCTS = [
    { id: 'capsulizer', name: 'کپسولایزر' },
    { id: 'coldanese', name: 'کلدانیز پلاس' },
    { id: 'folinozit', name: 'فولینوزیت' },
    { id: 'meglozek', name: 'مگلوزک' },
    { id: 'tiotoriva', name: 'تیوتوریوا' },
];

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<string | null>(null);

  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen, selectedProduct]);

  useEffect(() => {
    if (isOpen && selectedProduct && inputRef.current) {
        setTimeout(() => inputRef.current?.focus(), 300);
    }
  }, [isOpen, selectedProduct]);

  const handleProductSelect = (productId: string) => {
    setSelectedProduct(productId);
    const productName = PRODUCTS.find(p => p.id === productId)?.name;
    setMessages([
        {
            id: 'welcome',
            role: 'assistant',
            content: `سلام! من دستیار هوشمند محصول **${productName}** هستم. هر سوالی در مورد این دارو دارید بپرسید.`
        }
    ]);
  };

  const resetChat = () => {
      setSelectedProduct(null);
      setMessages([]);
      setInput('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading || !selectedProduct) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      // استفاده از URLSearchParams طبق درخواست شما برای فرمت application/x-www-form-urlencoded
      const body = new URLSearchParams();
      body.append('message', userMsg.content);
      body.append('product', selectedProduct);

      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
            "Content-Type": "application/x-www-form-urlencoded"
        },
        body: body,
      });

      if (!response.ok) throw new Error('Network response was not ok');

      const text = await response.text();

      const aiMsg: Message = { 
        id: (Date.now() + 1).toString(), 
        role: 'assistant', 
        content: text || 'متاسفانه مشکلی در دریافت پاسخ پیش آمد.' 
      };

      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error('Chat Error:', error);
      const errorMsg: Message = { 
        id: (Date.now() + 1).toString(), 
        role: 'assistant', 
        content: 'خطا در ارتباط با سرور. لطفا اتصال اینترنت خود را بررسی کنید.' 
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      {/* Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-40 p-4 rounded-full shadow-2xl transition-all duration-300 hover:scale-110 active:scale-95 group ${isOpen ? 'bg-skin-card text-skin-text rotate-90' : 'bg-skin-primary text-white'}`}
        style={{ boxShadow: '0 10px 30px -10px rgba(182, 22, 21, 0.5)' }}
      >
        {isOpen ? <X size={28} /> : (
            <>
                <MessageCircle size={28} className="absolute inset-0 m-auto animate-ping opacity-20" />
                <MessageCircle size={28} />
                <span className="absolute -top-1 -right-1 flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
                </span>
            </>
        )}
      </button>

      {/* Chat Window */}
      <div 
        className={`fixed bottom-24 right-4 sm:right-6 w-[calc(100%-2rem)] sm:w-96 bg-skin-card rounded-3xl shadow-2xl border border-skin-border flex flex-col overflow-hidden transition-all duration-300 origin-bottom-right z-40 ${isOpen ? 'opacity-100 scale-100 translate-y-0' : 'opacity-0 scale-95 translate-y-10 pointer-events-none'}`}
        style={{ height: 'min(500px, 70vh)' }}
      >
        {/* Header */}
        <div className="bg-skin-primary text-white p-4 flex items-center gap-3 shadow-md relative overflow-hidden shrink-0">
            <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-transparent"></div>

            {selectedProduct && (
                <button onClick={resetChat} className="relative z-10 p-1.5 rounded-full hover:bg-white/20 transition-colors -mr-2">
                    <ArrowRight size={20} />
                </button>
            )}

            <div className="bg-white/20 p-2 rounded-full backdrop-blur-sm relative z-10">
                <Bot size={24} />
            </div>

            <div className="relative z-10">
                <h3 className="font-bold text-lg leading-tight">
                    {selectedProduct 
                        ? PRODUCTS.find(p => p.id === selectedProduct)?.name 
                        : 'دستیار هوشمند'}
                </h3>
                <p className="text-[10px] text-white/80 flex items-center gap-1">
                    <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
                    {selectedProduct ? 'متصل به پایگاه دانش' : 'انتخاب محصول'}
                </p>
            </div>
            <Sparkles className="absolute top-2 left-2 text-white/10 w-24 h-24 -rotate-12" />
        </div>

        {/* Content Area */}
        {!selectedProduct ? (
            // Product Selection View
            <div className="flex-grow overflow-y-auto p-4 bg-skin-base/50 scrollbar-hide">
                <p className="text-skin-text text-sm mb-4 font-medium text-center">
                    لطفا محصولی که درباره آن سوال دارید را انتخاب کنید:
                </p>
                <div className="grid grid-cols-1 gap-2">
                    {PRODUCTS.map(product => (
                        <button 
                            key={product.id}
                            onClick={() => handleProductSelect(product.id)}
                            className="flex items-center gap-3 p-3 bg-skin-card hover:bg-skin-control-bg border border-skin-border rounded-xl transition-all hover:translate-x-[-4px] group text-right"
                        >
                            <div className="bg-skin-primary/10 text-skin-primary p-2 rounded-lg group-hover:bg-skin-primary group-hover:text-white transition-colors">
                                <Package size={20} />
                            </div>
                            <span className="text-sm font-bold text-skin-text">{product.name}</span>
                            <ChevronLeft size={16} className="mr-auto text-skin-muted" />
                        </button>
                    ))}
                </div>
            </div>
        ) : (
            // Chat Interface
            <>
                <div className="flex-grow overflow-y-auto p-4 space-y-4 bg-skin-base/50 scrollbar-hide">
                    {messages.map((msg) => (
                        <div 
                            key={msg.id} 
                            className={`flex items-end gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
                        >
                            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-skin-control-bg text-skin-text' : 'bg-skin-primary/10 text-skin-primary'}`}>
                                {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                            </div>
                            <div 
                                className={`max-w-[80%] p-3 rounded-2xl text-sm leading-relaxed ${
                                    msg.role === 'user' 
                                    ? 'bg-skin-primary text-white rounded-br-none shadow-md shadow-skin-primary/20' 
                                    : 'bg-skin-card border border-skin-border text-skin-text rounded-bl-none shadow-sm'
                                }`}
                            >
                                {/* Simple Markdown-like bold rendering for specific product name */}
                                {msg.content.split('**').map((part, i) => 
                                    i % 2 === 1 ? <strong key={i}>{part}</strong> : part
                                )}
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex items-end gap-2">
                            <div className="w-8 h-8 rounded-full bg-skin-primary/10 text-skin-primary flex items-center justify-center flex-shrink-0">
                                <Bot size={16} />
                            </div>
                            <div className="bg-skin-card border border-skin-border p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-1">
                                <span className="w-1.5 h-1.5 bg-skin-muted rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                <span className="w-1.5 h-1.5 bg-skin-muted rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                <span className="w-1.5 h-1.5 bg-skin-muted rounded-full animate-bounce"></span>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input */}
                <form onSubmit={handleSubmit} className="p-3 bg-skin-card border-t border-skin-border">
                    <div className="flex items-center gap-2 bg-skin-control-bg rounded-full px-4 py-2 focus-within:ring-2 focus-within:ring-skin-primary/50 transition-all border border-transparent focus-within:border-skin-primary">
                        <input
                            ref={inputRef}
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder="پیام خود را بنویسید..."
                            className="flex-grow bg-transparent border-none outline-none text-sm text-skin-text placeholder-skin-muted"
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={!input.trim() || isLoading}
                            className="p-2 bg-skin-primary text-white rounded-full hover:bg-skin-primary-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-sm"
                        >
                            {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} className={input.trim() ? '' : 'opacity-80'} />}
                        </button>
                    </div>
                    <div className="text-[10px] text-center text-skin-muted mt-2">
                        هوش مصنوعی ممکن است اشتباه کند.
                    </div>
                </form>
            </>
        )}
      </div>
    </>
  );
};

export default ChatBot;

import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import BookViewer from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import SkeletonCard from './components/SkeletonCard';
import ChatBot from './components/ChatBot'; // Import ChatBot
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon, Filter } from 'lucide-react';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [initialPage, setInitialPage] = useState(0);

  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [sortBy, setSortBy] = useState<SortOption>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('همه');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  const categories = ['همه', ...new Set(catalogs.map(c => c.category).filter(Boolean))];

  // --- Deep Linking: Parse URL on mount or when catalogs load ---
  useEffect(() => {
    if (catalogs.length > 0) {
      const params = new URLSearchParams(window.location.search);
      const catId = params.get('cat');
      const pageNum = params.get('page');

      if (catId) {
        const found = catalogs.find(c => c.id === catId);
        if (found) {
          let pIndex = 0;
          if (pageNum) {
            pIndex = Math.max(0, parseInt(pageNum) - 1);
            if (pIndex >= found.pages.length) pIndex = 0;
          }
          setInitialPage(pIndex);
          setSelectedCatalog(found);
        }
      }
    }
  }, [catalogs]);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 1200);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const handleResize = () => setDisplayMode(window.innerWidth < 768 ? 'list' : 'grid');
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    if (window.location.hash === '#admin') setViewMode('admin');
  }, []);

  const getProcessedCatalogs = () => {
    let result = catalogs.filter(cat => 
        (selectedCategory === 'همه' || cat.category === selectedCategory) &&
        (cat.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        cat.description.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    return result.sort((a, b) => {
        switch (sortBy) {
            case 'newest': return b.date.localeCompare(a.date);
            case 'oldest': return a.date.localeCompare(b.date);
            case 'az': return a.title.localeCompare(b.title, 'fa');
            case 'za': return b.title.localeCompare(a.title, 'fa');
            default: return 0;
        }
    });
  };

  const processedCatalogs = getProcessedCatalogs();

  const processedVideos = videos.filter(vid => 
     vid.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
     vid.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const getThemeIcon = () => {
    switch(theme) {
        case 'light': return <Sun size={20} />;
        case 'dark': return <Moon size={20} />;
        case 'reading': return <BookOpen size={20} />;
    }
  };

  const handleCloseViewer = () => {
    setSelectedCatalog(null);
    const newUrl = window.location.pathname;
    window.history.replaceState({}, '', newUrl);
  };

  const handleOpenCatalog = (cat: Catalog) => {
    setInitialPage(0);
    setSelectedCatalog(cat);
  };

  if (viewMode === 'admin') {
    if (!isAuthenticated) return <AdminLogin onLogin={() => setIsAuthenticated(true)} onBack={() => setViewMode('home')} />;
    return <AdminPanel onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} />;
  }

  return (
    <div className="min-h-screen font-sans bg-skin-base text-skin-text transition-colors duration-300 relative flex flex-col">
      <header className="sticky top-0 z-40 w-full backdrop-blur-lg bg-skin-base/80 border-b border-skin-border transition-all duration-300">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src="https://nafaspharmed.com/wp-content/uploads/2025/11/logo_fa.png" alt="نفس فارمد" className="h-10 w-auto object-contain" />
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex items-center bg-skin-card border border-skin-border rounded-full px-4 py-2 w-80 focus-within:border-skin-primary transition-colors">
                <Search size={18} className="text-skin-muted ml-2" />
                <input type="text" placeholder="جستجو..." className="bg-transparent border-none outline-none text-sm text-skin-text w-full placeholder-skin-muted" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
             </div>
             <button onClick={toggleTheme} className="flex items-center gap-2 px-3 py-2 rounded-lg bg-skin-card border border-skin-border text-skin-text hover:bg-skin-control-hover transition-colors">
                {getThemeIcon()}
             </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 md:py-12 flex-grow">
        <div className="mb-8 text-center md:text-right border-b border-skin-border pb-8 animate-fade-in">
            <h2 className="text-2xl md:text-4xl font-black text-skin-text mb-4 leading-tight">پورتال آموزشی <span className="text-transparent bg-clip-text bg-gradient-to-r from-skin-primary to-skin-primary-hover">نفس زیست فارمد</span></h2>
            <p className="text-skin-muted text-sm md:text-lg">دسترسی سریع به جدیدترین کاتالوگ‌ها، بروشورها و ویدئوهای آموزشی</p>
        </div>

        <div className="md:hidden mb-6">
             <div className="flex items-center bg-skin-card border border-skin-border rounded-xl px-4 py-3 w-full focus-within:border-skin-primary transition-colors shadow-sm">
                <Search size={20} className="text-skin-muted ml-3" />
                <input type="text" placeholder="جستجو..." className="bg-transparent border-none outline-none text-skin-text w-full placeholder-skin-muted" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
        </div>

        <div className="mb-12">
            <div className="flex flex-col gap-4 mb-6">
                <div className="flex flex-col sm:flex-row justify-between items-end gap-4">
                    <h3 className="text-xl md:text-2xl font-bold text-skin-text flex items-center gap-2"><BookOpen className="text-skin-primary" />کاتالوگ‌ها</h3>
                    <div className="flex items-center gap-2 bg-skin-card p-1.5 rounded-xl border border-skin-border shadow-sm">
                        <div className="relative flex items-center">
                            <ArrowDownUp size={16} className="absolute right-2 text-skin-muted pointer-events-none" />
                            <select value={sortBy} onChange={(e) => setSortBy(e.target.value as SortOption)} className="appearance-none bg-skin-control-bg hover:bg-skin-control-hover text-skin-text text-xs rounded-lg pr-7 pl-2 py-1.5 outline-none cursor-pointer">
                                <option value="newest">جدیدترین</option><option value="oldest">قدیمی‌ترین</option><option value="az">حروف الفبا</option>
                            </select>
                        </div>
                        <div className="w-px h-5 bg-skin-border mx-1"></div>
                        <button onClick={() => setDisplayMode('grid')} className={`p-1.5 rounded-lg ${displayMode === 'grid' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutGrid size={16} /></button>
                        <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-lg ${displayMode === 'list' ? 'bg-skin-control-hover text-skin-primary' : 'text-skin-muted'}`}><LayoutList size={16} /></button>
                    </div>
                </div>
                {categories.length > 1 && (
                    <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                        {categories.map(cat => (
                            <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap transition-all ${selectedCategory === cat ? 'bg-skin-primary text-white shadow-md' : 'bg-skin-card border border-skin-border text-skin-text hover:bg-skin-control-bg'}`}>
                                {cat}
                            </button>
                        ))}
                    </div>
                )}
            </div>

            {isLoading ? (
