import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  Maximize, 
  Minimize, 
  Volume2, 
  VolumeX,
  FileDown,
  ZoomIn,
  ZoomOut,
  Book,
  Smartphone,
  ChevronUp,
  ChevronDown,
  Highlighter,
  StickyNote,
  MousePointer2,
  Trash2,
  Check,
  MessageSquare
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
  initialPage?: number;
}

// Annotation Types
interface Annotation {
  id: string;
  type: 'highlight' | 'note';
  x: number; // Percentage 0-100
  y: number; // Percentage 0-100
  width?: number; // Percentage for highlight
  height?: number; // Percentage for highlight
  content?: string; // For notes
  color?: string;
}

// Sound effect URL
const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// Helper for distance between two touch points
const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

// --- Annotation Layer Component ---
interface AnnotationLayerProps {
    activeTool: 'cursor' | 'highlight' | 'note';
    annotations: Annotation[];
    onAdd: (ann: Annotation) => void;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
}

const AnnotationLayer: React.FC<AnnotationLayerProps> = ({ activeTool, annotations, onAdd, onUpdate, onDelete }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);
    const [startPoint, setStartPoint] = useState({ x: 0, y: 0 });
    const [currentPoint, setCurrentPoint] = useState({ x: 0, y: 0 });
    const [activeNoteId, setActiveNoteId] = useState<string | null>(null);

    const getRelativeCoords = (e: any) => {
        if (!containerRef.current) return { x: 0, y: 0 };
        const rect = containerRef.current.getBoundingClientRect();
        const clientX = e.touches ? e.touches[0].clientX : e.clientX;
        const clientY = e.touches ? e.touches[0].clientY : e.clientY;

        return {
            x: ((clientX - rect.left) / rect.width) * 100,
            y: ((clientY - rect.top) / rect.height) * 100
        };
    };

    const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
        if (activeTool === 'cursor') return;

        // Only start drawing if we are in highlight mode and NOT clicking an existing note
        if (activeTool === 'highlight') {
            const coords = getRelativeCoords(e);
            setIsDrawing(true);
            setStartPoint(coords);
            setCurrentPoint(coords);
        }
    };

    const handlePointerMove = (e: any) => {
        if (!isDrawing) return;
        setCurrentPoint(getRelativeCoords(e));
    };

    const handlePointerUp = () => {
        if (!isDrawing) return;
        setIsDrawing(false);

        const x = Math.min(startPoint.x, currentPoint.x);
        const y = Math.min(startPoint.y, currentPoint.y);
        const width = Math.abs(currentPoint.x - startPoint.x);
        const height = Math.abs(currentPoint.y - startPoint.y);

        if (width > 0.5 && height > 0.5) {
            onAdd({
                id: Date.now().toString(),
                type: 'highlight',
                x, y, width, height,
                color: 'rgba(253, 224, 71, 0.4)'
            });
        }
    };

    const handleClick = (e: React.MouseEvent) => {
        if (activeTool === 'note') {
            const coords = getRelativeCoords(e);
            const newId = Date.now().toString();
            onAdd({
                id: newId,
                type: 'note',
                x: coords.x,
                y: coords.y,
                content: ''
            });
            setActiveNoteId(newId);
        }
    };

    return (
        <div 
            ref={containerRef}
            className={`absolute inset-0 z-20 ${activeTool !== 'cursor' ? 'cursor-crosshair pointer-events-auto' : 'pointer-events-none'}`}
            onMouseDown={handlePointerDown}
            onMouseMove={handlePointerMove}
            onMouseUp={handlePointerUp}
            onTouchStart={handlePointerDown}
            onTouchMove={handlePointerMove}
            onTouchEnd={handlePointerUp}
            onClick={handleClick}
        >
            {annotations.map(ann => (
                <div 
                    key={ann.id}
                    className="absolute pointer-events-auto group"
                    style={{
                        left: `${ann.x}%`,
                        top: `${ann.y}%`,
                        width: ann.type === 'highlight' ? `${ann.width}%` : 'auto',
                        height: ann.type === 'highlight' ? `${ann.height}%` : 'auto',
                    }}
                    onClick={(e) => {
                        e.stopPropagation();
                        if (ann.type === 'note') {
                            setActiveNoteId(activeNoteId === ann.id ? null : ann.id);
                        }
                    }}
                >
                    {ann.type === 'highlight' && (
                        <div className="w-full h-full bg-yellow-300/40 border border-yellow-400/20 relative">
                             <button 
                                onClick={(e) => { e.stopPropagation(); onDelete(ann.id); }}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                                <X size={12} />
                            </button>
                        </div>
                    )}

                    {ann.type === 'note' && (
                        <div className="relative -translate-x-1/2 -translate-y-1/2">
                            <div className={`p-1.5 rounded-full shadow-lg transition-transform hover:scale-110 ${activeNoteId === ann.id ? 'bg-yellow-400 text-yellow-900 ring-2 ring-yellow-600' : 'bg-yellow-200 text-yellow-700'}`}>
                                <MessageSquare size={18} fill={activeNoteId === ann.id ? "currentColor" : "none"} />
                            </div>

                            {activeNoteId === ann.id && (
                                <div 
                                    className="absolute top-8 left-1/2 -translate-x-1/2 w-48 sm:w-64 bg-yellow-50 border border-yellow-200 rounded-lg shadow-2xl p-3 z-50 text-right animate-fade-in"
                                    onClick={e => e.stopPropagation()}
                                >
                                    <textarea 
                                        className="w-full bg-transparent border-b border-yellow-200 resize-none outline-none text-sm text-gray-800 min-h-[60px] mb-2 placeholder-yellow-800/50"
                                        placeholder="یادداشت..."
                                        value={ann.content}
                                        onChange={(e) => onUpdate(ann.id, e.target.value)}
                                        autoFocus
                                    />
                                    <div className="flex justify-between items-center">
                                        <button onClick={() => onDelete(ann.id)} className="text-red-500 hover:bg-red-50 p-1 rounded transition-colors"><Trash2 size={14} /></button>
                                        <button onClick={() => setActiveNoteId(null)} className="bg-yellow-500 text-white px-2 py-0.5 rounded text-xs hover:bg-yellow-600 flex items-center gap-1"><Check size={12} /> تایید</button>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            ))}

            {isDrawing && (
                <div 
                    className="absolute bg-yellow-300/30 border border-yellow-400 border-dashed pointer-events-none"
                    style={{
                        left: `${Math.min(startPoint.x, currentPoint.x)}%`,
                        top: `${Math.min(startPoint.y, currentPoint.y)}%`,
                        width: `${Math.abs(currentPoint.x - startPoint.x)}%`,
                        height: `${Math.abs(currentPoint.y - startPoint.y)}%`,
                    }}
                />
            )}
        </div>
    );
};

// ForwardRef for Page
const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none z-10">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(initialPage);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });

  // Settings
  const [isMobile, setIsMobile] = useState(false);
  const [forceSinglePage, setForceSinglePage] = useState(false);

  // UI Settings
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  // Panel States
  const [showTopPanel, setShowTopPanel] = useState(true);
  const [showBottomPanel, setShowBottomPanel] = useState(true);

  // Gesture State
  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isGesturing, setIsGesturing] = useState(false);

  // Annotation State
  const [activeTool, setActiveTool] = useState<'cursor' | 'highlight' | 'note'>('cursor');
  const [annotations, setAnnotations] = useState<Record<number, Annotation[]>>({});

  // Gesture Refs
  const gesture = useRef({
    startX: 0,
    startY: 0,
    startPanX: 0,
    startPanY: 0,
    startDist: 0,
    startZoom: 1,
    mode: 'none' as 'none' | 'swipe' | 'pan' | 'pinch',
  });

  // Load Annotations
  useEffect(() => {
    const saved = localStorage.getItem(`nafas_ann_${catalog.id}`);
    if (saved) {
      try {
        setAnnotations(JSON.parse(saved));
      } catch (e) { console.error('Failed to load annotations', e); }
    }
  }, [catalog.id]);

  // Save Annotations
  useEffect(() => {
    if (Object.keys(annotations).length > 0) {
      localStorage.setItem(`nafas_ann_${catalog.id}`, JSON.stringify(annotations));
    }
  }, [annotations, catalog.id]);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // Sync initial page
  useEffect(() => {
    if (initialPage > 0 && bookRef.current) {
        setTimeout(() => {
            bookRef.current.pageFlip()?.flip(initialPage);
        }, 300);
    }
  }, [initialPage]);

  // Responsive Resizing
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;
      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);

      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 20 : 100;

      const availableHeight = windowHeight - verticalPadding;
      const availableWidth = windowWidth - horizontalPadding;

      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      // Ensure dimensions are positive
      setDimensions({ 
          width: Math.max(300, Math.floor(bookWidth)), 
          height: Math.max(400, Math.floor(bookHeight)) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Fullscreen Handler
  useEffect(() => {
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Reset Pan
  useEffect(() => {
    if (zoomLevel <= 1) setPan({ x: 0, y: 0 });
  }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const onInit = useCallback((e: any) => {
    setTotalPages(e.object.pages.length);
  }, []);

  const nextFlip = () => bookRef.current?.pageFlip()?.flipNext();
  const prevFlip = () => bookRef.current?.pageFlip()?.flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip()?.flip(index);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(() => {});
    } else {
        document.exitFullscreen();
    }
  };

  const handleZoomIn = () => setZoomLevel(prev => Math.min(prev + 0.2, 4.0));
  const handleZoomOut = () => setZoomLevel(prev => Math.max(prev - 0.2, 0.5));

  const handleAddAnnotation = (pageIndex: number, ann: Annotation) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: [...(prev[pageIndex] || []), ann]
      }));
  };

  const handleUpdateAnnotation = (pageIndex: number, id: string, content: string) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: prev[pageIndex]?.map(a => a.id === id ? { ...a, content } : a) || []
      }));
  };

  const handleDeleteAnnotation = (pageIndex: number, id: string) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: prev[pageIndex]?.filter(a => a.id !== id) || []
      }));
  };

  const handleDownload = () => {
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title}.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- GESTURES ---
  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    if (activeTool !== 'cursor') return;
    setIsGesturing(true);
    gesture.current.startX = clientX;
    gesture.current.startY = clientY;
    gesture.current.mode = mode;
    if (mode === 'pan') {
      gesture.current.startPanX = pan.x;
      gesture.current.startPanY = pan.y;
    }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'cursor') return;
    if (gesture.current.mode === 'pan') {
      setPan({ 
        x: gesture.current.startPanX + (clientX - gesture.current.startX), 
        y: gesture.current.startPanY + (clientY - gesture.current.startY) 
      });
    }
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'cursor') return;
    setIsGesturing(false);
    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      if (Math.abs(dx) > 40) {
        if (dx > 0) prevFlip(); else nextFlip(); 
      }
    }
    gesture.current.mode = 'none';
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden"
    >
      <div className="flex-grow flex flex-col h-full relative">

        {/* --- TOP PANEL --- */}
        <div className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-30 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}>
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <span className="text-skin-muted text-xs">صفحه {currentPage + 1} از {catalog.pages.length}</span>
                </div>

                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border">
                        {/* Toolset */}
                        <div className="flex items-center border-l border-gray-300 ml-1 pl-1">
                            <button onClick={() => setActiveTool('cursor')} className={`p-2 rounded transition-colors ${activeTool === 'cursor' ? 'bg-skin-card text-skin-primary' : 'hover:bg-skin-control-hover'}`} title="انتخابگر"><MousePointer2 size={18} /></button>
                            <button onClick={() => setActiveTool('highlight')} className={`p-2 rounded transition-colors ${activeTool === 'highlight' ? 'bg-yellow-200 text-yellow-900' : 'hover:bg-skin-control-hover'}`} title="هایلایتر"><Highlighter size={18} /></button>
                            <button onClick={() => setActiveTool('note')} className={`p-2 rounded transition-colors ${activeTool === 'note' ? 'bg-yellow-200 text-yellow-900' : 'hover:bg-skin-control-hover'}`} title="یادداشت"><StickyNote size={18} /></button>
                        </div>
                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 hover:bg-skin-control-hover rounded transition-colors">{forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}</button>
                        <button onClick={handleZoomOut} className="p-2 hover:bg-skin-control-hover rounded"><ZoomOut size={18} /></button>
                        <span className="text-xs w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 hover:bg-skin-control-hover rounded"><ZoomIn size={18} /></button>
                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 hover:bg-skin-control-hover rounded">{isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}</button>
                        <button onClick={toggleFullscreen} className="p-2 hover:bg-skin-control-hover rounded"><Maximize size={18} /></button>
                        <button onClick={handleDownload} className="p-2 hover:bg-skin-control-hover rounded"><FileDown size={18} /></button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg hover:bg-red-500 hover:text-white transition-colors"><X size={20} /></button>
                </div>
            </div>
            <div className="flex justify-center -mb-3 pb-1"><button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary"><ChevronUp size={16} /></button></div>
        </div>

        {/* --- BOOK AREA --- */}
        <div 
            className={`flex-grow flex items-center justify-center relative w-full h-full overflow-hidden ${activeTool === 'cursor' ? 'cursor-grab active:cursor-grabbing' : ''} pb-20 pt-20`}
            onMouseDown={(e) => startGesture(e.clientX, e.clientY, zoomLevel > 1 ? 'pan' : 'swipe')}
            onMouseMove={(e) => moveGesture(e.clientX, e.clientY)}
            onMouseUp={(e) => endGesture(e.clientX, e.clientY)}
            onTouchStart={(e) => startGesture(e.touches[0].clientX, e.touches[0].clientY, zoomLevel > 1 ? 'pan' : 'swipe')}
            onTouchMove={(e) => moveGesture(e.touches[0].clientX, e.touches[0].clientY)}
            onTouchEnd={(e) => endGesture(e.changedTouches[0].clientX, e.changedTouches[0].clientY)}
        >
            <div 
                style={{ 
                    transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`,
                    transition: isGesturing ? 'none' : 'transform 0.2s ease-out'
                }}
                className="relative"
            >
                {/* @ts-ignore */}
                <HTMLFlipBook
                    key={`${dimensions.width}-${forceSinglePage}`} 
                    width={dimensions.width}
                    height={dimensions.height}
                    size="fixed"
                    showCover={false}
                    onFlip={onFlip}
                    onInit={onInit}
                    ref={bookRef}
                    usePortrait={forceSinglePage}
                    startPage={initialPage}
                    flippingTime={600}
                    useMouseEvents={false}
                    className="shadow-2xl"
                >
                    {catalog.pages.map((pageUrl, idx) => (
                        <Page number={idx + 1} key={idx}>
                             <div className="w-full h-full relative">
                                <img src={pageUrl} alt={`Page ${idx + 1}`} className="w-full h-full object-contain pointer-events-none" />
                                <AnnotationLayer 
                                    activeTool={activeTool}
                                    annotations={annotations[idx] || []}
                                    onAdd={(ann) => handleAddAnnotation(idx, ann)}
                                    onUpdate={(id, content) => handleUpdateAnnotation(idx, id, content)}
                                    onDelete={(id) => handleDeleteAnnotation(idx, id)}
                                />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>

            <button onClick={prevFlip} className="hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary text-white rounded-full shadow-xl hover:scale-110 transition-transform"><ChevronLeft size={24} /></button>
            <button onClick={nextFlip} className="hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary text-white rounded-full shadow-xl hover:scale-110 transition-transform"><ChevronRight size={24} /></button>
        </div>

        {/* --- BOTTOM PANEL --- */}
        <div className={`absolute bottom-0 left-0 right-0 z-30 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>
             <div className="flex justify-center -mt-3 pt-1"><button onClick={() => setShowBottomPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary"><ChevronDown size={16} /></button></div>

             {/* Mobile Toolbar */}
             <div className="md:hidden bg-skin-card border-t p-3 flex justify-between items-center shadow-lg">
                <div className="flex gap-2">
                    <button onClick={() => setActiveTool('cursor')} className={`p-2 rounded ${activeTool === 'cursor' ? 'bg-skin-primary text-white' : 'text-skin-muted'}`}><MousePointer2 size={18} /></button>
                    <button onClick={() => setActiveTool('highlight')} className={`p-2 rounded ${activeTool === 'highlight' ? 'bg-yellow-100 text-yellow-800' : 'text-skin-muted'}`}><Highlighter size={18} /></button>
                    <button onClick={() => setActiveTool('note')} className={`p-2 rounded ${activeTool === 'note' ? 'bg-yellow-100 text-yellow-800' : 'text-skin-muted'}`}><StickyNote size={18} /></button>
                </div>
                <div className="flex gap-3">
                    <button onClick={handleZoomOut}><ZoomOut size={20} /></button>
                    <button onClick={handleZoomIn}><ZoomIn size={20} /></button>
                    <button onClick={handleDownload}><FileDown size={20} /></button>
                </div>
             </div>

             {/* Thumbnails */}
             <div className="h-20 bg-skin-card/90 backdrop-blur-md border-t flex items-center px-4 gap-2 overflow-x-auto scrollbar-hide">
                 {catalog.pages.map((page, idx) => (
                     <button key={idx} onClick={() => goToPage(idx)} className={`shrink-0 h-16 w-12 rounded border-2 transition-all ${currentPage === idx ? 'border-skin-primary scale-110 shadow-md' : 'border-transparent opacity-60'}`}>
                         <img src={page} className="w-full h-full object-cover rounded-sm" />
                     </button>
                 ))}
             </div>
        </div>

        {/* Expanders */}
        {!showTopPanel && <button onClick={() => setShowTopPanel(true)} className="fixed top-4 left-1/2 -translate-x-1/2 z-40 bg-skin-card p-2 rounded-full shadow-lg text-skin-muted"><ChevronDown size={20} /></button>}
        {!showBottomPanel && <button onClick={() => setShowBottomPanel(true)} className="fixed bottom-4 left-1/2 -translate-x-1/2 z-40 bg-skin-card p-2 rounded-full shadow-lg text-skin-muted"><ChevronUp size={20} /></button>}
      </div>
    </div>
  );
};

export default BookViewer;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  Maximize, 
  Minimize, 
  Volume2, 
  VolumeX,
  FileDown,
  ZoomIn,
  ZoomOut,
  Book,
  Smartphone,
  ChevronUp,
  ChevronDown,
  Highlighter,
  StickyNote,
  MousePointer2,
  Trash2,
  Check,
  MessageSquare
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
  initialPage?: number;
}

// Annotation Types
interface Annotation {
  id: string;
  type: 'highlight' | 'note';
  x: number; // Percentage 0-100
  y: number; // Percentage 0-100
  width?: number; // Percentage for highlight
  height?: number; // Percentage for highlight
  content?: string; // For notes
  color?: string;
  isOpen?: boolean; // For notes UI state
}

// Sound effect URL
const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// Helper for distance between two touch points
const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

// --- Annotation Layer Component ---
interface AnnotationLayerProps {
    pageIndex: number;
    activeTool: 'cursor' | 'highlight' | 'note';
    annotations: Annotation[];
    onAdd: (ann: Annotation) => void;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
}

const AnnotationLayer: React.FC<AnnotationLayerProps> = ({ pageIndex, activeTool, annotations, onAdd, onUpdate, onDelete }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);
    const [startPoint, setStartPoint] = useState({ x: 0, y: 0 });
    const [currentPoint, setCurrentPoint] = useState({ x: 0, y: 0 });
    const [activeNoteId, setActiveNoteId] = useState<string | null>(null);

    const getRelativeCoords = (e: React.MouseEvent | React.TouchEvent) => {
        if (!containerRef.current) return { x: 0, y: 0 };
        const rect = containerRef.current.getBoundingClientRect();
        const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

        return {
            x: ((clientX - rect.left) / Math.max(rect.width, 1)) * 100,
            y: ((clientY - rect.top) / Math.max(rect.height, 1)) * 100
        };
    };

    const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
        if (activeTool === 'cursor') return;
        e.stopPropagation();

        if (activeTool === 'highlight') {
            setIsDrawing(true);
            const coords = getRelativeCoords(e);
            setStartPoint(coords);
            setCurrentPoint(coords);
        }
    };

    const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isDrawing) return;
        e.stopPropagation();
        setCurrentPoint(getRelativeCoords(e));
    };

    const handlePointerUp = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isDrawing) return;
        e.stopPropagation();
        setIsDrawing(false);

        const x = Math.min(startPoint.x, currentPoint.x);
        const y = Math.min(startPoint.y, currentPoint.y);
        const width = Math.abs(currentPoint.x - startPoint.x);
        const height = Math.abs(currentPoint.y - startPoint.y);

        if (width > 1 && height > 1) {
            onAdd({
                id: Date.now().toString(),
                type: 'highlight',
                x, y, width, height,
                color: '#fde047'
            });
        }
    };

    const handleClick = (e: React.MouseEvent) => {
        if (activeTool === 'note') {
            e.stopPropagation();
            if ((e.target as HTMLElement).closest('.annotation-item')) return;

            const coords = getRelativeCoords(e);
            const newId = Date.now().toString();
            onAdd({
                id: newId,
                type: 'note',
                x: coords.x, 
                y: coords.y,
                content: '',
                color: '#fef08a'
            });
            setActiveNoteId(newId);
        }
    };

    return (
        <div 
            ref={containerRef}
            className={`absolute inset-0 z-10 ${activeTool !== 'cursor' ? 'cursor-crosshair touch-none pointer-events-auto' : 'pointer-events-none'}`}
            onMouseDown={handlePointerDown}
            onMouseMove={handlePointerMove}
            onMouseUp={handlePointerUp}
            onTouchStart={handlePointerDown}
            onTouchMove={handlePointerMove}
            onTouchEnd={handlePointerUp}
            onClick={handleClick}
        >
            {annotations.map(ann => (
                <div 
                    key={ann.id}
                    className="annotation-item absolute pointer-events-auto group"
                    style={{
                        left: `${ann.x}%`,
                        top: `${ann.y}%`,
                        width: ann.type === 'highlight' ? `${ann.width}%` : 'auto',
                        height: ann.type === 'highlight' ? `${ann.height}%` : 'auto',
                    }}
                    onClick={(e) => {
                        if (activeTool === 'cursor' || activeTool === 'highlight') {
                            e.stopPropagation();
                            if (ann.type === 'note') setActiveNoteId(activeNoteId === ann.id ? null : ann.id);
                        }
                    }}
                >
                    {ann.type === 'highlight' && (
                        <div className="w-full h-full bg-yellow-300/40 mix-blend-multiply border border-yellow-400/30 hover:bg-yellow-300/60 transition-colors relative">
                             <button 
                                onClick={(e) => { e.stopPropagation(); onDelete(ann.id); }}
                                className="absolute -top-3 -right-3 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity transform scale-75"
                            >
                                <X size={12} />
                            </button>
                        </div>
                    )}

                    {ann.type === 'note' && (
                        <div className="relative -translate-x-1/2 -translate-y-1/2">
                            <button 
                                onClick={(e) => { e.stopPropagation(); setActiveNoteId(activeNoteId === ann.id ? null : ann.id); }}
                                className={`p-1.5 rounded-full shadow-md transition-transform hover:scale-110 ${activeNoteId === ann.id ? 'bg-yellow-400 text-yellow-900 ring-2 ring-yellow-500' : 'bg-yellow-200 text-yellow-700'}`}
                            >
                                <MessageSquare size={20} fill={activeNoteId === ann.id ? "currentColor" : "none"} />
                            </button>

                            {activeNoteId === ann.id && (
                                <div 
                                    className="absolute top-8 left-1/2 -translate-x-1/2 w-48 sm:w-64 bg-yellow-100 border border-yellow-300 rounded-lg shadow-xl p-3 z-50 text-left cursor-default animate-fade-in"
                                    onClick={e => e.stopPropagation()}
                                >
                                    <textarea 
                                        className="w-full bg-transparent border-b border-yellow-200 resize-none outline-none text-sm text-gray-800 min-h-[80px] mb-2 placeholder-yellow-800/50"
                                        placeholder="یادداشت خود را بنویسید..."
                                        value={ann.content}
                                        onChange={(e) => onUpdate(ann.id, e.target.value)}
                                        autoFocus
                                    />
                                    <div className="flex justify-between items-center">
                                        <button 
                                            onClick={() => onDelete(ann.id)}
                                            className="text-red-500 hover:bg-red-100 p-1 rounded transition-colors"
                                            title="حذف یادداشت"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                        <button 
                                            onClick={() => setActiveNoteId(null)}
                                            className="bg-yellow-500 text-white px-3 py-1 rounded text-xs hover:bg-yellow-600 transition-colors flex items-center gap-1"
                                        >
                                            <Check size={14} />
                                            بستن
                                        </button>
                                    </div>
                                    <div className="absolute -top-2 left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-b-[8px] border-b-yellow-100"></div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            ))}

            {isDrawing && (
                <div 
                    className="absolute bg-yellow-300/40 border border-yellow-400 border-dashed pointer-events-none"
                    style={{
                        left: `${Math.min(startPoint.x, currentPoint.x)}%`,
                        top: `${Math.min(startPoint.y, currentPoint.y)}%`,
                        width: `${Math.abs(currentPoint.x - startPoint.x)}%`,
                        height: `${Math.abs(currentPoint.y - startPoint.y)}%`,
                    }}
                />
            )}
        </div>
    );
};

const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden select-none">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none z-10">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(initialPage);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });

  const [isMobile, setIsMobile] = useState(false);
  const [forceSinglePage, setForceSinglePage] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  const [showTopPanel, setShowTopPanel] = useState(true);
  const [showBottomPanel, setShowBottomPanel] = useState(true);

  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isGesturing, setIsGesturing] = useState(false);

  const [activeTool, setActiveTool] = useState<'cursor' | 'highlight' | 'note'>('cursor');
  const [annotations, setAnnotations] = useState<Record<number, Annotation[]>>({});

  const gesture = useRef({
    startX: 0,
    startY: 0,
    startPanX: 0,
    startPanY: 0,
    startDist: 0,
    startZoom: 1,
    mode: 'none' as 'none' | 'swipe' | 'pan' | 'pinch',
  });

  useEffect(() => {
    const saved = localStorage.getItem(`nafas_ann_${catalog.id}`);
    if (saved) {
        try {
            setAnnotations(JSON.parse(saved));
        } catch (e) { console.error('Error loading annotations', e); }
    }
  }, [catalog.id]);

  useEffect(() => {
    if (Object.keys(annotations).length > 0) {
        localStorage.setItem(`nafas_ann_${catalog.id}`, JSON.stringify(annotations));
    }
  }, [annotations, catalog.id]);

  const handleAddAnnotation = (pageIndex: number, ann: Annotation) => {
    setAnnotations(prev => ({
        ...prev,
        [pageIndex]: [...(prev[pageIndex] || []), ann]
    }));
    if (ann.type === 'highlight') setActiveTool('cursor'); 
  };

  const handleUpdateAnnotation = (pageIndex: number, id: string, content: string) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: prev[pageIndex]?.map(a => a.id === id ? { ...a, content } : a) || []
      }));
  };

  const handleDeleteAnnotation = (pageIndex: number, id: string) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: prev[pageIndex]?.filter(a => a.id !== id) || []
      }));
  };

  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;

    const timeout = setTimeout(() => {
        if (initialPage > 0 && bookRef.current) {
            try {
                bookRef.current.pageFlip()?.flip(initialPage);
            } catch (err) { console.warn('Delayed flip failed', err); }
        }
    }, 500);
    return () => clearTimeout(timeout);
  }, [initialPage]);

  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;
      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);

      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 0 : 100;

      const availableHeight = Math.max(windowHeight - verticalPadding, 100);
      const availableWidth = Math.max(windowWidth - horizontalPadding, 100);

      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      setDimensions({ 
          width: Math.floor(bookWidth), 
          height: Math.floor(bookHeight) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    if (zoomLevel <= 1) {
      setPan({ x: 0, y: 0 });
    }
  }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip()?.flipNext();
  const prevFlip = () => bookRef.current?.pageFlip()?.flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip()?.flip(index);

  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    try {
        if (!document.fullscreenElement) {
            containerRef.current?.requestFullscreen().catch(() => {});
        } else {
            document.exitFullscreen().catch(() => {});
        }
    } catch (err) { console.error('Fullscreen toggle failed', err); }
  };

  const handleZoomIn = () => setZoomLevel(prev => Math.min(prev + 0.2, 4.0));
  const handleZoomOut = () => setZoomLevel(prev => Math.max(prev - 0.2, 0.5));

  const handleDownload = () => {
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    if (activeTool !== 'cursor') return;

    setIsGesturing(true);
    gesture.current.startX = clientX;
    gesture.current.startY = clientY;
    gesture.current.mode = mode;

    if (mode === 'pan') {
      gesture.current.startPanX = pan.x;
      gesture.current.startPanY = pan.y;
    }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'cursor') return;

    if (gesture.current.mode === 'pan') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      setPan({ 
        x: gesture.current.startPanX + dx, 
        y: gesture.current.startPanY + dy 
      });
    }
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'cursor') return;

    setIsGesturing(false);

    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      if (Math.abs(dx) > 30) {
        if (dx > 0) prevFlip(); 
        else nextFlip(); 
      }
    }

    if (gesture.current.mode === 'pinch') {
       if (zoomLevel < 1.1) setZoomLevel(1);
    }

    gesture.current.mode = 'none';
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (activeTool !== 'cursor') return;

    if (e.touches.length === 2) {
      setIsGesturing(true);
      gesture.current.mode = 'pinch';
      gesture.current.startDist = getDistance(e.touches);
      gesture.current.startZoom = zoomLevel;
    } else if (e.touches.length === 1) {
      const mode = zoomLevel > 1 ? 'pan' : 'swipe';
      startGesture(e.touches[0].clientX, e.touches[0].clientY, mode);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (activeTool !== 'cursor') return;

    if (gesture.current.mode === 'pinch' && e.touches.length === 2) {
      const dist = getDistance(e.touches);
      const scale = (dist / Math.max(gesture.current.startDist, 1)) * gesture.current.startZoom;
      setZoomLevel(Math.min(Math.max(scale, 0.5), 4));
    } else if (e.touches.length === 1) {
      moveGesture(e.touches[0].clientX, e.touches[0].clientY);
    }
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (activeTool !== 'cursor') return;
    const touch = e.changedTouches[0];
    if (touch) endGesture(touch.clientX, touch.clientY);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0 || activeTool !== 'cursor') return;
    const mode = zoomLevel > 1 ? 'pan' : 'swipe';
    startGesture(e.clientX, e.clientY, mode);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (activeTool !== 'cursor') return;
    if (gesture.current.mode !== 'none') {
       moveGesture(e.clientX, e.clientY);
    }
  };

  const handleMouseUp = (e: React.MouseEvent) => {
    if (activeTool !== 'cursor') return;
    if (gesture.current.mode !== 'none') {
       endGesture(e.clientX, e.clientY);
    }
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden"
    >
      <div className="flex-grow flex flex-col h-full relative">
        <div className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-30 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}>
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <span className="text-skin-muted text-xs">صفحه {currentPage + 1} از {catalog.pages.length}</span>
                </div>

                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border">
                        <div className="flex items-center border-l border-gray-300 ml-1 pl-1">
                            <button onClick={() => setActiveTool('cursor')} className={`p-2 rounded transition-colors ${activeTool === 'cursor' ? 'bg-skin-card text-skin-primary' : 'hover:bg-skin-control-hover'}`} title="انتخابگر"><MousePointer2 size={18} /></button>
                            <button onClick={() => setActiveTool('highlight')} className={`p-2 rounded transition-colors ${activeTool === 'highlight' ? 'bg-yellow-200 text-yellow-900' : 'hover:bg-skin-control-hover'}`} title="هایلایتر"><Highlighter size={18} /></button>
                            <button onClick={() => setActiveTool('note')} className={`p-2 rounded transition-colors ${activeTool === 'note' ? 'bg-yellow-200 text-yellow-900' : 'hover:bg-skin-control-hover'}`} title="یادداشت"><StickyNote size={18} /></button>
                        </div>
                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 hover:bg-skin-control-hover rounded transition-colors">{forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}</button>
                        <button onClick={handleZoomOut} className="p-2 hover:bg-skin-control-hover rounded"><ZoomOut size={18} /></button>
                        <span className="text-xs w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 hover:bg-skin-control-hover rounded"><ZoomIn size={18} /></button>
                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 hover:bg-skin-control-hover rounded">{isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}</button>
                        <button onClick={toggleFullscreen} className="p-2 hover:bg-skin-control-hover rounded"><Maximize size={18} /></button>
                        <button onClick={handleDownload} className="p-2 hover:bg-skin-control-hover rounded"><FileDown size={18} /></button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg hover:bg-red-500 hover:text-white transition-colors pointer-events-auto"><X size={20} /></button>
                </div>
            </div>
            <div className="flex justify-center -mb-3 pb-1"><button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary"><ChevronUp size={16} /></button></div>
        </div>

        <div 
            className={`flex-grow flex items-center justify-center relative w-full h-full overflow-hidden ${activeTool === 'cursor' ? 'cursor-grab active:cursor-grabbing' : ''} pb-20 pt-20`}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
        >
            <div 
                style={{ 
                    transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`,
                    transition: isGesturing ? 'none' : 'transform 0.2s ease-out'
                }}
                className="relative"
            >
                {/* @ts-ignore */}
                <HTMLFlipBook
                    key={`${dimensions.width}-${forceSinglePage}`} 
                    width={dimensions.width}
                    height={dimensions.height}
                    size="fixed"
                    showCover={false}
                    onFlip={onFlip}
                    onInit={onInit}
                    ref={bookRef}
                    usePortrait={forceSinglePage}
                    startPage={initialPage}
                    flippingTime={600}
                    useMouseEvents={false}
                    className="shadow-2xl"
                    style={{ margin: '0 auto' }}
                >
                    {catalog.pages.map((pageUrl, idx) => (
                        <Page number={idx + 1} key={idx}>
                             <div className="w-full h-full relative bg-white">
                                <img src={pageUrl} alt={`Page ${idx + 1}`} className="w-full h-full object-contain pointer-events-none" />
                                <AnnotationLayer 
                                    pageIndex={idx}
                                    activeTool={activeTool}
                                    annotations={annotations[idx] || []}
                                    onAdd={(ann) => handleAddAnnotation(idx, ann)}
                                    onUpdate={(id, content) => handleUpdateAnnotation(idx, id, content)}
                                    onDelete={(id) => handleDeleteAnnotation(idx, id)}
                                />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>

            <button onClick={prevFlip} className="hidden md:flex absolute left-6 z-20 p-3 bg-skin-primary text-white rounded-full shadow-xl hover:scale-110 transition-transform"><ChevronLeft size={24} /></button>
            <button onClick={nextFlip} className="hidden md:flex absolute right-6 z-20 p-3 bg-skin-primary text-white rounded-full shadow-xl hover:scale-110 transition-transform"><ChevronRight size={24} /></button>
        </div>

        <div className={`absolute bottom-0 left-0 right-0 z-30 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>
             <div className="flex justify-center -mt-3 pt-1"><button onClick={() => setShowBottomPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 text-skin-muted hover:text-skin-primary"><ChevronDown size={16} /></button></div>

             <div className="md:hidden bg-skin-card border-t p-3 flex justify-between items-center shadow-lg">
                <div className="flex gap-2">
                    <button onClick={() => setActiveTool('cursor')} className={`p-2 rounded ${activeTool === 'cursor' ? 'bg-skin-primary text-white' : 'text-skin-muted'}`}><MousePointer2 size={18} /></button>
                    <button onClick={() => setActiveTool('highlight')} className={`p-2 rounded ${activeTool === 'highlight' ? 'bg-yellow-100 text-yellow-800' : 'text-skin-muted'}`}><Highlighter size={18} /></button>
                    <button onClick={() => setActiveTool('note')} className={`p-2 rounded ${activeTool === 'note' ? 'bg-yellow-100 text-yellow-800' : 'text-skin-muted'}`}><StickyNote size={18} /></button>
                </div>
                <div className="flex gap-3">
                    <button onClick={handleZoomOut}><ZoomOut size={20} /></button>
                    <button onClick={handleZoomIn}><ZoomIn size={20} /></button>
                    <button onClick={handleDownload}><FileDown size={20} /></button>
                </div>
             </div>

             <div className="h-20 bg-skin-card/90 backdrop-blur-md border-t flex items-center px-4 gap-2 overflow-x-auto scrollbar-hide">
                 {catalog.pages.map((page, idx) => (
                     <button key={idx} onClick={() => goToPage(idx)} className={`shrink-0 h-16 w-12 rounded border-2 transition-all ${currentPage === idx ? 'border-skin-primary scale-110 shadow-md' : 'border-transparent opacity-60'}`}>
                         <img src={page} className="w-full h-full object-cover rounded-sm" loading="lazy" />
                     </button>
                 ))}
             </div>
        </div>

        {!showTopPanel && <button onClick={() => setShowTopPanel(true)} className="fixed top-4 left-1/2 -translate-x-1/2 z-40 bg-skin-card p-2 rounded-full shadow-lg text-skin-muted hover:text-skin-primary transition-all"><ChevronDown size={20} /></button>}
        {!showBottomPanel && <button onClick={() => setShowBottomPanel(true)} className="fixed bottom-4 left-1/2 -translate-x-1/2 z-40 bg-skin-card p-2 rounded-full shadow-lg text-skin-muted hover:text-skin-primary transition-all"><ChevronUp size={20} /></button>}
      </div>
    </div>
  );
};

