import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Send, X, Bot, Loader2, Sparkles, User, Package, ChevronLeft, ArrowRight, Building2, Activity, Headphones, CheckCircle, AlertCircle, Phone, FileText } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const API_URL = './chat.php';
const SUBMIT_API_URL = './submit_form.php';

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

type ChatView = 'menu' | 'products' | 'chat' | 'adr_select' | 'adr_form' | 'consult_form' | 'success';

const PRODUCTS = [
    { id: 'capsulizer', name: 'کپسولایزر' },
    { id: 'coldanese', name: 'کلدانیز پلاس' },
    { id: 'folinozit', name: 'فولینوزیت' },
    { id: 'meglozek', name: 'مگلوزک' },
    { id: 'tiotoriva', name: 'تیوتوریوا' },
];

const COMPANY_INFO = { id: 'nafas', name: 'شرکت نفس زیست فارمد' };

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [view, setView] = useState<ChatView>('menu');
  const [selectedProduct, setSelectedProduct] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
      name: '',
      phone: '',
      description: '',
      productName: ''
  });

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const validatePhone = (phone: string) => /^09\d{9}$/.test(phone);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, view, isOpen]);

  const resetChat = () => {
      setSelectedProduct(null);
      setMessages([]);
      setInput('');
      setFormData({ name: '', phone: '', description: '', productName: '' });
      setView('menu');
      setValidationError(null);
  };

  const handleFormSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setValidationError(null);

      // Validations
      if (formData.name.trim().length < 3) {
          setValidationError('نام و نام خانوادگی باید حداقل ۳ حرف باشد');
          return;
      }
      if (!validatePhone(formData.phone)) {
          setValidationError('لطفا یک شماره موبایل معتبر (مثلا 09123456789) وارد کنید');
          return;
      }
      if (formData.description.trim().length < 10) {
          setValidationError('شرح درخواست باید حداقل ۱۰ حرف باشد');
          return;
      }

      setIsLoading(true);
      try {
        const body = new URLSearchParams();
        const formType = view === 'adr_form' ? 'گزارش عوارض دارویی' : 'درخواست مشاوره';
        body.append('type', formType);
        body.append('name', formData.name.trim());
        body.append('phone', formData.phone.trim());
        body.append('description', formData.description.trim());
        if (view === 'adr_form') body.append('product', formData.productName);

        const response = await fetch(SUBMIT_API_URL, {
            method: 'POST',
            headers: { "Content-Type": "application/x-www-form-urlencoded" },
            body: body,
        });

        if (!response.ok) throw new Error('Server error');
        setView('success');
      } catch (error) {
        setValidationError('خطا در ثبت اطلاعات. لطفا دوباره تلاش کنید.');
      } finally {
        setIsLoading(false);
      }
  };

  const handleChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading || !selectedProduct) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input.trim() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const body = new URLSearchParams();
      body.append('message', userMsg.content);
      body.append('product', selectedProduct);

      const response = await fetch(API_URL, {
        method: 'POST',
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: body,
      });

      const text = await response.text();
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'assistant', 
        content: text || 'پاسخی دریافت نشد.' 
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: 'خطای شبکه!' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      <motion.button
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-40 p-4 rounded-full shadow-2xl transition-all duration-300 group ${isOpen ? 'bg-skin-card text-skin-text rotate-90' : 'bg-skin-primary text-white'}`}
      >
        {isOpen ? <X size={28} /> : <MessageCircle size={28} />}
      </motion.button>

      <AnimatePresence>
        {isOpen && (
          <motion.div 
            initial={{ opacity: 0, scale: 0.9, y: 50, originX: 1, originY: 1 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 50 }}
            className="fixed bottom-24 right-4 sm:right-6 w-[calc(100%-2rem)] sm:w-96 glass rounded-3xl shadow-2xl flex flex-col overflow-hidden z-40"
            style={{ height: 'min(600px, 80vh)' }}
          >
            {/* Header */}
            <div className="bg-skin-primary text-white p-4 flex items-center gap-3 relative shrink-0">
                {view !== 'menu' && (
                    <button onClick={() => view === 'success' ? resetChat() : view === 'adr_form' ? setView('adr_select') : setView('menu')} className="relative z-10 p-1.5 rounded-full hover:bg-white/20 transition-colors">
                        <ArrowRight size={20} />
                    </button>
                )}
                <div className="bg-white/20 p-2 rounded-full backdrop-blur-sm">
                    {view === 'consult_form' ? <Headphones size={22} /> : <Bot size={22} />}
                </div>
                <div>
                    <h3 className="font-bold text-md leading-tight">{view === 'menu' ? 'پشتیبانی نفس فارمد' : 'دستیار هوشمند'}</h3>
                    <p className="text-[10px] opacity-80 flex items-center gap-1">
                        <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span> آنلاین
                    </p>
                </div>
            </div>

            {/* View Container */}
            <div className="flex-grow overflow-y-auto p-4 flex flex-col bg-skin-base/30">
                {view === 'menu' && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-3">
                        <button onClick={() => { setSelectedProduct(COMPANY_INFO.id); setView('chat'); }} className="w-full flex items-center gap-3 p-4 bg-skin-card hover:bg-skin-control-bg border border-skin-border rounded-xl transition-all shadow-sm">
                            <Building2 className="text-blue-500" />
                            <div className="text-right flex-grow"><span className="block font-bold text-sm">سوال درباره شرکت</span></div>
                            <ChevronLeft size={16} />
                        </button>
                        <button onClick={() => setView('products')} className="w-full flex items-center gap-3 p-4 bg-skin-card hover:bg-skin-control-bg border border-skin-border rounded-xl transition-all shadow-sm">
                            <Package className="text-green-500" />
                            <div className="text-right flex-grow"><span className="block font-bold text-sm">سوال درباره محصولات</span></div>
                            <ChevronLeft size={16} />
                        </button>
                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={() => setView('adr_select')} className="p-4 bg-skin-card hover:bg-red-50 border border-skin-border rounded-xl transition-all text-center group">
                                <Activity className="mx-auto mb-2 text-red-500 group-hover:scale-110 transition-transform" />
                                <span className="text-xs font-bold">گزارش عارضه</span>
                            </button>
                            <button onClick={() => setView('consult_form')} className="p-4 bg-skin-card hover:bg-purple-50 border border-skin-border rounded-xl transition-all text-center group">
                                <Headphones className="mx-auto mb-2 text-purple-500 group-hover:scale-110 transition-transform" />
                                <span className="text-xs font-bold">درخواست مشاوره</span>
                            </button>
                        </div>
                    </motion.div>
                )}

                {(view === 'adr_form' || view === 'consult_form') && (
                    <motion.form initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} onSubmit={handleFormSubmit} className="space-y-4">
                        {validationError && (
                            <div className="bg-red-50 text-red-600 text-[10px] p-2 rounded-lg border border-red-100 flex items-center gap-2">
                                <AlertCircle size={14} /> {validationError}
                            </div>
                        )}
                        <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="نام و نام خانوادگی" className="w-full p-3 bg-skin-card border border-skin-border rounded-xl text-sm focus:border-skin-primary outline-none" />
                        <input required type="tel" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} placeholder="شماره موبایل (09...)" className="w-full p-3 bg-skin-card border border-skin-border rounded-xl text-sm focus:border-skin-primary outline-none dir-ltr" />
                        <textarea required rows={4} value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} placeholder="شرح درخواست شما..." className="w-full p-3 bg-skin-card border border-skin-border rounded-xl text-sm focus:border-skin-primary outline-none resize-none" />
                        <button type="submit" disabled={isLoading} className="w-full py-3 bg-skin-primary text-white rounded-xl font-bold shadow-lg flex items-center justify-center gap-2">
                            {isLoading ? <Loader2 size={20} className="animate-spin" /> : <CheckCircle size={20} />} ثبت اطلاعات
                        </button>
                    </motion.form>
                )}

                {view === 'chat' && (
                    <div className="flex-grow flex flex-col overflow-hidden">
                        <div className="flex-grow overflow-y-auto space-y-4 pb-4">
                            {messages.map(msg => (
                                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                                    <div className={`max-w-[85%] p-3 rounded-2xl text-xs leading-relaxed ${msg.role === 'user' ? 'bg-skin-primary text-white' : 'bg-skin-card border border-skin-border text-skin-text'}`}>
                                        {msg.content}
                                    </div>
                                </div>
                            ))}
                            <div ref={messagesEndRef} />
                        </div>
                        <form onSubmit={handleChatSubmit} className="pt-3 border-t border-skin-border flex gap-2">
                            <input ref={inputRef} value={input} onChange={e => setInput(e.target.value)} placeholder="سوال شما..." className="flex-grow bg-skin-control-bg p-2.5 rounded-full text-xs outline-none focus:ring-1 focus:ring-skin-primary" />
                            <button type="submit" className="bg-skin-primary text-white p-2.5 rounded-full"><Send size={16} /></button>
                        </form>
                    </div>
                )}

                {view === 'success' && (
                    <motion.div initial={{ scale: 0.8 }} animate={{ scale: 1 }} className="flex-grow flex flex-col items-center justify-center text-center">
                        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4"><CheckCircle size={40} /></div>
                        <h4 className="font-bold mb-2">ثبت موفقیت‌آمیز!</h4>
                        <p className="text-xs text-skin-muted mb-6">درخواست شما دریافت شد و کارشناسان ما به زودی با شما تماس می‌گیرند.</p>
                        <button onClick={resetChat} className="px-6 py-2 bg-skin-control-bg rounded-lg text-xs font-bold">متوجه شدم</button>
                    </motion.div>
                )}

                {(view === 'products' || view === 'adr_select') && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-2">
                        {PRODUCTS.map(p => (
                            <button key={p.id} onClick={() => { if(view === 'products') handleProductSelect(p.id); else { setFormData({...formData, productName: p.name}); setView('adr_form'); } }} className="w-full p-3 bg-skin-card border border-skin-border rounded-xl text-right text-xs font-bold hover:bg-skin-control-bg transition-colors flex justify-between">
                                {p.name} <ChevronLeft size={14} />
                            </button>
                        ))}
                    </motion.div>
                )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default ChatBot;

import React, { useState, useRef, useEffect, useCallback } from 'react';
