interface Annotation {
  id: string;
  type: 'highlight' | 'note';
  x: number;
  y: number;
  width?: number;
  height?: number;
  content?: string;
}

const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// --- Sub-component to manage Note focus state locally ---
const StickyNoteItem: React.FC<{ 
    ann: Annotation; 
    active: boolean; 
    onActivate: () => void; 
    onUpdate: (content: string) => void;
    onDelete: () => void;
    onClose: () => void;
}> = ({ ann, active, onActivate, onUpdate, onDelete, onClose }) => {
    const [localText, setLocalText] = useState(ann.content || '');

    useEffect(() => {
        setLocalText(ann.content || '');
    }, [ann.content]);

    return (
        <div 
            className="absolute pointer-events-auto"
            style={{ left: `${ann.x}%`, top: `${ann.y}%` }}
            onClick={(e) => { e.stopPropagation(); onActivate(); }}
        >
            <div className={`p-1.5 rounded-full shadow-lg transition-transform hover:scale-110 ${active ? 'bg-yellow-400 text-yellow-900 ring-2 ring-yellow-600' : 'bg-yellow-200 text-yellow-700'}`}>
                <MessageSquare size={18} fill={active ? "currentColor" : "none"} />
            </div>

            <AnimatePresence>
                {active && (
                    <motion.div 
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: 10 }}
                        className="absolute top-10 left-1/2 -translate-x-1/2 w-56 bg-yellow-50 border border-yellow-200 rounded-xl shadow-2xl p-3 z-50"
                        onClick={e => e.stopPropagation()}
                    >
                        <textarea 
                            className="w-full bg-transparent border-b border-yellow-200 resize-none outline-none text-xs text-gray-800 min-h-[70px] mb-2"
                            placeholder="یادداشت..."
                            value={localText}
                            onChange={(e) => setLocalText(e.target.value)}
                            onBlur={() => onUpdate(localText)}
                            autoFocus
                        />
                        <div className="flex justify-between items-center">
                            <button onClick={onDelete} className="text-red-500 hover:bg-red-50 p-1.5 rounded-lg"><Trash2 size={14} /></button>
                            <button onClick={() => { onUpdate(localText); onClose(); }} className="bg-yellow-500 text-white px-3 py-1 rounded-lg text-[10px] font-bold">تایید</button>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

const AnnotationLayer: React.FC<{
    activeTool: 'cursor' | 'highlight' | 'note';
    annotations: Annotation[];
    onAdd: (ann: Annotation) => void;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
}> = ({ activeTool, annotations, onAdd, onUpdate, onDelete }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);
    const [startPoint, setStartPoint] = useState({ x: 0, y: 0 });
    const [currentPoint, setCurrentPoint] = useState({ x: 0, y: 0 });
    const [activeNoteId, setActiveNoteId] = useState<string | null>(null);

    const getCoords = (e: any) => {
        const rect = containerRef.current!.getBoundingClientRect();
        const ex = e.touches ? e.touches[0].clientX : e.clientX;
        const ey = e.touches ? e.touches[0].clientY : e.clientY;
        return { x: ((ex - rect.left) / rect.width) * 100, y: ((ey - rect.top) / rect.height) * 100 };
    };

    return (
        <div 
            ref={containerRef}
            className={`absolute inset-0 z-20 ${activeTool !== 'cursor' ? 'cursor-crosshair pointer-events-auto' : 'pointer-events-none'}`}
            onMouseDown={e => {
                if(activeTool === 'highlight') { setIsDrawing(true); setStartPoint(getCoords(e)); setCurrentPoint(getCoords(e)); }
            }}
            onMouseMove={e => { if(isDrawing) setCurrentPoint(getCoords(e)); }}
            onMouseUp={() => {
                if(isDrawing) {
                    setIsDrawing(false);
                    const x = Math.min(startPoint.x, currentPoint.x), y = Math.min(startPoint.y, currentPoint.y);
                    const w = Math.abs(currentPoint.x - startPoint.x), h = Math.abs(currentPoint.y - startPoint.y);
                    if(w > 1 && h > 1) onAdd({ id: Date.now().toString(), type: 'highlight', x, y, width: w, height: h });
                }
            }}
            onClick={e => {
                if(activeTool === 'note') {
                    const c = getCoords(e);
                    const id = Date.now().toString();
                    onAdd({ id, type: 'note', x: c.x, y: c.y, content: '' });
                    setActiveNoteId(id);
                }
            }}
        >
            {annotations.map(ann => (
                ann.type === 'highlight' ? (
                    <div key={ann.id} className="absolute bg-yellow-300/30 border border-yellow-400/20 group pointer-events-auto" style={{ left: `${ann.x}%`, top: `${ann.y}%`, width: `${ann.width}%`, height: `${ann.height}%` }}>
                        <button onClick={(e) => { e.stopPropagation(); onDelete(ann.id); }} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"><X size={10} /></button>
                    </div>
                ) : (
                    <StickyNoteItem 
                        key={ann.id} 
                        ann={ann} 
                        active={activeNoteId === ann.id}
                        onActivate={() => setActiveNoteId(ann.id)}
                        onUpdate={(c) => onUpdate(ann.id, c)}
                        onDelete={() => onDelete(ann.id)}
                        onClose={() => setActiveNoteId(null)}
                    />
                )
            ))}
            {isDrawing && <div className="absolute bg-yellow-300/20 border border-dashed border-yellow-400 pointer-events-none" style={{ left: `${Math.min(startPoint.x, currentPoint.x)}%`, top: `${Math.min(startPoint.y, currentPoint.y)}%`, width: `${Math.abs(currentPoint.x - startPoint.x)}%`, height: `${Math.abs(currentPoint.y - startPoint.y)}%` }} />}
        </div>
    );
};

const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => (
  <div className="bg-white shadow-inner h-full w-full" ref={ref}>
    <div className="h-full w-full relative overflow-hidden">
        {props.children}
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-[10px] font-bold bg-white/60 backdrop-blur-sm px-2 py-0.5 rounded-md pointer-events-none z-10">{props.number}</div>
    </div>
  </div>
));
Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [currentPage, setCurrentPage] = useState(initialPage);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });
  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [activeTool, setActiveTool] = useState<'cursor' | 'highlight' | 'note'>('cursor');
  const [annotations, setAnnotations] = useState<Record<number, Annotation[]>>({});
  const [showPanels, setShowPanels] = useState(true);

  useEffect(() => {
    const saved = localStorage.getItem(`nafas_ann_${catalog.id}`);
    if (saved) setAnnotations(JSON.parse(saved));
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
  }, [catalog.id]);

  useEffect(() => {
    localStorage.setItem(`nafas_ann_${catalog.id}`, JSON.stringify(annotations));
  }, [annotations, catalog.id]);

  useEffect(() => {
    const handleResize = () => {
      const w = window.innerWidth, h = window.innerHeight;
      const vPad = w < 768 ? 160 : 120, hPad = w < 768 ? 20 : 100;
      let bh = h - vPad, bw = bh / 1.414;
      if (bw > w - hPad) { bw = w - hPad; bh = bw * 1.414; }
      setDimensions({ width: Math.max(300, Math.floor(bw)), height: Math.max(400, Math.floor(bh)) });
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-xl touch-none overflow-hidden">
      <div className="flex-grow flex flex-col h-full relative">
        {/* Header */}
        <AnimatePresence>
            {showPanels && (
                <motion.div initial={{ y: -100 }} animate={{ y: 0 }} exit={{ y: -100 }} className="absolute top-0 left-0 right-0 glass z-30 p-4 flex justify-between items-center">
                    <div><h2 className="font-bold text-sm">{catalog.title}</h2><span className="text-[10px] text-skin-muted">صفحه {currentPage + 1} از {catalog.pages.length}</span></div>
                    <div className="flex gap-2">
                        <div className="hidden md:flex bg-skin-control-bg/50 rounded-lg p-1 border border-skin-border">
                            <button onClick={() => setActiveTool('cursor')} className={`p-1.5 rounded ${activeTool === 'cursor' ? 'bg-white text-skin-primary shadow-sm' : ''}`}><MousePointer2 size={16} /></button>
                            <button onClick={() => setActiveTool('highlight')} className={`p-1.5 rounded ${activeTool === 'highlight' ? 'bg-yellow-200 text-yellow-900 shadow-sm' : ''}`}><Highlighter size={16} /></button>
                            <button onClick={() => setActiveTool('note')} className={`p-1.5 rounded ${activeTool === 'note' ? 'bg-yellow-200 text-yellow-900 shadow-sm' : ''}`}><StickyNote size={16} /></button>
                            <div className="w-px h-4 bg-gray-300 mx-1 self-center"></div>
                            <button onClick={() => setZoomLevel(z => Math.max(0.5, z - 0.2))}><ZoomOut size={16} /></button>
                            <span className="text-[10px] w-10 text-center self-center">{Math.round(zoomLevel * 100)}%</span>
                            <button onClick={() => setZoomLevel(z => Math.min(4, z + 0.2))}><ZoomIn size={16} /></button>
                        </div>
                        <button onClick={onClose} className="p-2 bg-skin-control-bg rounded-full hover:bg-red-500 hover:text-white transition-colors"><X size={18} /></button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {/* Book Body */}
        <div 
            className="flex-grow flex items-center justify-center p-20"
            onClick={() => setShowPanels(!showPanels)}
        >
            <div style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`, transition: 'transform 0.2s ease-out' }}>
                <HTMLFlipBook 
                    width={dimensions.width} height={dimensions.height} size="fixed"
                    onFlip={e => { setCurrentPage(e.data); audioRef.current?.play().catch(()=>{}); }}
                    ref={bookRef} showCover={false} flippingTime={600} useMouseEvents={false}
                >
                    {catalog.pages.map((url, idx) => (
                        <Page number={idx + 1} key={idx}>
                            <img src={url} className="w-full h-full object-contain pointer-events-none" loading="lazy" />
                            <AnnotationLayer 
                                activeTool={activeTool} annotations={annotations[idx] || []}
                                onAdd={a => setAnnotations(p => ({...p, [idx]: [...(p[idx]||[]), a]}))}
                                onUpdate={(id, c) => setAnnotations(p => ({...p, [idx]: (p[idx]||[]).map(x => x.id === id ? {...x, content: c} : x)}))}
                                onDelete={id => setAnnotations(p => ({...p, [idx]: (p[idx]||[]).filter(x => x.id !== id)}))}
                            />
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>
        </div>

        {/* Bottom Panel */}
        <AnimatePresence>
            {showPanels && (
                <motion.div initial={{ y: 100 }} animate={{ y: 0 }} exit={{ y: 100 }} className="absolute bottom-0 left-0 right-0 glass z-30 p-3 flex flex-col gap-2">
                    <div className="md:hidden flex justify-center gap-4 mb-2">
                        <button onClick={() => setActiveTool('cursor')} className={`p-2 rounded ${activeTool === 'cursor' ? 'bg-skin-primary text-white' : ''}`}><MousePointer2 size={18} /></button>
                        <button onClick={() => setActiveTool('highlight')} className={`p-2 rounded ${activeTool === 'highlight' ? 'bg-yellow-100 text-yellow-900' : ''}`}><Highlighter size={18} /></button>
                        <button onClick={() => setActiveTool('note')} className={`p-2 rounded ${activeTool === 'note' ? 'bg-yellow-100 text-yellow-900' : ''}`}><StickyNote size={18} /></button>
                    </div>
                    <div className="flex items-center gap-2 overflow-x-auto scrollbar-hide py-1">
                        {catalog.pages.map((p, i) => (
                            <button key={i} onClick={e => { e.stopPropagation(); bookRef.current.pageFlip()?.flip(i); }} className={`shrink-0 w-10 h-14 rounded border-2 ${currentPage === i ? 'border-skin-primary' : 'border-transparent'}`}><img src={p} className="w-full h-full object-cover rounded-sm" /></button>
                        ))}
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
};

