                        )}
                        {currentPage > 0 && (
                            <div className="absolute -bottom-2 -right-2 w-16 h-16 z-10 cursor-pointer group transition-all duration-300 hover:scale-125" onClick={(e) => { e.stopPropagation(); prevFlip(); }}>
                                <div className="absolute bottom-0 right-0 w-full h-full bg-gradient-to-tl from-black/30 via-transparent to-transparent rounded-br-2xl transition-all group-hover:from-skin-primary/40" />
                                <div className="absolute bottom-0 right-0 w-0 h-0 border-b-[24px] border-r-[24px] border-b-white border-r-transparent shadow-lg -rotate-90 transition-all group-hover:border-b-[32px] group-hover:border-r-[32px]" />
                            </div>
                        )}
                    </>
                )}

                {/* @ts-ignore */}
                <HTMLFlipBook
                    key={`${dimensions.width}-${forceSinglePage}`} 
                    width={dimensions.width}
                    height={dimensions.height}
                    size="fixed"
                    minWidth={300}
                    maxWidth={3000}
                    minHeight={400}
                    maxHeight={4000}
                    maxShadowOpacity={0.5}
                    showCover={false}
                    mobileScrollSupport={false}
                    onFlip={onFlip}
                    onInit={onInit}
                    ref={bookRef}
                    className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`}
                    style={{ margin: '0 auto' }}
                    usePortrait={isMobile || forceSinglePage}
                    startPage={initialPage}
                    drawShadow={true}
                    flippingTime={800}
                    useMouseEvents={false}
                    swipeDistance={10000}
                >
                    {catalog.pages.map((pageUrl, index) => (
                        <Page 
                            number={index + 1} 
                            key={index}
                            activeTool={activeTool}
                            annotations={annotations[index] || []}
                            onAddAnnotation={(type, x, y) => addAnnotationToPage(index, type, x, y)}
                            onDeleteAnnotation={(id) => deleteAnnotation(index, id)}
                        >
                             <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                                <img 
                                    src={pageUrl} 
                                    alt={`Page ${index + 1}`} 
                                    className="w-full h-full object-contain select-none pointer-events-none bg-white"
                                    loading={index < 4 ? "eager" : "lazy"}
                                    onDragStart={(e) => e.preventDefault()}
                                />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>
        </div>

        {/* --- BOTTOM PANEL (Thumbnails + Mobile Toolbar) --- */}
        <div className={`absolute bottom-0 left-0 right-0 z-20 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>

             {/* Bottom Collapse Button */}
             <div className="flex justify-center -mt-3 pt-1 pointer-events-none">
                 <button onClick={() => setShowBottomPanel(false)} className="pointer-events-auto bg-skin-card border border-skin-border rounded-full p-1 shadow-sm text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg transition-colors relative z-30">
                    <ChevronDown size={16} />
                 </button>
             </div>

            {/* Mobile Toolbar (Above Thumbnails) */}
            <div 
                className={`md:hidden bg-skin-card border-t border-skin-border shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]`}
            >
                <div className="flex flex-col gap-2 px-4 py-2">
                    {/* Mobile Annotation Toolbar */}
                    <div className="flex justify-center items-center gap-2 py-1 border-b border-gray-100 pb-2">
                         <button 
                                onClick={() => setActiveTool(activeTool === 'none' ? 'none' : 'none')}
                                className={`p-2 rounded-md ${activeTool === 'none' ? 'bg-gray-200 text-skin-primary' : 'text-gray-500'}`}
                            >
                                <MousePointer2 size={16} />
                        </button>
                        <button 
                                onClick={() => setActiveTool(activeTool === 'highlight' ? 'none' : 'highlight')}
                                className={`p-2 rounded-md ${activeTool === 'highlight' ? 'bg-yellow-100 text-yellow-800' : 'text-gray-500'}`}
                            >
                                <Highlighter size={16} />
                        </button>
                        <button 
                                onClick={() => setActiveTool(activeTool === 'note' ? 'none' : 'note')}
                                className={`p-2 rounded-md ${activeTool === 'note' ? 'bg-yellow-100 text-yellow-800' : 'text-gray-500'}`}
                            >
                                <StickyNote size={16} />
                        </button>
                         <button 
                                onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                                className={`p-2 rounded-md ${activeTool === 'eraser' ? 'bg-red-100 text-red-800' : 'text-gray-500'}`}
                            >
                                <Trash2 size={16} />
                        </button>
                    </div>

                    <div className="flex justify-center items-center gap-4 py-1 border-b border-gray-100 pb-2 mb-1">
                        <button onClick={handleZoomOut} className="p-1.5 bg-gray-100 rounded text-gray-600"><ZoomOut size={16} /></button>
                        <span className="text-xs font-mono text-gray-500 w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-1.5 bg-gray-100 rounded text-gray-600"><ZoomIn size={16} /></button>
                    </div>

                    <div className="flex justify-between items-center">
                        <button onClick={nextFlip} className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors">
                            <ChevronRight size={24} />
                        </button>

                        <div className="flex gap-4 text-skin-muted">
                            <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">
                                {isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                            </button>
                            <button onClick={handleDownload} className="p-2"><FileDown size={20} /></button>
                        </div>

                        <button onClick={prevFlip} className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors">
                            <ChevronLeft size={24} />
                        </button>
                    </div>
                </div>
            </div>

            {/* Thumbnail Strip */}
            <div className={`h-20 bg-skin-card/90 backdrop-blur-md border-t border-skin-border flex items-center px-4 gap-2 overflow-x-auto`}>
                 {catalog.pages.map((page, idx) => (
                     <button 
                        key={idx} 
                        onClick={() => goToPage(idx)}
                        className={`shrink-0 h-16 w-12 rounded border-2 overflow-hidden transition-all ${currentPage === idx ? 'border-skin-primary scale-110 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}
                     >
                         <img src={page} className="w-full h-full object-cover" loading="lazy" />
                     </button>
                 ))}
            </div>
        </div>

        {/* Floating Bottom Expand Button */}
        <button 
            onClick={() => setShowBottomPanel(true)}
            className={`absolute bottom-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all duration-300 ${!showBottomPanel ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'}`}
        >
            <ChevronUp size={20} />
        </button>

      </div>
    </div>
  );
};

export default BookViewer;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Send, X, Bot, Loader2, Sparkles, User, Package, ChevronLeft, ArrowRight, Building2, Activity, Headphones, CheckCircle, AlertTriangle, Phone, FileText } from 'lucide-react';

const API_URL = './chat.php';
const SUBMIT_API_URL = './submit_form.php';

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

type ChatView = 'menu' | 'products' | 'chat' | 'adr_select' | 'adr_form' | 'consult_form' | 'success';

const PRODUCTS = [
    { id: 'capsulizer', name: 'کپسولایزر' },
    { id: 'coldanese', name: 'کلدانیز پلاس' },
    { id: 'folinozit', name: 'فولینوزیت' },
    { id: 'meglozek', name: 'مگلوزک' },
    { id: 'tiotoriva', name: 'تیوتوریوا' },
];

const COMPANY_INFO = { id: 'nafas', name: 'شرکت نفس زیست فارمد' };

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [view, setView] = useState<ChatView>('menu');
  const [selectedProduct, setSelectedProduct] = useState<string | null>(null);

  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Form States
  const [formData, setFormData] = useState({
      name: '',
      phone: '',
      description: '',
      productName: ''
  });

  const [formError, setFormError] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen, view]);

  useEffect(() => {
    if (isOpen && view === 'chat' && inputRef.current) {
        setTimeout(() => inputRef.current?.focus(), 300);
    }
  }, [isOpen, view]);

  const resetChat = () => {
      setSelectedProduct(null);
      setMessages([]);
      setInput('');
      setFormData({ name: '', phone: '', description: '', productName: '' });
      setFormError(null);
      setView('menu');
  };

  const handleOptionSelect = (option: 'company' | 'products' | 'adr' | 'consult') => {
      setFormError(null);
      if (option === 'company') {
          setSelectedProduct(COMPANY_INFO.id);
          setMessages([{
              id: 'welcome',
              role: 'assistant',
              content: `سلام! من آماده پاسخگویی به سوالات شما درباره **${COMPANY_INFO.name}** هستم.`
          }]);
          setView('chat');
      } else if (option === 'products') {
          setView('products');
      } else if (option === 'adr') {
          setView('adr_select');
      } else if (option === 'consult') {
          setView('consult_form');
      }
  };

  const handleProductSelect = (productId: string) => {
    setSelectedProduct(productId);
    const productName = PRODUCTS.find(p => p.id === productId)?.name;
    setMessages([
        {
            id: 'welcome',
            role: 'assistant',
            content: `سلام! من دستیار هوشمند محصول **${productName}** هستم. هر سوالی در مورد این دارو دارید بپرسید.`
        }
    ]);
    setView('chat');
  };

  const handleAdrProductSelect = (productId: string) => {
      const product = PRODUCTS.find(p => p.id === productId);
      setFormData(prev => ({ ...prev, productName: product?.name || '' }));
      setView('adr_form');
  };

  const handleChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading || !selectedProduct) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const body = new URLSearchParams();
      body.append('message', userMsg.content);
      body.append('product', selectedProduct);

      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
            "Content-Type": "application/x-www-form-urlencoded"
        },
        body: body,
      });

      if (!response.ok) throw new Error('Network response was not ok');

      const text = await response.text();

      const aiMsg: Message = { 
        id: (Date.now() + 1).toString(), 
        role: 'assistant', 
        content: text || 'متاسفانه مشکلی در دریافت پاسخ پیش آمد.' 
      };

      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error('Chat Error:', error);
      const errorMsg: Message = { 
        id: (Date.now() + 1).toString(), 
        role: 'assistant', 
        content: 'خطا در ارتباط با سرور. لطفا اتصال اینترنت خود را بررسی کنید.' 
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const validateForm = () => {
      if (formData.name.trim().length < 3) {
          setFormError('نام و نام خانوادگی باید حداقل ۳ کاراکتر باشد.');
          return false;
      }

      // Iranian Mobile Regex: 09xx xxx xxxx
      const phoneRegex = /^09[0-9]{9}$/;
      if (!phoneRegex.test(formData.phone)) {
          setFormError('شماره موبایل نامعتبر است. (مثال: 09123456789)');
          return false;
      }

      if (formData.description.trim().length < 5) {
          setFormError('لطفا توضیحات کامل‌تری بنویسید.');
          return false;
      }

      setFormError(null);
      return true;
  };

  const handleFormSubmit = async (e: React.FormEvent) => {
      e.preventDefault();

      if (!validateForm()) return;

      setIsLoading(true);

      try {
        const body = new URLSearchParams();
        const formType = view === 'adr_form' ? 'گزارش عوارض دارویی' : 'درخواست مشاوره';
        body.append('type', formType);
        body.append('name', formData.name.trim());
        body.append('phone', formData.phone.trim());
        body.append('description', formData.description.trim());

        if (view === 'adr_form') {
            body.append('product', formData.productName);
        }

        const response = await fetch(SUBMIT_API_URL, {
            method: 'POST',
            headers: {
                "Content-Type": "application/x-www-form-urlencoded"
            },
            body: body,
        });

        if (!response.ok) {
            throw new Error('Server error');
        }

        const resJson = await response.json();
        if (resJson.status === 'error') {
            throw new Error(resJson.message);
        }

        setView('success');

      } catch (error: any) {
        console.error('Form Submit Error:', error);
        setFormError(error.message || 'متاسفانه در ثبت اطلاعات مشکلی پیش آمد. لطفا اتصال اینترنت خود را بررسی کرده و مجددا تلاش کنید.');
      } finally {
        setIsLoading(false);
      }
  };

  const getHeaderTitle = () => {
      if (view === 'menu') return 'دستیار هوشمند';
      if (view === 'products') return 'انتخاب محصول';
      if (view === 'adr_select') return 'انتخاب دارو';
      if (view === 'adr_form') return 'ثبت عوارض';
      if (view === 'consult_form') return 'درخواست مشاوره';
      if (view === 'success') return 'تکمیل عملیات';
      if (selectedProduct === COMPANY_INFO.id) return COMPANY_INFO.name;
      return PRODUCTS.find(p => p.id === selectedProduct)?.name || 'دستیار هوشمند';
  };

  const getSubHeader = () => {
      if (view === 'chat') return 'متصل به پایگاه دانش';
      if (view === 'adr_form' || view === 'consult_form') return 'اطلاعات خود را وارد کنید';
      return 'آنلاین';
  };

  return (
    <>
      {/* Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-40 p-4 rounded-full shadow-2xl transition-all duration-300 hover:scale-110 active:scale-95 group ${isOpen ? 'bg-skin-card text-skin-text rotate-90' : 'bg-skin-primary text-white'}`}
        style={{ boxShadow: '0 10px 30px -10px rgba(182, 22, 21, 0.5)' }}
      >
        {isOpen ? <X size={28} /> : (
            <>
                <MessageCircle size={28} className="absolute inset-0 m-auto animate-ping opacity-20" />
                <MessageCircle size={28} />
                <span className="absolute -top-1 -right-1 flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
                </span>
            </>
        )}
      </button>

      {/* Chat Window */}
      <div 
        className={`fixed bottom-24 right-4 sm:right-6 w-[calc(100%-2rem)] sm:w-96 bg-skin-card rounded-3xl shadow-2xl border border-skin-border flex flex-col overflow-hidden transition-all duration-300 origin-bottom-right z-40 ${isOpen ? 'opacity-100 scale-100 translate-y-0' : 'opacity-0 scale-95 translate-y-10 pointer-events-none'}`}
        style={{ height: 'min(600px, 80vh)' }}
      >
        {/* Header */}
        <div className="bg-skin-primary text-white p-4 flex items-center gap-3 shadow-md relative overflow-hidden shrink-0">
            <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-transparent"></div>

            {view !== 'menu' && (
                <button 
                    onClick={() => view === 'success' ? resetChat() : view === 'adr_form' ? setView('adr_select') : setView('menu')} 
                    className="relative z-10 p-1.5 rounded-full hover:bg-white/20 transition-colors -mr-2"
                >
                    <ArrowRight size={20} />
                </button>
            )}

            <div className="bg-white/20 p-2 rounded-full backdrop-blur-sm relative z-10">
                {view === 'consult_form' ? <Headphones size={24} /> : 
                 view === 'adr_form' || view === 'adr_select' ? <Activity size={24} /> :
                 <Bot size={24} />}
            </div>

            <div className="relative z-10">
                <h3 className="font-bold text-lg leading-tight truncate max-w-[180px]">
                    {getHeaderTitle()}
                </h3>
                <p className="text-[10px] text-white/80 flex items-center gap-1">
                    <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
                    {getSubHeader()}
