import React, { createContext, useContext, useState, useEffect } from 'react';
import { Catalog, Video } from '../types';
import { CATALOGS as FALLBACK_CATALOGS, VIDEOS as FALLBACK_VIDEOS } from '../initialData';

interface CatalogContextType {
  catalogs: Catalog[];
  videos: Video[];
  addCatalog: (catalog: Catalog) => void;
  updateCatalog: (id: string, updatedCatalog: Catalog) => void;
  deleteCatalog: (id: string) => void;
  addVideo: (video: Video) => void;
  updateVideo: (id: string, updatedVideo: Video) => void;
  deleteVideo: (id: string) => void;
  resetToDefault: () => void;
  importData: (catalogs: Catalog[], videos: Video[]) => void;
  isLoading: boolean;
}

const CatalogContext = createContext<CatalogContextType | undefined>(undefined);

export const CatalogProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [catalogs, setCatalogs] = useState<Catalog[]>([]);
  const [videos, setVideos] = useState<Video[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Unified Data Loading Strategy
  useEffect(() => {
    const loadData = () => {
      try {
        // Priority 1: External Data File (window.NAFAS_DATA)
        // This allows dynamic updates without rebuilding the React app
        if (typeof window !== 'undefined' && window.NAFAS_DATA) {
          console.log('📦 Loading data from External Source (data.js)');
          setCatalogs(window.NAFAS_DATA.catalogs || []);
          setVideos(window.NAFAS_DATA.videos || []);
          setIsLoading(false);
          return;
        }

        // Priority 2: Local Storage (Admin Changes)
        const savedCatalogs = localStorage.getItem('nafas_catalogs');
        const savedVideos = localStorage.getItem('nafas_videos');

        if (savedCatalogs && savedVideos) {
           console.log('💾 Loading data from Local Storage');
           setCatalogs(JSON.parse(savedCatalogs));
           setVideos(JSON.parse(savedVideos));
           setIsLoading(false);
           return;
        }

        // Priority 3: Fallback / Initial Data
        console.log('⚠️ Loading Fallback Data');
        setCatalogs(FALLBACK_CATALOGS);
        setVideos(FALLBACK_VIDEOS);
      } catch (err) {
        console.error("Data loading failed:", err);
        // Emergency fallback
        setCatalogs(FALLBACK_CATALOGS);
        setVideos(FALLBACK_VIDEOS);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, []);

  // Sync with LocalStorage for Admin persistence
  useEffect(() => {
    if (!isLoading) {
      localStorage.setItem('nafas_catalogs', JSON.stringify(catalogs));
      localStorage.setItem('nafas_videos', JSON.stringify(videos));
    }
  }, [catalogs, videos, isLoading]);

  // Catalog Actions
  const addCatalog = (catalog: Catalog) => setCatalogs(prev => [catalog, ...prev]);
  const updateCatalog = (id: string, updatedCatalog: Catalog) => setCatalogs(prev => prev.map(cat => cat.id === id ? updatedCatalog : cat));
  const deleteCatalog = (id: string) => setCatalogs(prev => prev.filter(cat => cat.id !== id));

  // Video Actions
  const addVideo = (video: Video) => setVideos(prev => [video, ...prev]);
  const updateVideo = (id: string, updatedVideo: Video) => setVideos(prev => prev.map(vid => vid.id === id ? updatedVideo : vid));
  const deleteVideo = (id: string) => setVideos(prev => prev.filter(vid => vid.id !== id));

  const resetToDefault = () => {
    if (window.confirm('آیا مطمئن هستید؟ تمام تغییرات شما حذف و به حالت اولیه باز می‌گردد.')) {
      setCatalogs(FALLBACK_CATALOGS);
      setVideos(FALLBACK_VIDEOS);
      localStorage.removeItem('nafas_catalogs');
      localStorage.removeItem('nafas_videos');
      window.location.reload();
    }
  };

  const importData = (newCatalogs: Catalog[], newVideos: Video[]) => {
    setCatalogs(newCatalogs);
    setVideos(newVideos);
  };

  return (
    <CatalogContext.Provider value={{ 
      catalogs, videos, 
      addCatalog, updateCatalog, deleteCatalog, 
      addVideo, updateVideo, deleteVideo,
      resetToDefault, importData, isLoading 
    }}>
      {children}
    </CatalogContext.Provider>
  );
};

export const useCatalogs = () => {
  const context = useContext(CatalogContext);
  if (context === undefined) {
    throw new Error('useCatalogs must be used within a CatalogProvider');
  }
  return context;
};

