  viewMode?: 'grid' | 'list';
  index?: number;
}

const CatalogCard: React.FC<CatalogCardProps> = ({ catalog, onClick, viewMode = 'grid', index = 0 }) => {
  const isList = viewMode === 'list';

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title}.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getLangBadge = (lang?: string) => {
      if (lang === 'en') return { img: 'https://patient.nafaspharmed.com/doc/en.png', code: 'EN' };
      return { img: 'https://patient.nafaspharmed.com/doc/ir.png', code: 'IR' };
  };

  const langData = getLangBadge(catalog.language);

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, delay: index * 0.05 }}
      whileHover={{ y: -5, transition: { duration: 0.2 } }}
      onClick={() => onClick(catalog)}
      className={`group glass rounded-2xl overflow-hidden cursor-pointer flex transition-shadow hover:shadow-xl hover:border-skin-primary/30 ${isList ? 'flex-row h-40 sm:h-48' : 'flex-col h-full'}`}
