import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import BookViewer from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import SkeletonCard from './components/SkeletonCard';
import ChatBot from './components/ChatBot';
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos, isLoading } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [initialPage, setInitialPage] = useState(0);

  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const [sortBy, setSortBy] = useState<SortOption>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('همه');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  const categories = ['همه', ...Array.from(new Set(catalogs.map(c => c.category).filter(Boolean)))];

  // Deep Linking
  useEffect(() => {
    if (catalogs.length > 0) {
      const params = new URLSearchParams(window.location.search);
      const catId = params.get('cat');
      const pageNum = params.get('page');

      if (catId) {
        const found = catalogs.find(c => c.id === catId);
        if (found) {
          let pIndex = 0;
          if (pageNum) {
            pIndex = Math.max(0, parseInt(pageNum) - 1);
            if (pIndex >= found.pages.length) pIndex = 0;
          }
          setInitialPage(pIndex);
          setSelectedCatalog(found);
        }
      }
    }
  }, [catalogs]);

  useEffect(() => {
    const handleResize = () => setDisplayMode(window.innerWidth < 768 ? 'list' : 'grid');
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    if (window.location.hash === '#admin') setViewMode('admin');
  }, []);

  const getProcessedCatalogs = () => {
    let result = catalogs.filter(cat => 
        (selectedCategory === 'همه' || cat.category === selectedCategory) &&
        (cat.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        cat.description.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    return result.sort((a, b) => {
        switch (sortBy) {
            case 'newest': return b.date.localeCompare(a.date);
            case 'oldest': return a.date.localeCompare(b.date);
            case 'az': return a.title.localeCompare(b.title, 'fa');
            case 'za': return b.title.localeCompare(a.title, 'fa');
            default: return 0;
        }
    });
  };

  const processedCatalogs = getProcessedCatalogs();
  const processedVideos = videos.filter(vid => 
     vid.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
     vid.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const getThemeIcon = () => {
    switch(theme) {
        case 'light': return <Sun size={20} />;
        case 'dark': return <Moon size={20} />;
        case 'reading': return <BookOpen size={20} />;
    }
  };

  const handleCloseViewer = () => {
    setSelectedCatalog(null);
    window.history.replaceState({}, '', window.location.pathname);
  };

  // --- Views ---
  if (viewMode === 'admin') {
    if (!isAuthenticated) return <AdminLogin onLogin={() => setIsAuthenticated(true)} onBack={() => setViewMode('home')} />;
    return <AdminPanel onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} />;
  }

  return (
    <div className="min-h-screen font-sans bg-skin-base text-skin-text transition-colors duration-500 relative flex flex-col bg-[url('https://nafaspharmed.com/wp-content/uploads/2023/12/bg-pattern.png')] bg-fixed bg-contain bg-no-repeat bg-center bg-blend-soft-light">

      {/* Navbar */}
      <motion.header 
        initial={{ y: -100 }}
        animate={{ y: 0 }}
        className="sticky top-0 z-40 w-full glass-heavy border-b border-skin-border transition-all duration-300 shadow-sm"
      >
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <motion.img 
              whileHover={{ scale: 1.05 }}
              src="https://nafaspharmed.com/wp-content/uploads/2025/11/logo_fa.png" 
              alt="نفس فارمد" 
              className="h-10 w-auto object-contain drop-shadow-sm" 
            />
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex items-center bg-skin-card border border-skin-border rounded-full px-4 py-2 w-80 focus-within:border-skin-primary focus-within:ring-1 focus-within:ring-skin-primary transition-all">
                <Search size={18} className="text-skin-muted ml-2" />
                <input type="text" placeholder="جستجو در کاتالوگ‌ها..." className="bg-transparent border-none outline-none text-sm text-skin-text w-full placeholder-skin-muted" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
             </div>
             <motion.button 
                whileTap={{ scale: 0.9 }}
                onClick={toggleTheme} 
                className="flex items-center justify-center w-10 h-10 rounded-full glass border border-skin-border text-skin-text hover:bg-skin-control-hover transition-colors shadow-sm"
             >
                {getThemeIcon()}
             </motion.button>
          </div>
        </div>
      </motion.header>

      <main className="container mx-auto px-4 py-8 md:py-12 flex-grow">

        {/* Hero Section */}
        <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-10 text-center md:text-right border-b border-skin-border pb-8 relative"
        >
            <div className="absolute top-0 left-0 w-32 h-32 bg-skin-primary/10 rounded-full blur-3xl -z-10 animate-pulse"></div>
            <h2 className="text-2xl md:text-4xl font-black text-skin-text mb-4 leading-tight">
                پورتال آموزشی <span className="text-transparent bg-clip-text bg-gradient-to-r from-skin-primary to-orange-600">نفس زیست فارمد</span>
            </h2>
            <p className="text-skin-muted text-sm md:text-lg max-w-2xl leading-relaxed">
                دسترسی سریع و آسان به جدیدترین کاتالوگ‌های دیجیتال، بروشورهای تخصصی و ویدئوهای آموزشی محصولات دارویی
            </p>
        </motion.div>

        {/* Mobile Search */}
        <div className="md:hidden mb-6">
             <div className="flex items-center glass border border-skin-border rounded-xl px-4 py-3 w-full focus-within:border-skin-primary transition-all shadow-sm">
                <Search size={20} className="text-skin-muted ml-3" />
                <input type="text" placeholder="جستجو..." className="bg-transparent border-none outline-none text-skin-text w-full placeholder-skin-muted" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
        </div>

        {/* Filters & Controls */}
        <div className="mb-8">
            <div className="flex flex-col gap-4 mb-6">
                <div className="flex flex-col sm:flex-row justify-between items-end gap-4">
                    <h3 className="text-xl md:text-2xl font-bold text-skin-text flex items-center gap-2">
                        <span className="p-2 bg-skin-primary/10 rounded-lg text-skin-primary"><BookOpen size={24} /></span>
                        کاتالوگ‌ها
                    </h3>
                    <div className="flex items-center gap-2 glass p-1.5 rounded-xl border border-skin-border shadow-sm">
                        <div className="relative flex items-center">
                            <ArrowDownUp size={16} className="absolute right-2 text-skin-muted pointer-events-none" />
                            <select value={sortBy} onChange={(e) => setSortBy(e.target.value as SortOption)} className="appearance-none bg-transparent hover:bg-skin-control-hover text-skin-text text-xs rounded-lg pr-7 pl-2 py-1.5 outline-none cursor-pointer transition-colors">
                                <option value="newest">جدیدترین</option><option value="oldest">قدیمی‌ترین</option><option value="az">حروف الفبا</option>
                            </select>
                        </div>
                        <div className="w-px h-5 bg-skin-border mx-1"></div>
                        <button onClick={() => setDisplayMode('grid')} className={`p-1.5 rounded-lg transition-all ${displayMode === 'grid' ? 'bg-skin-card shadow-sm text-skin-primary' : 'text-skin-muted hover:bg-skin-control-hover'}`}><LayoutGrid size={16} /></button>
                        <button onClick={() => setDisplayMode('list')} className={`p-1.5 rounded-lg transition-all ${displayMode === 'list' ? 'bg-skin-card shadow-sm text-skin-primary' : 'text-skin-muted hover:bg-skin-control-hover'}`}><LayoutList size={16} /></button>
                    </div>
                </div>

                {/* Categories */}
                <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide mask-fade-right">
                    {categories.map(cat => (
                        <motion.button 
                            whileTap={{ scale: 0.95 }}
                            key={cat} 
                            onClick={() => setSelectedCategory(cat)} 
                            className={`px-4 py-2 rounded-xl text-xs font-bold whitespace-nowrap transition-all border ${selectedCategory === cat ? 'bg-skin-primary border-skin-primary text-white shadow-lg shadow-skin-primary/25' : 'glass border-skin-border text-skin-text hover:bg-skin-control-bg'}`}
                        >
                            {cat}
                        </motion.button>
                    ))}
                </div>
            </div>

            {/* Content Grid */}
            <AnimatePresence mode='wait'>
                {isLoading ? (
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                        className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}
                    >
                         {[1, 2, 3, 4].map(i => <SkeletonCard key={i} />)}
                    </motion.div>
                ) : processedCatalogs.length > 0 ? (
                    <motion.div 
                        layout
                        className={`grid gap-4 md:gap-6 ${displayMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2'}`}
                    >
                        {processedCatalogs.map((catalog, index) => (
                            <CatalogCard key={catalog.id} catalog={catalog} onClick={(c) => { setInitialPage(0); setSelectedCatalog(c); }} viewMode={displayMode} index={index} />
                        ))}
                    </motion.div>
                ) : (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="py-16 text-center text-skin-muted glass rounded-3xl border border-dashed border-skin-border flex flex-col items-center justify-center gap-4">
                        <div className="bg-skin-control-bg p-4 rounded-full"><Search size={32} /></div>
                        <p>هیچ کاتالوگی با این مشخصات یافت نشد.</p>
