                    </motion.div>
                )}
            </AnimatePresence>
        </div>

        {/* Videos Section */}
        {processedVideos.length > 0 && !isLoading && (
            <motion.div 
                initial={{ opacity: 0, y: 50 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
