            </div>
            <a href="https://dbsgraphic.ir/" target="_blank" rel="noopener noreferrer" className="text-[10px] text-skin-muted hover:text-skin-primary transition-colors flex items-center gap-1 bg-white dark:bg-slate-800 px-3 py-1.5 rounded-full border border-skin-border shadow-sm group">
                <Sparkles size={12} className="text-yellow-500 group-hover:rotate-12 transition-transform" />
