      <ChatBot />

      <AnimatePresence>
        {selectedCatalog && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-50">
                 <BookViewer catalog={selectedCatalog} initialPage={initialPage} onClose={handleCloseViewer} />
