        )}
        {selectedVideo && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-50">
                 <VideoPlayer video={selectedVideo} onClose={() => setSelectedVideo(null)} />
            </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

