import React, { useState, useRef, useEffect, useCallback } from 'react';
import HTMLFlipBook from 'react-pageflip';
import { Catalog } from '../types';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  Maximize, 
  Minimize, 
  Volume2, 
  VolumeX,
  FileDown,
  ZoomIn,
  ZoomOut,
  Book,
  Smartphone,
  ChevronUp,
  ChevronDown,
  Highlighter,
  StickyNote,
  Trash2,
  MousePointer2
} from 'lucide-react';

interface BookViewerProps {
  catalog: Catalog;
  onClose: () => void;
  initialPage?: number;
}

// Annotation Types
type AnnotationType = 'highlight' | 'note';
interface Annotation {
  id: string;
  type: AnnotationType;
  x: number; // percentage (0-100)
  y: number; // percentage (0-100)
  content?: string; // for notes
  color?: string;
}

// Sound effect URL
const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// Helper for distance between two touch points
const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

// ForwardRef for Page
const Page = React.forwardRef<HTMLDivElement, { 
    children: React.ReactNode, 
    number: number, 
    annotations: Annotation[],
    activeTool: 'none' | AnnotationType | 'eraser',
    onAddAnnotation: (type: AnnotationType, x: number, y: number) => void,
    onDeleteAnnotation: (id: string) => void
}>((props, ref) => {

  const handlePageClick = (e: React.MouseEvent<HTMLDivElement>) => {
    // Only proceed if a tool is active
    if (props.activeTool === 'none' || props.activeTool === 'eraser') return;

    e.preventDefault();
    e.stopPropagation(); // Critical: Stop the book from trying to flip

    const rect = e.currentTarget.getBoundingClientRect();
    // Calculate relative percentage coordinates
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    props.onAddAnnotation(props.activeTool, x, y);
  };

  const handleAnnotationClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation(); // Always stop propagation on annotation click
      e.preventDefault();
      if (props.activeTool === 'eraser') {
          props.onDeleteAnnotation(id);
      }
  };

  return (
    <div className="bg-white shadow-inner h-full w-full relative overflow-hidden" ref={ref}>
        {/* Wrapper handles the clicks for annotations */}
        <div 
            className={`absolute inset-0 z-10 ${props.activeTool !== 'none' && props.activeTool !== 'eraser' ? 'cursor-crosshair' : ''}`}
            onClick={handlePageClick}
        >
            {/* Annotation Layer */}
            {props.annotations.map(ann => (
                <div
                    key={ann.id}
                    onClick={(e) => handleAnnotationClick(e, ann.id)}
                    className={`absolute z-20 hover:scale-110 transition-transform cursor-pointer ${props.activeTool === 'eraser' ? 'hover:opacity-50' : ''}`}
                    style={{ 
                        left: `${ann.x}%`, 
                        top: `${ann.y}%`,
                        transform: 'translate(-50%, -50%)'
                    }}
                    title={ann.content || 'Highlight'}
                >
                    {ann.type === 'highlight' && (
                        <div className="w-32 h-6 bg-yellow-300/50 mix-blend-multiply rounded-sm border border-yellow-400/30" />
                    )}
                    {ann.type === 'note' && (
                         <div className="relative group">
                            <StickyNote size={32} className="text-yellow-500 fill-yellow-100 drop-shadow-md" />
                            {/* Tooltip for Note Content */}
                            {ann.content && (
                                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 bg-yellow-50 text-yellow-900 text-xs p-2 rounded shadow-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-30 border border-yellow-200 text-center font-bold">
                                    {ann.content}
                                </div>
                            )}
                         </div>
                    )}
                </div>
            ))}
        </div>

        {/* Page Content */}
        <div className="h-full w-full relative z-0">
             {props.children}
             <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none select-none">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

export const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(initialPage);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });

  // Settings
  const [isMobile, setIsMobile] = useState(false);
  const [forceSinglePage, setForceSinglePage] = useState(false);

  // UI Settings
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  // New Independent Panel States
  const [showTopPanel, setShowTopPanel] = useState(true);
  const [showBottomPanel, setShowBottomPanel] = useState(true);

  // Annotations
  const [annotations, setAnnotations] = useState<{ [pageIndex: number]: Annotation[] }>({});
  const [activeTool, setActiveTool] = useState<'none' | AnnotationType | 'eraser'>('none');

  // Gesture State
  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isGesturing, setIsGesturing] = useState(false);

  // Gesture Refs
  const gesture = useRef({
    startX: 0,
    startY: 0,
    startPanX: 0,
    startPanY: 0,
    startDist: 0,
    startZoom: 1,
    mode: 'none' as 'none' | 'swipe' | 'pan' | 'pinch',
  });

  // Load annotations from local storage
  useEffect(() => {
      const saved = localStorage.getItem(`annotations_${catalog.id}`);
      if (saved) {
          try {
              setAnnotations(JSON.parse(saved));
          } catch (e) {
              console.error("Failed to load annotations");
          }
      }
  }, [catalog.id]);

  // Save annotations to local storage
  const saveAnnotations = (newAnnotations: typeof annotations) => {
      setAnnotations(newAnnotations);
      localStorage.setItem(`annotations_${catalog.id}`, JSON.stringify(newAnnotations));
  };

  const addAnnotationToPage = (pageIndex: number, type: AnnotationType, x: number, y: number) => {
      let content = '';
      if (type === 'note') {
          const text = window.prompt("یادداشت خود را بنویسید:");
          if (!text) return; // Cancelled
          content = text;
      }

      const newAnnotation: Annotation = {
          id: Date.now().toString(),
          type,
          x,
          y,
          content
      };

      const pageAnnotations = annotations[pageIndex] || [];
      const updated = {
          ...annotations,
          [pageIndex]: [...pageAnnotations, newAnnotation]
      };

      saveAnnotations(updated);

      // We do NOT automatically reset the tool to 'none' for Highlight, 
      // so user can highlight multiple areas. 
      // For Notes, it's better to reset or keep it based on UX preference.
      // Let's keep Highlight active, but maybe reset Note?
      if (type === 'note') setActiveTool('none');
  };

  const deleteAnnotation = (pageIndex: number, id: string) => {
      const pageAnnotations = annotations[pageIndex] || [];
      const updated = {
          ...annotations,
          [pageIndex]: pageAnnotations.filter(a => a.id !== id)
      };
      saveAnnotations(updated);
  };

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;
  }, []);

  // Jump to initial page if provided
  useEffect(() => {
      if (initialPage > 0 && bookRef.current) {
          setTimeout(() => {
            bookRef.current?.pageFlip().flip(initialPage);
          }, 500);
      }
  }, [initialPage]);

  // Responsive Resizing & Mode
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;
      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);

      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 0 : 100;

      const availableHeight = windowHeight - verticalPadding;
      const availableWidth = windowWidth - horizontalPadding;

      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      setDimensions({ 
          width: Math.floor(bookWidth), 
          height: Math.floor(bookHeight) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Fullscreen Handler
  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Reset Pan when Zoom is <= 1
  useEffect(() => {
    if (zoomLevel <= 1) {
      setPan({ x: 0, y: 0 });
    }
  }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip().flipNext();
  const prevFlip = () => bookRef.current?.pageFlip().flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip().flip(index);

  const onInit = useCallback((e: any) => {
      setTotalPages(e.object.pages.length);
      if (initialPage > 0) {
          e.object.flip(initialPage);
      }
  }, [initialPage]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(err => console.error(err));
    } else {
        document.exitFullscreen();
    }
  };

  const handleZoomIn = () => setZoomLevel(prev => Math.min(Math.round((prev + 0.1) * 10) / 10, 4.0));
  const handleZoomOut = () => setZoomLevel(prev => Math.max(Math.round((prev - 0.1) * 10) / 10, 0.5));

  const handleDownload = () => {
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- GESTURE LOGIC ---
  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    if (activeTool !== 'none') return;

    setIsGesturing(true);
    gesture.current.startX = clientX;
    gesture.current.startY = clientY;
    gesture.current.mode = mode;

    if (mode === 'pan') {
      gesture.current.startPanX = pan.x;
      gesture.current.startPanY = pan.y;
    }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'none') return;

    if (gesture.current.mode === 'pan') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      setPan({ 
        x: gesture.current.startPanX + dx, 
        y: gesture.current.startPanY + dy 
      });
    }
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'none') return;

    setIsGesturing(false);

    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      const absDx = Math.abs(dx);
      const absDy = Math.abs(dy);

      if (absDx > 30 && absDx > absDy) {
        if (dx > 0) prevFlip(); 
        else nextFlip(); 
      }
    }

    if (gesture.current.mode === 'pinch') {
       if (zoomLevel < 1.1) setZoomLevel(1);
    }

    gesture.current.mode = 'none';
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (activeTool !== 'none') return;
    if (e.touches.length === 2) {
      setIsGesturing(true);
      gesture.current.mode = 'pinch';
      gesture.current.startDist = getDistance(e.touches);
      gesture.current.startZoom = zoomLevel;
    } else if (e.touches.length === 1) {
      const mode = zoomLevel > 1 ? 'pan' : 'swipe';
      startGesture(e.touches[0].clientX, e.touches[0].clientY, mode);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (activeTool !== 'none') return;
    if (gesture.current.mode === 'pinch' && e.touches.length === 2) {
      const dist = getDistance(e.touches);
      const scale = (dist / gesture.current.startDist) * gesture.current.startZoom;
      setZoomLevel(Math.min(Math.max(scale, 0.5), 4));
    } else if (e.touches.length === 1) {
      moveGesture(e.touches[0].clientX, e.touches[0].clientY);
    }
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const touch = e.changedTouches[0];
    endGesture(touch.clientX, touch.clientY);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0 || activeTool !== 'none') return;
    e.preventDefault(); 
    const mode = zoomLevel > 1 ? 'pan' : 'swipe';
    startGesture(e.clientX, e.clientY, mode);
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden"
    >
      <div className="flex-grow flex flex-col h-full relative">

        {/* --- TOP PANEL --- */}
        <div 
            className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-20 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}
        >
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <div className="flex items-center gap-2 text-skin-muted text-xs mt-0.5">
                        <span>صفحه {currentPage + 1} از {catalog.pages.length}</span>
                    </div>
                </div>

                {/* Desktop Controls */}
                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                        {/* Annotation Tools */}
                        <div className="flex items-center px-1 border-l border-gray-300 ml-1 pl-2 gap-1">
                            <button 
                                onClick={() => setActiveTool(activeTool === 'none' ? 'none' : 'none')}
                                className={`p-2 rounded-md transition-colors ${activeTool === 'none' ? 'bg-skin-card shadow-sm text-skin-primary' : 'text-skin-control-text hover:bg-skin-control-hover'}`}
                                title="جابجایی / ورق زدن"
                            >
                                <MousePointer2 size={18} />
                            </button>
                            <button 
                                onClick={() => setActiveTool(activeTool === 'highlight' ? 'none' : 'highlight')}
                                className={`p-2 rounded-md transition-colors ${activeTool === 'highlight' ? 'bg-yellow-200 text-yellow-800 shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`}
                                title="هایلایت"
                            >
                                <Highlighter size={18} />
                            </button>
                            <button 
                                onClick={() => setActiveTool(activeTool === 'note' ? 'none' : 'note')}
                                className={`p-2 rounded-md transition-colors ${activeTool === 'note' ? 'bg-yellow-200 text-yellow-800 shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`}
                                title="یادداشت"
                            >
                                <StickyNote size={18} />
                            </button>
                            <button 
                                onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                                className={`p-2 rounded-md transition-colors ${activeTool === 'eraser' ? 'bg-red-200 text-red-800 shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`}
                                title="حذف"
                            >
                                <Trash2 size={18} />
                            </button>
                        </div>

                        {/* View Mode Toggle */}
                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}
                        </button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomOut size={18} /></button>
                        <span className="text-xs w-8 text-center tabular-nums text-skin-muted select-none">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomIn size={18} /></button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                        </button>
                        <button onClick={toggleFullscreen} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                        </button>
                        <button onClick={handleDownload} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            <FileDown size={18} />
                        </button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border pointer-events-auto">
                        <X size={20} />
                    </button>
                </div>
            </div>

            <div className="flex justify-center -mb-3 pb-1">
                 <button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 shadow-sm text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg transition-colors">
                    <ChevronUp size={16} />
                 </button>
            </div>
        </div>

        {/* Floating Top Expand Button */}
        <button 
            onClick={() => setShowTopPanel(true)}
            className={`absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all duration-300 ${!showTopPanel ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-full pointer-events-none'}`}
        >
            <ChevronDown size={20} />
        </button>

        {/* Book Container */}
        <div 
            className="flex-grow flex items-center justify-center relative w-full h-full overflow-hidden cursor-grab active:cursor-grabbing pb-20 pt-20" 
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
            onMouseDown={handleMouseDown}
            onMouseMove={(e) => { if (activeTool === 'none') moveGesture(e.clientX, e.clientY); }}
            onMouseUp={(e) => { if (activeTool === 'none') endGesture(e.clientX, e.clientY); }}
            onMouseLeave={(e) => { if (activeTool === 'none') endGesture(e.clientX, e.clientY); }}
            style={{ cursor: activeTool !== 'none' ? 'crosshair' : 'grab' }}
        >
            <button onClick={(e) => { e.stopPropagation(); nextFlip(); }} className={`hidden md:flex absolute right-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group opacity-100 ${activeTool !== 'none' ? 'pointer-events-none opacity-50' : ''}`}>
                <ChevronRight size={24} className="group-active:translate-x-1 transition-transform" />
            </button>

            <button onClick={(e) => { e.stopPropagation(); prevFlip(); }} className={`hidden md:flex absolute left-6 z-10 p-3 bg-skin-primary hover:bg-skin-primary-hover text-white rounded-full shadow-lg transition-all hover:scale-110 backdrop-blur-sm border border-white/20 group opacity-100 ${activeTool !== 'none' ? 'pointer-events-none opacity-50' : ''}`}>
                <ChevronLeft size={24} className="group-active:-translate-x-1 transition-transform" />
            </button>

            <div 
                style={{ 
                    transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})`,
                    transition: isGesturing ? 'none' : 'transform 0.2s ease-out',
                    transformOrigin: 'center center',
                }}
                className="flex items-center justify-center relative"
            >
                {/* @ts-ignore */}
                <HTMLFlipBook
                    key={`${dimensions.width}-${forceSinglePage}`} 
                    width={dimensions.width}
                    height={dimensions.height}
                    size="fixed"
                    minWidth={300}
                    maxWidth={3000}
                    minHeight={400}
                    maxHeight={4000}
                    maxShadowOpacity={0.5}
                    showCover={false}
                    mobileScrollSupport={false}
                    onFlip={onFlip}
                    onInit={onInit}
                    ref={bookRef}
                    className={`shadow-2xl transition-opacity duration-500 ${dimensions.width === 400 ? 'opacity-0' : 'opacity-100'}`}
                    style={{ margin: '0 auto' }}
                    usePortrait={isMobile || forceSinglePage}
                    startPage={initialPage}
                    drawShadow={true}
                    flippingTime={800}
                    useMouseEvents={false}
                    swipeDistance={10000}
                >
                    {catalog.pages.map((pageUrl, index) => (
                        <Page 
                            number={index + 1} 
                            key={index}
                            activeTool={activeTool}
                            annotations={annotations[index] || []}
                            onAddAnnotation={(type, x, y) => addAnnotationToPage(index, type, x, y)}
                            onDeleteAnnotation={(id) => deleteAnnotation(index, id)}
                        >
                             <div className="w-full h-full bg-slate-100 flex items-center justify-center select-none pointer-events-none">
                                <img 
                                    src={pageUrl} 
                                    alt={`Page ${index + 1}`} 
                                    className="w-full h-full object-contain"
                                    loading={index < 4 ? "eager" : "lazy"}
                                />
                             </div>
                        </Page>
                    ))}
                </HTMLFlipBook>
            </div>
        </div>

        {/* --- BOTTOM PANEL (Thumbnails + Mobile Toolbar) --- */}
        <div className={`absolute bottom-0 left-0 right-0 z-20 transition-transform duration-300 ${showBottomPanel ? 'translate-y-0' : 'translate-y-full'}`}>

             {/* Bottom Collapse Button */}
             <div className="flex justify-center -mt-3 pt-1 pointer-events-none">
                 <button onClick={() => setShowBottomPanel(false)} className="pointer-events-auto bg-skin-card border border-skin-border rounded-full p-1 shadow-sm text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg transition-colors relative z-30">
                    <ChevronDown size={16} />
                 </button>
             </div>

            {/* Mobile Toolbar (Above Thumbnails) */}
            <div 
                className={`md:hidden bg-skin-card border-t border-skin-border shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]`}
            >
                <div className="flex flex-col gap-2 px-4 py-2">
                    {/* Mobile Annotation Toolbar */}
                    <div className="flex justify-center items-center gap-2 py-1 border-b border-gray-100 pb-2">
                         <button 
                                onClick={() => setActiveTool(activeTool === 'none' ? 'none' : 'none')}
                                className={`p-2 rounded-md ${activeTool === 'none' ? 'bg-gray-200 text-skin-primary' : 'text-gray-500'}`}
                            >
                                <MousePointer2 size={16} />
                        </button>
                        <button 
                                onClick={() => setActiveTool(activeTool === 'highlight' ? 'none' : 'highlight')}
                                className={`p-2 rounded-md ${activeTool === 'highlight' ? 'bg-yellow-100 text-yellow-800' : 'text-gray-500'}`}
                            >
                                <Highlighter size={16} />
                        </button>
                        <button 
                                onClick={() => setActiveTool(activeTool === 'note' ? 'none' : 'note')}
                                className={`p-2 rounded-md ${activeTool === 'note' ? 'bg-yellow-100 text-yellow-800' : 'text-gray-500'}`}
                            >
                                <StickyNote size={16} />
                        </button>
                         <button 
                                onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                                className={`p-2 rounded-md ${activeTool === 'eraser' ? 'bg-red-100 text-red-800' : 'text-gray-500'}`}
                            >
                                <Trash2 size={16} />
                        </button>
                    </div>

                    <div className="flex justify-center items-center gap-4 py-1 border-b border-gray-100 pb-2 mb-1">
                        <button onClick={handleZoomOut} className="p-1.5 bg-gray-100 rounded text-gray-600"><ZoomOut size={16} /></button>
                        <span className="text-xs font-mono text-gray-500 w-10 text-center">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-1.5 bg-gray-100 rounded text-gray-600"><ZoomIn size={16} /></button>
                    </div>

                    <div className="flex justify-between items-center">
                        <button onClick={nextFlip} className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors">
                            <ChevronRight size={24} />
                        </button>

                        <div className="flex gap-4 text-skin-muted">
                            <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2">
                                {isSoundEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                            </button>
                            <button onClick={handleDownload} className="p-2"><FileDown size={20} /></button>
                        </div>

                        <button onClick={prevFlip} className="p-3 rounded-xl bg-skin-control-bg text-skin-control-text active:bg-skin-primary active:text-white transition-colors">
                            <ChevronLeft size={24} />
                        </button>
                    </div>
                </div>
            </div>

            {/* Thumbnail Strip */}
            <div className={`h-20 bg-skin-card/90 backdrop-blur-md border-t border-skin-border flex items-center px-4 gap-2 overflow-x-auto`}>
                 {catalog.pages.map((page, idx) => (
                     <button 
                        key={idx} 
                        onClick={() => goToPage(idx)}
                        className={`shrink-0 h-16 w-12 rounded border-2 overflow-hidden transition-all ${currentPage === idx ? 'border-skin-primary scale-110 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}
                     >
                         <img src={page} className="w-full h-full object-cover" loading="lazy" />
                     </button>
                 ))}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import { BookViewer } from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import SkeletonCard from './components/SkeletonCard';
import ChatBot from './components/ChatBot';
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos, isLoading } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [initialPage, setInitialPage] = useState(0);

  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const [sortBy, setSortBy] = useState<SortOption>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('همه');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  const categories = ['همه', ...Array.from(new Set(catalogs.map(c => c.category).filter(Boolean)))];

  // Deep Linking
  useEffect(() => {
    if (catalogs.length > 0) {
      const params = new URLSearchParams(window.location.search);
      const catId = params.get('cat');
      const pageNum = params.get('page');

      if (catId) {
        const found = catalogs.find(c => c.id === catId);
        if (found) {
          let pIndex = 0;
          if (pageNum) {
            pIndex = Math.max(0, parseInt(pageNum) - 1);
            if (pIndex >= found.pages.length) pIndex = 0;
          }
          setInitialPage(pIndex);
          setSelectedCatalog(found);
        }
      }
    }
  }, [catalogs]);

  useEffect(() => {
    const handleResize = () => setDisplayMode(window.innerWidth < 768 ? 'list' : 'grid');
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
