// --- Specialized Note Item to prevent focus loss ---
const NoteItem = ({ ann, activeTool, onUpdate, onDelete, isActive, onToggleActive }: {
    ann: Annotation;
    activeTool: string;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
    isActive: boolean;
    onToggleActive: () => void;
}) => {
    const [localContent, setLocalContent] = useState(ann.content || '');

    // Sync with external changes if any (rare)
    useEffect(() => {
        setLocalContent(ann.content || '');
    }, [ann.content]);

    return (
        <div 
            className="absolute pointer-events-auto"
            style={{ left: `${ann.x}%`, top: `${ann.y}%`, zIndex: isActive ? 50 : 20 }}
            onClick={(e) => {
                e.stopPropagation();
                onToggleActive();
            }}
        >
            <div className="relative -translate-x-1/2 -translate-y-1/2">
                <button 
                    className={`p-1.5 rounded-full shadow-lg transition-all transform hover:scale-110 ${isActive ? 'bg-yellow-400 text-yellow-900 ring-2 ring-yellow-600' : 'bg-yellow-200 text-yellow-700'}`}
                >
                    <MessageSquare size={22} fill={isActive ? "currentColor" : "none"} />
                </button>

                {isActive && (
                    <div 
                        className="absolute top-10 left-1/2 -translate-x-1/2 w-56 sm:w-64 bg-yellow-50 border border-yellow-300 rounded-xl shadow-2xl p-3 animate-fade-in"
                        onClick={e => e.stopPropagation()}
                    >
