                            placeholder="یادداشت خود را بنویسید..."
                            value={localContent}
                            onChange={(e) => setLocalContent(e.target.value)}
                            onBlur={() => onUpdate(ann.id, localContent)}
                            autoFocus
                        />
                        <div className="flex justify-between items-center border-t border-yellow-200 pt-2">
                            <button 
                                onClick={() => onDelete(ann.id)}
                                className="text-red-500 hover:bg-red-100 p-1.5 rounded-lg transition-colors"
                            >
                                <Trash2 size={16} />
                            </button>
                            <button 
                                onClick={() => {
                                    onUpdate(ann.id, localContent);
                                    onToggleActive();
                                }}
                                className="bg-yellow-500 text-white px-4 py-1.5 rounded-lg text-xs font-bold hover:bg-yellow-600 transition-colors flex items-center gap-1.5"
                            >
                                <Check size={14} />
