                        <div className="absolute -top-2 left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-b-[8px] border-b-yellow-50"></div>
                    </div>
                )}
            </div>
        </div>
    );
};

// --- Annotation Layer Component ---
const AnnotationLayer = ({ pageIndex, activeTool, annotations, onAdd, onUpdate, onDelete }: {
    pageIndex: number;
    activeTool: 'cursor' | 'highlight' | 'note';
    annotations: Annotation[];
    onAdd: (ann: Annotation) => void;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
}) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [activeNoteId, setActiveNoteId] = useState<string | null>(null);

    const handleClick = (e: React.MouseEvent) => {
        if (!containerRef.current) return;

        if (activeTool === 'highlight' || activeTool === 'note') {
            e.stopPropagation();
            const rect = containerRef.current.getBoundingClientRect();
            const x = ((e.clientX - rect.left) / rect.width) * 100;
            const y = ((e.clientY - rect.top) / rect.height) * 100;

            const newId = Date.now().toString();
            if (activeTool === 'highlight') {
                onAdd({ id: newId, type: 'highlight', x, y, width: 25, height: 4 });
            } else {
                onAdd({ id: newId, type: 'note', x, y, content: '' });
                setActiveNoteId(newId);
            }
        } else {
            setActiveNoteId(null);
        }
    };

    return (
        <div 
            ref={containerRef}
            className={`absolute inset-0 z-10 ${activeTool !== 'cursor' ? 'cursor-crosshair' : 'pointer-events-none'}`}
            onClick={handleClick}
        >
            {annotations.map(ann => {
                if (ann.type === 'highlight') {
                    return (
                        <div 
                            key={ann.id}
                            className="absolute pointer-events-auto bg-yellow-400/40 mix-blend-multiply group border border-yellow-500/20"
                            style={{ left: `${ann.x}%`, top: `${ann.y}%`, width: `${ann.width}%`, height: `${ann.height}%`, transform: 'translate(-50%, -50%)' }}
                        >
                            <button 
                                onClick={(e) => { e.stopPropagation(); onDelete(ann.id); }}
                                className="absolute -top-3 -right-3 bg-red-600 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                                <X size={12} />
                            </button>
                        </div>
                    );
                }
                return (
                    <NoteItem 
                        key={ann.id} 
                        ann={ann} 
                        activeTool={activeTool}
                        onUpdate={onUpdate}
                        onDelete={onDelete}
                        isActive={activeNoteId === ann.id}
                        onToggleActive={() => setActiveNoteId(activeNoteId === ann.id ? null : ann.id)}
                    />
                );
            })}
        </div>
    );
};

