import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Send, X, Bot, Loader2, Sparkles, User, Package, ChevronLeft, ArrowRight, Building2, Activity, Headphones, CheckCircle, AlertTriangle, Phone, FileText } from 'lucide-react';

const API_URL = './chat.php';
const SUBMIT_API_URL = './submit_form.php';

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

type ChatView = 'menu' | 'products' | 'chat' | 'adr_select' | 'adr_form' | 'consult_form' | 'success';

const PRODUCTS = [
    { id: 'capsulizer', name: 'کپسولایزر' },
    { id: 'coldanese', name: 'کلدانیز پلاس' },
    { id: 'folinozit', name: 'فولینوزیت' },
    { id: 'meglozek', name: 'مگلوزک' },
    { id: 'tiotoriva', name: 'تیوتوریوا' },
];

const COMPANY_INFO = { id: 'nafas', name: 'شرکت نفس زیست فارمد' };

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [view, setView] = useState<ChatView>('menu');
  const [selectedProduct, setSelectedProduct] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const [formData, setFormData] = useState({ name: '', phone: '', description: '', productName: '' });
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  useEffect(() => scrollToBottom(), [messages, isOpen, view]);

  useEffect(() => {
    if (isOpen && view === 'chat' && inputRef.current) {
        setTimeout(() => inputRef.current?.focus(), 300);
    }
  }, [isOpen, view]);

  const resetChat = () => {
      setSelectedProduct(null);
      setMessages([]);
      setInput('');
      setFormData({ name: '', phone: '', description: '', productName: '' });
      setView('menu');
  };

  const handleOptionSelect = (option: 'company' | 'products' | 'adr' | 'consult') => {
      if (option === 'company') {
          setSelectedProduct(COMPANY_INFO.id);
          setMessages([{ id: 'welcome', role: 'assistant', content: `سلام! من آماده پاسخگویی به سوالات شما درباره **${COMPANY_INFO.name}** هستم.` }]);
          setView('chat');
      } else if (option === 'products') setView('products');
      else if (option === 'adr') setView('adr_select');
      else if (option === 'consult') setView('consult_form');
  };

  const handleProductSelect = (productId: string) => {
    setSelectedProduct(productId);
    const productName = PRODUCTS.find(p => p.id === productId)?.name;
    setMessages([{ id: 'welcome', role: 'assistant', content: `سلام! من دستیار هوشمند محصول **${productName}** هستم. هر سوالی در مورد این دارو دارید بپرسید.` }]);
    setView('chat');
  };

  const handleChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading || !selectedProduct) return;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const body = new URLSearchParams();
      body.append('message', userMsg.content);
      body.append('product', selectedProduct);
      const response = await fetch(API_URL, { method: 'POST', body });
      if (!response.ok) throw new Error('API Error');
      const text = await response.text();
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: text || 'پاسخی دریافت نشد.' }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: 'خطا در برقراری ارتباط با سرور.' }]);
    } finally { setIsLoading(false); }
  };

  return (
    <>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-40 p-4 rounded-full shadow-2xl transition-all group ${isOpen ? 'bg-white text-slate-900 rotate-90' : 'bg-skin-primary text-white'}`}
      >
        {isOpen ? <X size={28} /> : <MessageCircle size={28} />}
      </button>

      <div 
        className={`fixed bottom-24 right-4 sm:right-6 w-[calc(100%-2rem)] sm:w-96 bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-700 flex flex-col overflow-hidden transition-all duration-300 z-40 ${isOpen ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}
        style={{ height: '560px' }}
      >
        <div className="bg-skin-primary text-white p-4 flex items-center gap-3 shrink-0">
            {view !== 'menu' && (
                <button onClick={() => view === 'success' ? resetChat() : setView('menu')} className="p-1 hover:bg-white/20 rounded-full"><ArrowRight size={20} /></button>
            )}
            <div className="bg-white/20 p-2 rounded-full"><Bot size={24} /></div>
            <div>
                <h3 className="font-bold text-sm leading-tight">{getHeaderTitle()}</h3>
                <p className="text-[10px] opacity-80 flex items-center gap-1">
                    <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
                    {getSubHeader()}
                </p>
            </div>
        </div>

        {view === 'menu' && (
            <div className="flex-grow overflow-y-auto p-5 space-y-3">
                <p className="text-center text-slate-500 text-sm mb-6">به مرکز پاسخگویی نفس فارمد خوش آمدید. چطور می‌توانم به شما کمک کنم؟</p>
                <button onClick={() => handleOptionSelect('company')} className="w-full flex items-center gap-3 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl hover:bg-slate-100 transition-all text-right border border-slate-100 dark:border-slate-700">
                    <div className="bg-blue-100 text-blue-600 p-2 rounded-xl"><Building2 size={20} /></div>
                    <span className="font-bold text-sm">اطلاعات شرکت نفس فارمد</span>
                </button>
                <button onClick={() => handleOptionSelect('products')} className="w-full flex items-center gap-3 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl hover:bg-slate-100 transition-all text-right border border-slate-100 dark:border-slate-700">
                    <div className="bg-green-100 text-green-600 p-2 rounded-xl"><Package size={20} /></div>
                    <span className="font-bold text-sm">مشاوره در مورد محصولات</span>
                </button>
                <div className="grid grid-cols-2 gap-3">
                    <button onClick={() => handleOptionSelect('adr')} className="flex flex-col items-center gap-2 p-4 bg-red-50 dark:bg-red-950/20 rounded-2xl border border-red-100 dark:border-red-900/30">
                        <Activity className="text-red-500" size={24} />
                        <span className="font-bold text-xs">گزارش عوارض</span>
                    </button>
                    <button onClick={() => handleOptionSelect('consult')} className="flex flex-col items-center gap-2 p-4 bg-purple-50 dark:bg-purple-950/20 rounded-2xl border border-purple-100 dark:border-purple-900/30">
                        <Headphones className="text-purple-500" size={24} />
                        <span className="font-bold text-xs">درخواست تماس</span>
                    </button>
                </div>
            </div>
        )}

        {view === 'chat' && (
            <div className="flex-grow flex flex-col overflow-hidden">
                <div className="flex-grow overflow-y-auto p-4 space-y-4">
                    {messages.map(msg => (
                        <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-skin-primary text-white rounded-tr-none' : 'bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-tl-none'}`}>
                                {msg.content}
                            </div>
                        </div>
                    ))}
                    {isLoading && <div className="flex gap-1 items-center p-2"><Loader2 size={16} className="animate-spin text-skin-primary" /> <span className="text-xs text-slate-400">درحال بررسی...</span></div>}
                    <div ref={messagesEndRef} />
                </div>
                <form onSubmit={handleChatSubmit} className="p-3 bg-slate-50 dark:bg-slate-800 border-t border-slate-100 dark:border-slate-700 flex gap-2">
                    <input 
                        ref={inputRef} value={input} onChange={e => setInput(e.target.value)}
                        placeholder="سوال خود را اینجا بنویسید..."
                        className="flex-grow bg-white dark:bg-slate-900 p-2 px-4 rounded-full text-sm outline-none border border-slate-200 dark:border-slate-700 focus:border-skin-primary"
                    />
                    <button disabled={!input.trim() || isLoading} className="bg-skin-primary text-white p-2 rounded-full disabled:opacity-50"><Send size={18} /></button>
                </form>
            </div>
        )}
      </div>
    </>
  );
};

const getHeaderTitle = (v: any) => "پشتیبانی هوشمند نفس فارمد";
const getSubHeader = (v: any) => "پاسخگویی خودکار ۲۴ ساعته";

export default ChatBot;

import React, { useState, useEffect } from 'react';
import { Catalog, Video } from './types';
import { CatalogProvider, useCatalogs } from './context/CatalogContext';
import CatalogCard from './components/CatalogCard';
import VideoCard from './components/VideoCard';
import BookViewer from './components/BookViewer';
import VideoPlayer from './components/VideoPlayer';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import SkeletonCard from './components/SkeletonCard';
import ChatBot from './components/ChatBot';
import { Search, Sun, Moon, BookOpen, LayoutList, ArrowDownUp, LayoutGrid, Video as VideoIcon, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

type Theme = 'light' | 'dark' | 'reading';
type ViewMode = 'home' | 'admin';
type SortOption = 'newest' | 'oldest' | 'az' | 'za';
type DisplayMode = 'grid' | 'list';

const MainApp = () => {
  const { catalogs, videos, isLoading } = useCatalogs();
  const [selectedCatalog, setSelectedCatalog] = useState<Catalog | null>(null);
  const [initialPage, setInitialPage] = useState(0);
  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [viewMode, setViewMode] = useState<ViewMode>('home');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [sortBy, setSortBy] = useState<SortOption>('newest');
  const [selectedCategory, setSelectedCategory] = useState<string>('همه');
  const [displayMode, setDisplayMode] = useState<DisplayMode>('grid');

  const categories = ['همه', ...Array.from(new Set(catalogs.map(c => c.category).filter(Boolean)))];

  useEffect(() => {
    if (catalogs.length > 0) {
      const params = new URLSearchParams(window.location.search);
      const catId = params.get('cat');
      const pageNum = params.get('page');
      if (catId) {
        const found = catalogs.find(c => c.id === catId);
        if (found) {
          let pIndex = 0;
          if (pageNum) pIndex = Math.max(0, parseInt(pageNum) - 1);
          setInitialPage(pIndex);
          setSelectedCatalog(found);
        }
      }
    }
  }, [catalogs]);

  useEffect(() => {
    const handleResize = () => setDisplayMode(window.innerWidth < 768 ? 'list' : 'grid');
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.removeAttribute('data-theme');
    if (theme !== 'light') document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    if (theme === 'light') setTheme('dark');
    else if (theme === 'dark') setTheme('reading');
    else setTheme('light');
  };

  const processedCatalogs = catalogs.filter(cat => 
    (selectedCategory === 'همه' || cat.category === selectedCategory) &&
    (cat.title.toLowerCase().includes(searchTerm.toLowerCase()) || cat.description.toLowerCase().includes(searchTerm.toLowerCase()))
  ).sort((a, b) => {
    if (sortBy === 'newest') return b.date.localeCompare(a.date);
    if (sortBy === 'oldest') return a.date.localeCompare(b.date);
    if (sortBy === 'az') return a.title.localeCompare(b.title, 'fa');
    return b.title.localeCompare(a.title, 'fa');
  });

  const processedVideos = videos.filter(vid => 
     vid.title.toLowerCase().includes(searchTerm.toLowerCase()) || vid.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (viewMode === 'admin') {
    if (!isAuthenticated) return <AdminLogin onLogin={() => setIsAuthenticated(true)} onBack={() => setViewMode('home')} />;
    return <AdminPanel onLogout={() => { setIsAuthenticated(false); setViewMode('home'); }} />;
  }

  return (
