  height?: number; // Percentage for highlight
  content?: string; // For notes
  color?: string;
  isOpen?: boolean; // For notes UI state
}

// Sound effect URL
const PAGE_FLIP_SOUND_URL = "https://nafaspharmed.com/mp3/paper.mp3";

// Helper for distance between two touch points
const getDistance = (touches: React.TouchList) => {
  return Math.hypot(
    touches[0].clientX - touches[1].clientX,
    touches[0].clientY - touches[1].clientY
  );
};

// --- Note Item Component ---
interface NoteItemProps {
    ann: Annotation;
    isActive: boolean;
    onToggleActive: () => void;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
}

const NoteItem: React.FC<NoteItemProps> = ({ ann, isActive, onToggleActive, onUpdate, onDelete }) => {
    const [content, setContent] = useState(ann.content || '');

    // Sync local state with prop only if prop changes externally
    useEffect(() => {
        setContent(ann.content || '');
    }, [ann.content]);

    const handleSave = () => {
        if (content !== ann.content) {
            onUpdate(ann.id, content);
        }
    };

    return (
        <div className="relative -translate-x-1/2 -translate-y-1/2">
            <button 
                onClick={(e) => { e.stopPropagation(); onToggleActive(); }}
                className={`p-1.5 rounded-full shadow-md transition-transform hover:scale-110 ${isActive ? 'bg-yellow-400 text-yellow-900 ring-2 ring-yellow-500' : 'bg-yellow-200 text-yellow-700'}`}
            >
                <MessageSquare size={20} fill={isActive ? "currentColor" : "none"} />
            </button>

            {isActive && (
                <div 
                    className="absolute top-8 left-1/2 -translate-x-1/2 w-48 sm:w-64 bg-yellow-100 border border-yellow-300 rounded-lg shadow-xl p-3 z-50 text-left cursor-default animate-fade-in"
                    onClick={e => e.stopPropagation()}
                >
                    <textarea 
                        className="w-full bg-transparent border-b border-yellow-200 resize-none outline-none text-sm text-gray-800 min-h-[80px] mb-2 placeholder-yellow-800/50"
                        placeholder="یادداشت خود را بنویسید..."
                        value={content}
                        onChange={(e) => setContent(e.target.value)}
                        onBlur={handleSave}
                        autoFocus
                    />
                    <div className="flex justify-between items-center">
                        <button 
                            onClick={() => onDelete(ann.id)}
                            className="text-red-500 hover:bg-red-100 p-1 rounded transition-colors"
                            title="حذف یادداشت"
                        >
                            <Trash2 size={16} />
                        </button>
                        <button 
                            onClick={() => {
                                handleSave();
                                onToggleActive();
                            }}
                            className="bg-yellow-500 text-white px-3 py-1 rounded text-xs hover:bg-yellow-600 transition-colors flex items-center gap-1"
                        >
                            <Check size={14} />
                            بستن
                        </button>
                    </div>
                    {/* Triangle pointer */}
                    <div className="absolute -top-2 left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-b-[8px] border-b-yellow-100"></div>
                </div>
            )}
        </div>
    );
};

// --- Annotation Layer Component ---
interface AnnotationLayerProps {
    pageIndex: number;
    activeTool: 'cursor' | 'highlight' | 'note';
    annotations: Annotation[];
    onAdd: (ann: Annotation) => void;
    onUpdate: (id: string, content: string) => void;
    onDelete: (id: string) => void;
}

const AnnotationLayer: React.FC<AnnotationLayerProps> = ({ pageIndex, activeTool, annotations, onAdd, onUpdate, onDelete }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);
    const [startPoint, setStartPoint] = useState({ x: 0, y: 0 });
    const [currentPoint, setCurrentPoint] = useState({ x: 0, y: 0 });
    const [activeNoteId, setActiveNoteId] = useState<string | null>(null);

    const getRelativeCoords = (e: React.MouseEvent | React.TouchEvent) => {
        if (!containerRef.current) return { x: 0, y: 0 };
        const rect = containerRef.current.getBoundingClientRect();
        const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

        return {
            x: ((clientX - rect.left) / rect.width) * 100,
            y: ((clientY - rect.top) / rect.height) * 100
        };
    };

    const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
        if (activeTool === 'cursor') return;
        e.stopPropagation(); // Prevent flip/pan gestures

        if (activeTool === 'highlight') {
            setIsDrawing(true);
            const coords = getRelativeCoords(e);
            setStartPoint(coords);
            setCurrentPoint(coords);
        }
    };

    const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isDrawing) return;
        e.stopPropagation();
        setCurrentPoint(getRelativeCoords(e));
    };

    const handlePointerUp = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isDrawing) return;
        e.stopPropagation();
        setIsDrawing(false);

        // Calculate rect
        const x = Math.min(startPoint.x, currentPoint.x);
        const y = Math.min(startPoint.y, currentPoint.y);
        const width = Math.abs(currentPoint.x - startPoint.x);
        const height = Math.abs(currentPoint.y - startPoint.y);

        if (width > 1 && height > 1) { // Min size threshold
            onAdd({
                id: Date.now().toString(),
                type: 'highlight',
                x, y, width, height,
                color: '#fde047' // yellow-300
            });
        }
    };

    const handleClick = (e: React.MouseEvent) => {
        if (activeTool === 'note') {
            e.stopPropagation();
            // Don't add if clicking an existing annotation
            if ((e.target as HTMLElement).closest('.annotation-item')) return;

            const rect = containerRef.current!.getBoundingClientRect();
            const x = ((e.clientX - rect.left) / rect.width) * 100;
            const y = ((e.clientY - rect.top) / rect.height) * 100;

            const newId = Date.now().toString();
            onAdd({
                id: newId,
                type: 'note',
                x, y,
                content: '',
                color: '#fef08a'
            });
            setActiveNoteId(newId);
        }
    };

    return (
        <div 
            ref={containerRef}
            className={`absolute inset-0 z-10 ${activeTool !== 'cursor' ? 'cursor-crosshair touch-none' : 'pointer-events-none'}`}
            onMouseDown={handlePointerDown}
            onMouseMove={handlePointerMove}
            onMouseUp={handlePointerUp}
            onTouchStart={handlePointerDown}
            onTouchMove={handlePointerMove}
            onTouchEnd={handlePointerUp}
            onClick={handleClick}
        >
            {/* Existing Annotations */}
            {annotations.map(ann => (
                <div 
                    key={ann.id}
                    className="annotation-item absolute pointer-events-auto group"
                    style={{
                        left: `${ann.x}%`,
                        top: `${ann.y}%`,
                        width: ann.type === 'highlight' ? `${ann.width}%` : 'auto',
                        height: ann.type === 'highlight' ? `${ann.height}%` : 'auto',
                    }}
                    onClick={(e) => {
                        if (activeTool === 'cursor' || activeTool === 'highlight') {
                            e.stopPropagation();
                            if (ann.type === 'note') setActiveNoteId(activeNoteId === ann.id ? null : ann.id);
                        }
                    }}
                >
                    {ann.type === 'highlight' && (
                        <div className="w-full h-full bg-yellow-300/40 mix-blend-multiply border border-yellow-400/50 hover:bg-yellow-300/60 transition-colors relative">
                             {/* Delete Highlight Button */}
                             <button 
                                onClick={(e) => { e.stopPropagation(); onDelete(ann.id); }}
                                className="absolute -top-3 -right-3 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity transform scale-75"
                            >
                                <X size={12} />
                            </button>
                        </div>
                    )}

                    {ann.type === 'note' && (
                        <NoteItem 
                            ann={ann} 
                            isActive={activeNoteId === ann.id} 
                            onToggleActive={() => setActiveNoteId(activeNoteId === ann.id ? null : ann.id)}
                            onUpdate={onUpdate}
                            onDelete={onDelete}
                        />
                    )}
                </div>
            ))}

            {/* Drawing Preview */}
            {isDrawing && (
                <div 
                    className="absolute bg-yellow-300/40 border border-yellow-400 border-dashed pointer-events-none"
                    style={{
                        left: `${Math.min(startPoint.x, currentPoint.x)}%`,
                        top: `${Math.min(startPoint.y, currentPoint.y)}%`,
                        width: `${Math.abs(currentPoint.x - startPoint.x)}%`,
                        height: `${Math.abs(currentPoint.y - startPoint.y)}%`,
                    }}
                />
            )}
        </div>
    );
};

// ForwardRef for Page
const Page = React.forwardRef<HTMLDivElement, { children: React.ReactNode, number: number }>((props, ref) => {
  return (
    <div className="bg-white shadow-inner h-full w-full" ref={ref}>
        <div className="h-full w-full relative overflow-hidden select-none">
            {props.children}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-slate-400 text-xs font-medium bg-white/80 px-2 py-1 rounded-md shadow-sm pointer-events-none z-10">
                {props.number}
            </div>
        </div>
    </div>
  );
});
Page.displayName = 'Page';

const BookViewer: React.FC<BookViewerProps> = ({ catalog, onClose, initialPage = 0 }) => {
  const bookRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentPage, setCurrentPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [dimensions, setDimensions] = useState({ width: 400, height: 600 });

  // Settings
  const [isMobile, setIsMobile] = useState(false);
  const [forceSinglePage, setForceSinglePage] = useState(false);

  // UI Settings
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  // Independent Panel States
  const [showTopPanel, setShowTopPanel] = useState(true);
  const [showBottomPanel, setShowBottomPanel] = useState(true);

  // Gesture State
  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isGesturing, setIsGesturing] = useState(false);

  // Annotation State
  const [activeTool, setActiveTool] = useState<'cursor' | 'highlight' | 'note'>('cursor');
  const [annotations, setAnnotations] = useState<Record<number, Annotation[]>>({});

  // Gesture Refs
  const gesture = useRef({
    startX: 0,
    startY: 0,
    startPanX: 0,
    startPanY: 0,
    startDist: 0,
    startZoom: 1,
    mode: 'none' as 'none' | 'swipe' | 'pan' | 'pinch',
  });

  // Load Annotations
  useEffect(() => {
    const saved = localStorage.getItem(`nafas_annotations_${catalog.id}`);
    if (saved) {
        try {
            setAnnotations(JSON.parse(saved));
        } catch (e) { console.error('Error loading annotations', e); }
    }
  }, [catalog.id]);

  // Save Annotations
  useEffect(() => {
    if (Object.keys(annotations).length > 0) {
        localStorage.setItem(`nafas_annotations_${catalog.id}`, JSON.stringify(annotations));
    }
  }, [annotations, catalog.id]);

  const handleAddAnnotation = (pageIndex: number, ann: Annotation) => {
    setAnnotations(prev => ({
        ...prev,
        [pageIndex]: [...(prev[pageIndex] || []), ann]
    }));
    // Switch back to cursor after adding note? No, let user add multiple.
    if (ann.type === 'highlight') setActiveTool('cursor'); 
  };

  const handleUpdateAnnotation = (pageIndex: number, id: string, content: string) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: prev[pageIndex]?.map(a => a.id === id ? { ...a, content } : a) || []
      }));
  };

  const handleDeleteAnnotation = (pageIndex: number, id: string) => {
      setAnnotations(prev => ({
          ...prev,
          [pageIndex]: prev[pageIndex]?.filter(a => a.id !== id) || []
      }));
  };

  // Initialize Audio & Jump to Page
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_SOUND_URL);
    audioRef.current.volume = 0.4;

    // Slight delay to allow book to init
    if (initialPage > 0) {
        setTimeout(() => {
             bookRef.current?.pageFlip().flip(initialPage);
        }, 500);
    }
  }, [initialPage]);

  // Responsive Resizing & Mode
  useEffect(() => {
    const handleResize = () => {
      const windowWidth = window.innerWidth;
      const windowHeight = window.innerHeight;
      const isSmallScreen = windowWidth < 768;
      setIsMobile(isSmallScreen);
      if (isSmallScreen) setForceSinglePage(true);

      const verticalPadding = isSmallScreen ? 140 : 120;
      const horizontalPadding = isSmallScreen ? 0 : 100;

      const availableHeight = windowHeight - verticalPadding;
      const availableWidth = windowWidth - horizontalPadding;

      const aspectRatio = 1.414;
      let bookHeight = availableHeight;
      let bookWidth = bookHeight / aspectRatio;

      if (bookWidth > availableWidth) {
        bookWidth = availableWidth;
        bookHeight = bookWidth * aspectRatio;
      }

      setDimensions({ 
          width: Math.floor(bookWidth), 
          height: Math.floor(bookHeight) 
      });
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Fullscreen Handler
  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  // Reset Pan when Zoom is <= 1
  useEffect(() => {
    if (zoomLevel <= 1) {
      setPan({ x: 0, y: 0 });
    }
  }, [zoomLevel]);

  const playSound = useCallback(() => {
    if (isSoundEnabled && audioRef.current) {
        audioRef.current.currentTime = 0;
        audioRef.current.play().catch(() => {});
    }
  }, [isSoundEnabled]);

  const onFlip = useCallback((e: any) => {
    setCurrentPage(e.data);
    playSound();
  }, [playSound]);

  const nextFlip = () => bookRef.current?.pageFlip().flipNext();
  const prevFlip = () => bookRef.current?.pageFlip().flipPrev();
  const goToPage = (index: number) => bookRef.current?.pageFlip().flip(index);

  const onInit = useCallback((e: any) => setTotalPages(e.object.pages.length), []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
        containerRef.current?.requestFullscreen().catch(err => console.error(err));
    } else {
        document.exitFullscreen();
    }
  };

  const handleZoomIn = () => setZoomLevel(prev => {
      const next = Math.round((prev + 0.1) * 10) / 10;
      return Math.min(next, 4.0);
  });

  const handleZoomOut = () => setZoomLevel(prev => {
      const next = Math.round((prev - 0.1) * 10) / 10;
      return Math.max(next, 0.5);
  });

  const handleDownload = () => {
    const link = document.createElement('a');
    if (catalog.pdfUrl) {
      link.href = catalog.pdfUrl;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
    } else {
      link.href = catalog.pages[0];
      link.download = `${catalog.title.replace(/\s+/g, '_')}_preview.jpg`;
    }
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- GESTURE LOGIC (TOUCH & MOUSE) ---
  const startGesture = (clientX: number, clientY: number, mode: 'swipe' | 'pan') => {
    // Disable gestures if a tool is active
    if (activeTool !== 'cursor') return;

    setIsGesturing(true);
    gesture.current.startX = clientX;
    gesture.current.startY = clientY;
    gesture.current.mode = mode;

    if (mode === 'pan') {
      gesture.current.startPanX = pan.x;
      gesture.current.startPanY = pan.y;
    }
  };

  const moveGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'cursor') return;

    if (gesture.current.mode === 'pan') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      setPan({ 
        x: gesture.current.startPanX + dx, 
        y: gesture.current.startPanY + dy 
      });
    }
  };

  const endGesture = (clientX: number, clientY: number) => {
    if (activeTool !== 'cursor') return;

    setIsGesturing(false);

    if (gesture.current.mode === 'swipe') {
      const dx = clientX - gesture.current.startX;
      const dy = clientY - gesture.current.startY;
      const absDx = Math.abs(dx);
      const absDy = Math.abs(dy);

      if (absDx > 30 && absDx > absDy) {
        if (dx > 0) prevFlip(); 
        else nextFlip(); 
      }
    }

    if (gesture.current.mode === 'pinch') {
       if (zoomLevel < 1.1) setZoomLevel(1);
    }

    gesture.current.mode = 'none';
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (activeTool !== 'cursor') return;

    if (e.touches.length === 2) {
      setIsGesturing(true);
      gesture.current.mode = 'pinch';
      gesture.current.startDist = getDistance(e.touches);
      gesture.current.startZoom = zoomLevel;
    } else if (e.touches.length === 1) {
      const mode = zoomLevel > 1 ? 'pan' : 'swipe';
      startGesture(e.touches[0].clientX, e.touches[0].clientY, mode);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (activeTool !== 'cursor') return;

    if (gesture.current.mode === 'pinch' && e.touches.length === 2) {
      const dist = getDistance(e.touches);
      const scale = (dist / gesture.current.startDist) * gesture.current.startZoom;
      setZoomLevel(Math.min(Math.max(scale, 0.5), 4));
    } else if (e.touches.length === 1) {
      moveGesture(e.touches[0].clientX, e.touches[0].clientY);
    }
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (activeTool !== 'cursor') return;
    const touch = e.changedTouches[0];
    endGesture(touch.clientX, touch.clientY);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0 || activeTool !== 'cursor') return;
    e.preventDefault(); 
    const mode = zoomLevel > 1 ? 'pan' : 'swipe';
    startGesture(e.clientX, e.clientY, mode);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (activeTool !== 'cursor') return;
    if (gesture.current.mode !== 'none') {
       e.preventDefault();
       moveGesture(e.clientX, e.clientY);
    }
  };

  const handleMouseUp = (e: React.MouseEvent) => {
    if (activeTool !== 'cursor') return;
    if (gesture.current.mode !== 'none') {
       endGesture(e.clientX, e.clientY);
    }
  };

  const handleMouseLeave = (e: React.MouseEvent) => {
    if (activeTool !== 'cursor') return;
    if (gesture.current.mode !== 'none') {
       endGesture(e.clientX, e.clientY);
    }
  };

  return (
    <div 
        ref={containerRef}
        className="fixed inset-0 z-50 flex bg-skin-overlay backdrop-blur-md animate-fade-in touch-none select-none overflow-hidden"
    >
      <div className="flex-grow flex flex-col h-full relative">

        {/* --- TOP PANEL --- */}
        <div 
            className={`flex flex-col border-b border-skin-border bg-skin-base/95 backdrop-blur-md z-20 shadow-sm transition-transform duration-300 absolute top-0 left-0 right-0 ${showTopPanel ? 'translate-y-0' : '-translate-y-full'}`}
        >
            <div className="flex items-center justify-between p-4">
                <div className="flex flex-col">
                    <h2 className="text-skin-text font-bold text-lg leading-tight line-clamp-1">{catalog.title}</h2>
                    <div className="flex items-center gap-2 text-skin-muted text-xs mt-0.5">
                        <span>صفحه {currentPage + 1} از {catalog.pages.length}</span>
                    </div>
                </div>

                {/* Desktop Controls */}
                <div className="flex items-center gap-2">
                    <div className="hidden md:flex items-center gap-1 bg-skin-control-bg rounded-lg p-1 border border-skin-border mr-2">
                        {/* Annotation Tools */}
                        <div className="flex items-center gap-1 border-l border-gray-300 pl-2 ml-1">
                            <button 
                                onClick={() => setActiveTool('cursor')} 
                                className={`p-2 rounded-md transition-colors ${activeTool === 'cursor' ? 'bg-skin-card text-skin-primary shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`} 
                                title="جابجایی و ورق زدن"
                            >
                                <MousePointer2 size={18} />
                            </button>
                            <button 
                                onClick={() => setActiveTool('highlight')} 
                                className={`p-2 rounded-md transition-colors ${activeTool === 'highlight' ? 'bg-yellow-200 text-yellow-900 shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`} 
                                title="هایلایت متن"
                            >
                                <Highlighter size={18} />
                            </button>
                            <button 
                                onClick={() => setActiveTool('note')} 
                                className={`p-2 rounded-md transition-colors ${activeTool === 'note' ? 'bg-yellow-200 text-yellow-900 shadow-sm' : 'text-skin-control-text hover:bg-skin-control-hover'}`} 
                                title="افزودن یادداشت"
                            >
                                <StickyNote size={18} />
                            </button>
                        </div>

                        {/* View Mode Toggle */}
                        <button onClick={() => setForceSinglePage(!forceSinglePage)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors" title={forceSinglePage ? "مشاهده دو صفحه" : "مشاهده تک صفحه"}>
                            {forceSinglePage ? <Book size={18} /> : <Smartphone size={18} />}
                        </button>
                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={handleZoomOut} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomOut size={18} /></button>
                        <span className="text-xs w-8 text-center tabular-nums text-skin-muted select-none">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors"><ZoomIn size={18} /></button>

                        <div className="w-px h-5 bg-gray-300 mx-1"></div>

                        <button onClick={() => setIsSoundEnabled(!isSoundEnabled)} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {isSoundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                        </button>
                        <button onClick={toggleFullscreen} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
                        </button>
                        <button onClick={handleDownload} className="p-2 text-skin-control-text hover:bg-skin-control-hover rounded-md transition-colors">
                            <FileDown size={18} />
                        </button>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full bg-skin-control-bg text-skin-control-text hover:bg-red-500 hover:text-white transition-colors border border-skin-border pointer-events-auto">
                        <X size={20} />
                    </button>
                </div>
            </div>

            {/* Top Collapse Button */}
            <div className="flex justify-center -mb-3 pb-1">
                 <button onClick={() => setShowTopPanel(false)} className="bg-skin-card border border-skin-border rounded-full p-1 shadow-sm text-skin-muted hover:text-skin-primary hover:bg-skin-control-bg transition-colors">
                    <ChevronUp size={16} />
                 </button>
            </div>
        </div>

        {/* Floating Top Expand Button */}
        <button 
            onClick={() => setShowTopPanel(true)}
            className={`absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-skin-card/80 backdrop-blur-sm border border-skin-border rounded-full p-2 shadow-lg text-skin-muted hover:text-skin-primary transition-all duration-300 ${!showTopPanel ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-full pointer-events-none'}`}
        >
            <ChevronDown size={20} />
